        public ActionResult ExportToExcel_to_Master()
        {
            var userid = User.Identity.GetUserId();
            DataTable dt = new DataTable();
            dt.Columns.Add("M/D Firm", typeof(string));
            dt.Columns.Add("M/D Name", typeof(string));
            dt.Columns.Add("Registred No.", typeof(string));
            dt.Columns.Add("Account Balance", typeof(string));
            dt.Columns.Add("Admin Credit", typeof(string));
            var ch = db.Whitelabel_Master_Reamin_Cr_report(userid).ToList();
            foreach (var item in ch)
            {
                dt.Rows.Add(item.FarmName, item.SuperstokistName, item.Mobile, item.remainbal, item.cr);
            }
            var grid = new GridView();
            grid.DataSource = dt;
            grid.DataBind();
            Response.ClearContent();
            Response.Buffer = true;
            Response.AddHeader("content-disposition", "attachment; filename=Master_remain_balance.xls");
            Response.ContentType = "application/ms-excel";
            Response.Charset = "";
            StringWriter sw = new StringWriter();
            HtmlTextWriter htw = new HtmlTextWriter(sw);
            grid.RenderControl(htw);
            Response.Output.Write(sw.ToString());
            Response.Flush();
            Response.End();
            return View();
        }
