        public ActionResult DeleteMD(string ssid)
        {
            var userid = User.Identity.GetUserId();
            var check = db.whitelabel_Dealer_Details.Where(aa => aa.masterid == ssid).FirstOrDefault();
            var msg = "";
            if (check == null)
            {
                int _min = 1000;
                int _max = 9999;
                Random _rdm = new Random();
                var otp = _rdm.Next(_min, _max).ToString();
                MobileOtp mobile = new MobileOtp();
                mobile.Date = DateTime.Now;
                mobile.mobileno = check.Mobile;
                mobile.Otp = otp;
                mobile.Type = "WHITELABELMASTERDELETE";
                mobile.Userid = ssid;
                db.MobileOtps.Add(mobile);
                db.SaveChanges();
                int otpi = Convert.ToInt32(otp);
                new Whitelabel_DeleteUserSendOtp().sendmasterotp(otpi, userid);
                var smsapilist = (from ff in db.apisms where ff.sts == "Y" select ff).SingleOrDefault();
                if (smsapilist != null)
                {
                    try
                    {
                        var usermobiles = db.Whitelabel_Superstokist_details.Where(aa => aa.SSId == ssid).ToList();
                        var txtMsgBody = "Master Delete Otp " + otp;
                        var adminmobile = db.WhiteLabel_userList.Where(aa => aa.WhiteLabelID == userid).SingleOrDefault().Mobile;
                        var url = smsapilist.smsapi;
                        if (url != null && url.Contains("tttt") && url.Contains("mmmm"))
                        {
                            url = url.Replace("tttt", adminmobile);
                            url = url.Replace("mmmm", txtMsgBody);

                            HttpWebRequest WebRequestObject = (HttpWebRequest)HttpWebRequest.Create(url);
                            WebRequestObject.Timeout = (System.Int32)TimeSpan.FromSeconds(10).TotalMilliseconds;

                            WebResponse Response = WebRequestObject.GetResponse();
                            Stream WebStream = Response.GetResponseStream();

                            StreamReader Reader = new StreamReader(WebStream);
                            string webcontent = Reader.ReadToEnd();
                            whitelabel_sms_api_entry sms = new whitelabel_sms_api_entry();

                            sms.userid = userid;
                            sms.apiname = url;
                            sms.msg = txtMsgBody;
                            sms.messagefor = userid;
                            sms.userid = userid;
                            sms.m_date = System.DateTime.Now;
                            sms.response = webcontent;
                            db.whitelabel_sms_api_entry.Add(sms);
                            db.SaveChanges();
                        }
                    }
                    catch (System.Net.WebException E)
                    {
                    }
                }
                msg = "success";
            }
            else
            {
                msg = "Not Allow To Delete, First Change The Distributor.";
            }
            return Json(msg, JsonRequestBehavior.AllowGet);
        }
