        [HttpPost]
        public async Task<ActionResult> insert_super(string masterid, string Name, string FarmName, int State, int District, string Mb, string Address, int Pincode, string Email, string pancard, string adharcard, string gst, string ddlrole)
        {
            string msg = "";
            string type = "";
            var userid = User.Identity.GetUserId();
            var appDbContext = HttpContext.GetOwinContext().Get<ApplicationDbContext>();
            using (var transaction = appDbContext.Database.BeginTransaction())
            {
                var Password = "";
                var ConfirmPassword = "";
                try
                {
                    //if (slab_name == " " || slab_name.Contains("Select Slab"))
                    //{
                    //    TempData["mobileno"] = "Please Select Any Slab";
                    //    return RedirectToAction("DistibutorList");
                    //}
                    //else
                    //{

                    //var hh = db.slab_name_list().ToList();
                    //ViewBag.slabname = new SelectList(hh, "slab_name", "slab_name");
                    ViewBag.state = new SelectList(db.Select_State_Details(), "State_Id", "State_Name").ToList();
                    if (District != 0 && State != 0)
                    {
                        var chkmobile = db.Users.Where(a => a.PhoneNumber == Mb).Any();
                        if (chkmobile == true)
                        {
                            msg = "This Mobile Number Already Exists.";
                            return Json(new { msg = msg, type = "error" }, JsonRequestBehavior.AllowGet);
                            //TempData["mobileno"] = "This Mobile Number Already Exists.";
                            // return RedirectToAction("DistibutorList");

                        }
                        var check = db.whitelabel_Dealer_Details.Where(a => a.Mobile == Mb).Any();
                        if (check == false)
                        {
                            bool includeLowercase = false;
                            bool includeUppercase = false;
                            bool includeNumeric = true;
                            bool includeSpecial = false;
                            bool includeSpaces = false;
                            int lengthOfPassword = 4;

                            string pingen = PasswordGenerator.GeneratePassword(includeLowercase, includeUppercase, includeNumeric, includeSpecial, includeSpaces, lengthOfPassword);

                            while (!PasswordGenerator.PasswordIsValid(includeLowercase, includeUppercase, includeNumeric, includeSpecial, includeSpaces, pingen))
                            {
                                pingen = PasswordGenerator.GeneratePassword(includeLowercase, includeUppercase, includeNumeric, includeSpecial, includeSpaces, lengthOfPassword);
                            }
                            var enpin = Encrypt(pingen);

                            var user = new ApplicationUser { UserName = Email, Email = Email, PhoneNumber = Mb };
                            //Generate Random Password

                            includeLowercase = true;
                            includeUppercase = true;
                            includeNumeric = true;
                            includeSpecial = true;
                            includeSpaces = false;
                            lengthOfPassword = 8;

                            string pass = PasswordGenerator.GeneratePassword(includeLowercase, includeUppercase, includeNumeric, includeSpecial, includeSpaces, lengthOfPassword);

                            while (!PasswordGenerator.PasswordIsValid(includeLowercase, includeUppercase, includeNumeric, includeSpecial, includeSpaces, pass))
                            {
                                pass = PasswordGenerator.GeneratePassword(includeLowercase, includeUppercase, includeNumeric, includeSpecial, includeSpaces, lengthOfPassword);
                            }
                            Password = pass.ToString();
                            ConfirmPassword = pass.ToString();
                            var result = await UserManager.CreateAsync(user, Password);
                            if (result.Succeeded)
                            {
                                System.Data.Entity.Core.Objects.ObjectParameter output = new
                            System.Data.Entity.Core.Objects.ObjectParameter("Output", typeof(string));

                                var ch = db.Whitelabel_Insert_Dealer(userid, masterid, user.Id, Name, FarmName, State.ToString(), District.ToString(), Mb, Address, Pincode, Email, "", 0, "", pancard, adharcard, gst, "WhiteLabel", ddlrole, enpin, output).Single().msg.ToString();


                                var AdminMailId = db.WhiteLabel_userList.Where(aa => aa.WhiteLabelID == userid).Single().EmailId;

                                var MasterDetails = db.Whitelabel_Superstokist_details.Where(aa => aa.SSId == masterid).Single();

                                if (ch.ToString() == "Register SuccessFully.")
                                {
                                    string passsss = HttpUtility.UrlEncode(Password);
                                    transaction.Commit();

                                    // Send an email with this link
                                    string code = await UserManager.GenerateEmailConfirmationTokenAsync(user.Id);
                                    var callbackUrl = Url.Action("ConfirmEmailAdmin", "Account", new { userId = user.Id, code = code }, protocol: Request.Url.Scheme);
                                    callbackUrl = callbackUrl.Replace("/WHITELABEL", "");
                                    try
                                    {
                                        string body = new Whitelabel_CommonUtil().PopulateBodyDealer(userid, "", "Confirm your account", "", "" + callbackUrl + "", Email, Password);
                                        new Whitelabel_CommonUtil().Insertsendmail(userid, Email, "Confirm your account", body, callbackUrl);

                                        string Welcomebody = new Whitelabel_CommonUtil().PopulateBodyWelcome(userid, "", "Confirm your account", "", "" + callbackUrl + "", Email, Password);
                                        new Whitelabel_CommonUtil().InsertsendmailWelcome(userid, Email, "Confirm your account", Welcomebody, callbackUrl);

                                        var adminemail = db.Admin_details.SingleOrDefault().email;
                                        new Whitelabel_CommonUtil().Rsendmailadmin(userid, adminemail, "Confirm your account", body, callbackUrl);
                                    }
                                    catch
                                    {

