        public ActionResult DealerMD_switch(string dealerid, string masterid)
        {
            var userid = User.Identity.GetUserId();
            int valss = 0;
            var msg = "";
            var oldssid = (db.whitelabel_Dealer_Details.Where(aa => aa.DealerId == dealerid && aa.Whitelabelid == userid).FirstOrDefault().masterid);
            if (oldssid.ToLower() != masterid.ToLower())
            {
                using (VastwebmultiEntities newdb = new VastwebmultiEntities())
                {
                    whitelabel_Dealer_Details objCourse = (from p in newdb.whitelabel_Dealer_Details
                                                           where p.DealerId == dealerid && p.Whitelabelid == userid
                                                           select p).Single();
                    objCourse.masterid = masterid;
                    valss = newdb.SaveChanges();
                    if (valss > 0)
                    {
                        Whitelabel_Switch_DealerTOMD model = new Whitelabel_Switch_DealerTOMD();
                        model.DealerId = dealerid;
                        model.OldMasterId = oldssid;
                        model.CurrentMasterId = objCourse.masterid;
                        model.SwitchDate = DateTime.Now;
                        db.Whitelabel_Switch_DealerTOMD.Add(model);
                        db.SaveChanges();
                        msg = "Distributor Transfer SuccessFully.";
                        return Json(new { Success = "Success", msg = msg }, JsonRequestBehavior.AllowGet);
                    }
                }
            }
            else
            {
                TempData["error"] = "Distributor Already Under This Master.";
                msg = "Distributor Already Under This Master.";
            }
            return Json(new { error = "error", msg = msg }, JsonRequestBehavior.AllowGet);
        }

        [HttpPost]
        public ActionResult dealer_retailer_Switch(string remid, string dlmid)
        {
            var userid = User.Identity.GetUserId();
            var msg = "";
            int valss = 0;
            try
            {
                var olddlmid = string.Empty;
                var objCourse = db.Whitelabel_Retailer_Details.SingleOrDefault(p => p.RetailerId.ToLower() == remid.ToLower() && p.Whitelabelid == userid);
                olddlmid = objCourse.DealerId;
                try
                {
                    objCourse.DealerId = dlmid;
                    db.Entry(objCourse).State = EntityState.Modified;
                    valss = db.SaveChanges();
                    if (valss > 0)
                    {
                        Whitelabel_Switch_RetailerDealer model = new Whitelabel_Switch_RetailerDealer();
                        model.RetailerId = remid;
                        model.OldDealer = olddlmid;
                        model.CurrentDealer = objCourse.DealerId;
                        model.SwitchDate = DateTime.Now;
                        db.Whitelabel_Switch_RetailerDealer.Add(model);
                        db.SaveChanges();
                        msg = "Retailer Transfer SuccessFully.";

                    }
                }
                catch (Exception ex)
                {
                }
                ViewBag.dlmid = new SelectList(db.whitelabel_Dealer_Details.Where(a => a.Whitelabelid == userid), "Dealerid", "FarmName", null);
                ViewBag.remid = new SelectList(db.Whitelabel_Retailer_Details.Where(a => a.Whitelabelid == userid), "RetailerId", "Frm_Name", null);
                var newdlmid = objCourse.DealerId;
                if (olddlmid != newdlmid)
                {
                    var olddlmemailid = (db.whitelabel_Dealer_Details.SingleOrDefault(p => p.DealerId == olddlmid).Email);
                    var newdlmemailid = (db.whitelabel_Dealer_Details.SingleOrDefault(p => p.DealerId == newdlmid));
