                    string Olddllmbody = "Your Retailer Id '" + objCourse.Email + "' & Mobile no '" + objCourse.Mobile + "' and Farm Name '" + objCourse.Frm_Name + "'  is Transfer to This Distributor Id '" + newdlmemailid.Email + "'.";
                    new Whitelabel_CommonUtil().Rsendmailadmin(userid, olddlmemailid, "Your Retailer Remove Successfully.", Olddllmbody, Olddllmbody);

                    string Newdllmbody = "Contratulation ! This Retailer Id '" + objCourse.Email + "' and Mobile no '" + objCourse.Mobile + "' is Added to Your Account.";
                    new Whitelabel_CommonUtil().Rsendmailadmin(userid, newdlmemailid.Email, "Retailer Added In Our Account.", Newdllmbody, Newdllmbody);

                    TempData["success"] = "Retailer Transfer SuccessFully.";

                    return Json(new { Success = "Success", msg = msg }, JsonRequestBehavior.AllowGet);
