                sb.Append("<td style='background-color: #B8DBFD;border: 1px solid #ccc'>" + item.RecivedDate + "</td>");
                sb.Append("<td style='background-color: #B8DBFD;border: 1px solid #ccc'>" + item.BenifitRecived + "</td>");
                sb.Append("<td style='background-color: #B8DBFD;border: 1px solid #ccc'>" + item.sharingtype + "</td>");
