        public JsonResult InsertRefferalsetting(string reftype, decimal minlimit, int noofday, string sharingtype, decimal sharingvalue, string catetype)
        {
            var userid = User.Identity.GetUserId();

            if (reftype == "Purchases Basis")
            {
                catetype = null;
            }
            var typs = db.Whitelabel_Refferalsetting.Where(x => x.ReferalType == reftype && x.WhitelabelId == userid).Any();
            if (typs == false)
            {
                var result = new Whitelabel_Refferalsetting();
                result.WhitelabelId = userid;
                result.ReferalType = reftype;
                result.minimiumimit = minlimit;
                result.expnoofday = noofday;
                result.SharingType = sharingtype;
                result.SharingValue = sharingvalue;
                result.category = catetype;
                result.status = false;
                result.dates = DateTime.Today;
                db.Whitelabel_Refferalsetting.Add(result);
                var countval = db.SaveChanges();
                if (countval > 0)
                {
                    return Json("Success", JsonRequestBehavior.AllowGet);

                }
            }
            else
            {
                return Json(reftype + " Already Exist", JsonRequestBehavior.AllowGet);
            }
            return Json("Something Wrong", JsonRequestBehavior.AllowGet);
        }

