        public JsonResult DeleteReferedCode(string type)
        {
            var userid = User.Identity.GetUserId();
            var res = db.Whitelabel_Refferalsetting.Where(x => x.ReferalType == type && x.WhitelabelId == userid).Any();
            if (res == true)
            {
                int findreferalid = db.Whitelabel_Refferalsetting.FirstOrDefault(x => x.ReferalType == type && x.WhitelabelId == userid).refferalID;
                Whitelabel_Refferalsetting model = db.Whitelabel_Refferalsetting.Where(x => x.refferalID == findreferalid && x.WhitelabelId == userid).FirstOrDefault();
                db.Whitelabel_Refferalsetting.Remove(model);
                int count = db.SaveChanges();
                if (count > 0)
                {
                    return Json(type, JsonRequestBehavior.AllowGet);
                }
                return Json("Erroe", JsonRequestBehavior.AllowGet);
            }
            else
            {
                return Json("Erroe", JsonRequestBehavior.AllowGet);
            }
        }

