        [HttpPost]
        public ActionResult SMSSettingSave(string[] ch, string MsgType)
        {
            var userid = User.Identity.GetUserId();
            var responseMsg = "";
            try
            {
                if (MsgType == "Message's")
                {
                    foreach (var item in ch)
                    {
                        var groupname1 = item.Split(',');

                        var Status = groupname1[1].ToString();
                        var name = groupname1[0].ToString();
                        Whitelabel_SMSSendAll obj = (from pp in db.Whitelabel_SMSSendAll
                                                     where pp.ServiceName == name && pp.Whitelabelid == userid
                                                     select pp).SingleOrDefault();
                        if (obj != null)
                        {
                            obj.Status = Status;
                            db.SaveChanges();
                        }
                        else
                        {
                            Whitelabel_SMSSendAll obj1 = new Whitelabel_SMSSendAll();
                            obj1.Status = Status;
                            obj1.ServiceName = name;
                            obj1.Whitelabelid = userid;
                            db.Whitelabel_SMSSendAll.Add(obj1);
                            db.SaveChanges();
                        }

                    }

                    responseMsg = "SMS Setting Change Successfully !";
                }
                else if (MsgType == "Email's")
                {
                    foreach (var item in ch)
                    {
                        var groupname1 = item.Split(',');

                        var Status = groupname1[1].ToString();
                        var name = groupname1[0].ToString();
                        Whitelabel_EmailSendAll obj = (from pp in db.Whitelabel_EmailSendAll
                                                       where pp.ServiceName == name && pp.Whitelabelid == userid
                                                       select pp).SingleOrDefault();
                        if (obj != null)
                        {
                            obj.Status = Status;
                            db.SaveChanges();
                        }
                        else
                        {
                            Whitelabel_EmailSendAll obj1 = new Whitelabel_EmailSendAll();
                            obj1.Status = Status;
                            obj1.ServiceName = name;
                            obj1.Whitelabelid = userid;
                            db.Whitelabel_EmailSendAll.Add(obj1);
                            db.SaveChanges();
                        }

                    }
                    responseMsg = "Mail Setting Change Successfully !";
                }

                return Json(new { status = "Success", Message = responseMsg });
            }
            catch (Exception ex)
            {
                return Json(new { status = "Failed", Message = "Something Went Wrong !!!" });
            }
        }
