        [HttpPost]
        public ActionResult InsertOTP(string txtcode)
        {
            var type = "";
            var mobile = "";
            var data = db.MobileOtps.Where(p => p.Otp == txtcode).ToList();
            if (data.Count > 0)
            {
                type = data.Single().Type;
                mobile = data.Single().mobileno;
            }
            else
            {
                type = "";
                mobile = "";
            }

            if (type == "Dealer")
            {
                MobileOtp objOTP = db.MobileOtps.Where(p => p.Type == type).OrderByDescending(a => a.idno).Take(1).Single();
                if (objOTP != null && objOTP.Otp == txtcode)
                {
                    if (objOTP.Userid != null)
                    {
                        whitelabel_Dealer_Details objCourse = (from p in db.whitelabel_Dealer_Details
                                                               where p.DealerId == objOTP.Userid
                                                               select p).SingleOrDefault();
                        objCourse.Mobile = mobile;
                        db.SaveChanges();
                        User obj = (from p in db.Users
                                    where p.UserId == objOTP.Userid
                                    select p).SingleOrDefault();
                        obj.PhoneNumber = mobile;
                        db.SaveChanges();
                        return RedirectToAction("DistibutorList");
                    }
                }
                else
                {
                    ViewData["MSG"] = "Wrong OTP.";
                }
            }
            else if (type == "Retailer")
            {
                MobileOtp objOTP = db.MobileOtps.Where(p => p.Type == type).OrderByDescending(a => a.idno).Take(1).Single();
                if (objOTP != null && objOTP.Otp == txtcode)
                {
                    if (objOTP.Userid != null)
                    {
                        Whitelabel_Retailer_Details objCourse = (from p in db.Whitelabel_Retailer_Details
                                                                 where p.RetailerId == objOTP.Userid
                                                                 select p).SingleOrDefault();
                        objCourse.Mobile = mobile;
                        db.SaveChanges();
                        User obj = (from p in db.Users
                                    where p.UserId == objOTP.Userid
                                    select p).SingleOrDefault();
                        obj.PhoneNumber = mobile;
                        db.SaveChanges();
                        return RedirectToAction("Retailerlist");
                    }
                }
                else
                {
                    ViewData["MSG"] = "Wrong OTP.";
                }
            }

            ViewData["MSG"] = "Wrong OTP.";
            return View();
        }

