        public ActionResult M_Poss()
        {
            var whitelabelid = User.Identity.GetUserId();
            MposSlabModel model = new MposSlabModel();
            var commonSlab = db.Common_whitelabel_Mpos_comm.Where(a => a.whitelabelid == whitelabelid).ToList();

            model.common = commonSlab;

            model.UserId = new List<SelectListItem>() { new SelectListItem { Text = "No data", Value = "No Data" } };
            return View(model);
        }
        [HttpPost]
        public ActionResult M_Poss(MposSlabModel model)
        {
            var whitelabelid = User.Identity.GetUserId();
            foreach (var item in model.common)
            {
                Common_whitelabel_Mpos_comm entry = (from p in db.Common_whitelabel_Mpos_comm where p.whitelabelid == whitelabelid && p.idno == item.idno select p).Single();
                entry.CashWithdraw = item.CashWithdraw;
                entry.Salesdebitupto2000 = item.Salesdebitupto2000;
                entry.Salesdebitabove2000 = item.Salesdebitabove2000;
                entry.SalescreditNormal = item.SalescreditNormal;
                entry.Salescreditgrocery = item.Salescreditgrocery;
                entry.SalescreditEduandInsu = item.SalescreditEduandInsu;
                entry.gst = item.gst;
                db.SaveChanges();
            }
            return RedirectToAction("M_Poss");
        }
