        [HttpPost]
        public ActionResult M_PossUserWise(MposSlabModel model, string ddlUserId, string role, string credite_type, string credite_typeAll)
        {

            var whitelabelid = User.Identity.GetUserId();
            if (role == "Dealer")
            {
                if (ddlUserId != "")
                {
                    foreach (var item in model.DealerMposUser)
                    {
                        Whitelabel_Mpos_comm_details entry = (from p in db.Whitelabel_Mpos_comm_details where p.whitelabelid == whitelabelid && p.userid == ddlUserId && p.userRole == "Whitelabeldealer" select p).Single();
                        entry.CashWithdraw = Convert.ToDecimal(item.CashWithdraw);
                        entry.Salesdebitupto2000 = Convert.ToDecimal(item.salesDebitUpto2000);
                        entry.Salesdebitabove2000 = Convert.ToDecimal(item.salesDebitAbove2000);
                        entry.SalescreditNormal = Convert.ToDecimal(item.saleCredit);
                        entry.Salescreditgrocery = Convert.ToDecimal(item.saleCreditGrocery);
                        entry.SalescreditEduandInsu = Convert.ToDecimal(item.saleCreditEduAndIns);
                        entry.gst = item.gst;
                        entry.credit_type = credite_type;
                        db.SaveChanges();
                    }
                }
                else
                {
                    foreach (var item in model.UpdateDealerMposUser)
                    {
                        db.Whitelabel_Update_Mos_All_Slab("Whitelabeldealer", item.CashWithdraw, item.Salesdebitupto2000, item.Salesdebitabove2000, item.SalescreditNormal, item.Salescreditgrocery, item.SalescreditEduandInsu, item.gst, credite_typeAll, whitelabelid);
                    }

                }
            }

            if (role == "Retailer")
            {
                if (ddlUserId != "")
                {
                    foreach (var item in model.RetailerMposUser)
                    {
                        Whitelabel_Mpos_comm_details entry = (from p in db.Whitelabel_Mpos_comm_details where p.whitelabelid == whitelabelid && p.userid == ddlUserId && p.userRole == "Whitelabelretailer" select p).Single();
                        entry.CashWithdraw = Convert.ToDecimal(item.CashWithdraw);
                        entry.Salesdebitupto2000 = Convert.ToDecimal(item.salesDebitUpto2000);
                        entry.Salesdebitabove2000 = Convert.ToDecimal(item.salesDebitAbove2000);
                        entry.SalescreditNormal = Convert.ToDecimal(item.saleCredit);
                        entry.Salescreditgrocery = Convert.ToDecimal(item.saleCreditGrocery);
                        entry.SalescreditEduandInsu = Convert.ToDecimal(item.saleCreditEduAndIns);
                        entry.gst = item.gst;
                        entry.credit_type = credite_type;
                        db.SaveChanges(); ;
                    }
                }
                else
                {
                    foreach (var item in model.UpdateRetailerMposUser)
                    {
                        db.Whitelabel_Update_Mos_All_Slab("Whitelabelretailer", item.CashWithdraw, item.Salesdebitupto2000, item.Salesdebitabove2000, item.SalescreditNormal, item.Salescreditgrocery, item.SalescreditEduandInsu, item.gst, credite_typeAll, whitelabelid);
                    }

                }
            }


            return RedirectToAction("M_Poss");
        }

