                {
                    userid = "ALL";
                }
                else
                {
                    userid = allretailer;
                }
            }
            if (ddlusers == "WAdmin" || ddlusers == null)
            {
                ddlusers = "Whitelabel";
            }


            DataTable dataTbl = new DataTable();
            dataTbl.Columns.Add("Status", typeof(string));
            dataTbl.Columns.Add("mPossId", typeof(string));
            dataTbl.Columns.Add("Customer Id", typeof(string));
            dataTbl.Columns.Add("BankRRN", typeof(string));
            dataTbl.Columns.Add("TxnId", typeof(string));
