                dataTbl.Rows.Add(sts, item.mPOSid, item.Frm_Name, item.BankRRN, item.TxnId, item.transType, item.amount, item.merchatID, item.bankmerchantID, item.bankterminalID,
                item.cardholdername, item.cardnumber, item.cardtype, item.date, item.invoiceno, item.paymentid, item.merchantnameaddress, item.AdminPre, item.AdminPost, item.MasterPre, item.MasterPost,
                item.DealerPre, item.DealerPost, item.RetailerPre, item.RetailerPost, item.MdComm, item.Dlm_Comm, item.Rem_comm, item.mdgst, item.dlmgst, item.remgst, item.mdincome, item.dlmincome,
                item.remincome, item.adminincome, item.purchase);
            }

            var grid = new GridView();
            grid.DataSource = dataTbl;
            grid.DataBind();
            Response.ClearContent();
            Response.Buffer = true;
            Response.AddHeader("content-disposition", "attachment; filename=mPoss_Report.xls");
            Response.ContentType = "application/ms-excel";
            Response.Charset = "";
            StringWriter sw = new StringWriter();
            HtmlTextWriter htw = new HtmlTextWriter(sw);
            grid.RenderControl(htw);
            Response.Output.Write(sw.ToString());
            Response.Flush();
            Response.End();

            return View();
        }
