        public virtual ActionResult ExcelPanCardReport(string txt_frm_date, string txt_to_date, string ddlusers, string ddl_status, string alldealer, string allretailer)
        {
            string userid = "";
            var status = "";

            if (txt_frm_date == null && txt_to_date == null)
            {
                txt_frm_date = DateTime.Now.ToString();
                txt_to_date = DateTime.Now.ToString();
            }

            DateTime frm = Convert.ToDateTime(txt_frm_date);
            DateTime to = Convert.ToDateTime(txt_to_date);


            txt_frm_date = frm.ToString("dd-MM-yyyy");
            txt_to_date = to.ToString("dd-MM-yyyy");

            ViewBag.apiid = new SelectList(db.select_apiusers_for_ddl("Admin"), "apiid", "username", null).ToList();
            string[] formats = new[] { "MM/dd/yyyy", "dd-MMM-yyyy",
                            "yyyy-MM-dd", "dd-MM-yyyy", "dd MMM yyyy" };
            DateTime dt = DateTime.ParseExact(txt_frm_date, formats, CultureInfo.InvariantCulture, DateTimeStyles.None);
            DateTime dt1 = DateTime.ParseExact(txt_to_date, formats, CultureInfo.InvariantCulture, DateTimeStyles.None);
            string frm_date = Convert.ToDateTime(dt).ToShortDateString();
            string to_date = Convert.ToDateTime(dt1).AddDays(1).ToString();

            if (ddlusers == "Dealer")
            {
                if (alldealer == "" || alldealer.Contains("All Distubutor") || alldealer == null)
                {
                    userid = "ALL";
                }
                else
                {
                    userid = alldealer;
                }
            }
            if (ddlusers == "Retailer")
            {
                if (allretailer == "" || allretailer.Contains("All Retailer") || allretailer == null)
                {
                    userid = "ALL";
                }
                else
                {
                    userid = allretailer;
                }
            }
            if (ddlusers == "Admin" || ddlusers == null)
            {
                userid = User.Identity.GetUserId();
            }

            if (ddl_status == "All" || ddl_status == null)
            {
                status = "ALL";
            }
            else
            {
                status = ddl_status;
            }

            DataTable dataTbl = new DataTable();
            dataTbl.Columns.Add("Status", typeof(string));
            dataTbl.Columns.Add("User Firm", typeof(string));
            dataTbl.Columns.Add("Merchant Txn Id", typeof(string));
            dataTbl.Columns.Add("Physical", typeof(string));
            dataTbl.Columns.Add("Digital", typeof(string));
            dataTbl.Columns.Add("Processing Fees", typeof(string));
            dataTbl.Columns.Add("UTI Status", typeof(string));
            dataTbl.Columns.Add("Date", typeof(string));
            dataTbl.Columns.Add("UTI TXN ID", typeof(string));
            dataTbl.Columns.Add("Retailer Remain Pre", typeof(string));
            dataTbl.Columns.Add("Net Income", typeof(string));
            dataTbl.Columns.Add("Retailer Remain Post", typeof(string));
            dataTbl.Columns.Add("Dealer Remain Pre", typeof(string));
            dataTbl.Columns.Add("Dealer Remain Post", typeof(string));
            dataTbl.Columns.Add("WhiteLabel Remain Pre", typeof(string));
            dataTbl.Columns.Add("WhiteLabel Net Income", typeof(string));
            dataTbl.Columns.Add("WhiteLabel Remain Post", typeof(string));

            var respo = db.proc_Whitelabel_PAN_CARD_IPAY_Token_report_Paging(userid, ddlusers, status, Convert.ToDateTime(frm_date), Convert.ToDateTime(to_date), 10000000, 1).ToList();
            foreach (var item in respo)
            {
                var sts = item.Particulars;
                if (item.Particulars.ToUpper().Contains("REQ"))
                {
                    sts = "Pending";
                }
                dataTbl.Rows.Add(sts, item.Frm_Name, item.MerchantTxnId, item.PhysicalCount, item.DigitalCount,
                    item.ProcessingFees, item.CouponStatus,
                item.Date, item.UTI_TXN_ID, item.retailer_remain_pre, item.RetailerIncome, item.retailer_remain_post, item.retailer_dealer_pre, item.retailer_dealer_post, item.whitelabel_remain_pre,
                item.whitelabelincome, item.retailer_dealer_post);
            }

            var grid = new GridView();
            grid.DataSource = dataTbl;
            grid.DataBind();
            Response.ClearContent();
            Response.Buffer = true;
            Response.AddHeader("content-disposition", "attachment; filename=PanCard_Report.xls");
            Response.ContentType = "application/ms-excel";
            Response.Charset = "";
            StringWriter sw = new StringWriter();
            HtmlTextWriter htw = new HtmlTextWriter(sw);
            grid.RenderControl(htw);
            Response.Output.Write(sw.ToString());
            Response.Flush();
            Response.End();

            return View();
        }
