            DateTime dt1 = DateTime.ParseExact(txt_to_date, formats, CultureInfo.InvariantCulture, DateTimeStyles.None);
            string frm_date = Convert.ToDateTime(dt).ToShortDateString();
            string to_date = Convert.ToDateTime(dt1).AddDays(1).ToString();

            if (ddlusers == "Dealer")
            {
                if (alldealer == "" || alldealer.Contains("All Distubutor") || alldealer == null)
                {
                    userid = "ALL";
                }
                else
                {
                    userid = alldealer;
                }
            }
            if (ddlusers == "Retailer")
            {
                if (allretailer == "" || allretailer.Contains("All Retailer") || allretailer == null)
                {
                    userid = "ALL";
                }
                else
                {
                    userid = allretailer;
                }
            }
            if (ddlusers == "Admin" || ddlusers == null)
            {
                userid = User.Identity.GetUserId();
            }

            if (ddl_status == "All" || ddl_status == null)
            {
                status = "ALL";
            }
            else
            {
                status = ddl_status;
            }

            var respo = db.proc_Whitelabel_PAN_CARD_IPAY_Token_report_Paging(userid, ddlusers, status, Convert.ToDateTime(frm_date), Convert.ToDateTime(to_date), 10000000, 1).ToList();
            return new ViewAsPdf(respo);
        }

        public ActionResult FindTotalPanCardReport(string txt_frm_date, string txt_to_date, string ddlusers, string ddl_status, string alldealer, string allretailer)
        {
            string userid = "";
            var status = "";

            if (txt_frm_date == null && txt_to_date == null)
            {
                txt_frm_date = DateTime.Now.ToString();
                txt_to_date = DateTime.Now.ToString();
            }

            DateTime frm = Convert.ToDateTime(txt_frm_date);
            DateTime to = Convert.ToDateTime(txt_to_date);


            txt_frm_date = frm.ToString("dd-MM-yyyy");
            txt_to_date = to.ToString("dd-MM-yyyy");

            ViewBag.apiid = new SelectList(db.select_apiusers_for_ddl("Admin"), "apiid", "username", null).ToList();
            string[] formats = new[] { "MM/dd/yyyy", "dd-MMM-yyyy",
                            "yyyy-MM-dd", "dd-MM-yyyy", "dd MMM yyyy" };
            DateTime dt = DateTime.ParseExact(txt_frm_date, formats, CultureInfo.InvariantCulture, DateTimeStyles.None);
            DateTime dt1 = DateTime.ParseExact(txt_to_date, formats, CultureInfo.InvariantCulture, DateTimeStyles.None);
            string frm_date = Convert.ToDateTime(dt).ToShortDateString();
            string to_date = Convert.ToDateTime(dt1).AddDays(1).ToString();

            if (ddlusers == "Dealer")
            {
                if (alldealer == "" || alldealer.Contains("All Distubutor") || alldealer == null)
                {
                    userid = "ALL";
                }
                else
                {
                    userid = alldealer;
                }
            }
            if (ddlusers == "Retailer")
            {
                if (allretailer == "" || allretailer.Contains("All Retailer") || allretailer == null)
                {
                    userid = "ALL";
                }
                else
                {
                    userid = allretailer;
                }
            }
            if (ddlusers == "Admin" || ddlusers == null)
            {
                userid = User.Identity.GetUserId();
            }

            if (ddl_status == "All" || ddl_status == null)
            {
                status = "ALL";
            }
            else
            {
                status = ddl_status;
            }

            var chk = db.proc_Whitelabel_PAN_CARD_IPAY_Token_report_Paging(userid, ddlusers, status, Convert.ToDateTime(frm_date), Convert.ToDateTime(to_date), 10000000, 1).ToList();


            var successtotal = chk.Where(a => a.Particulars.ToUpper() == "SUCCESS").Sum(a => a.ProcessingFees); //chk.Where(aa => aa.rstatus.ToUpper() == "SUCCESS").Sum(aa => aa.amount);
            var Failedtotal = chk.Where(aa => aa.Particulars.ToUpper() == "FAILED").Sum(aa => aa.ProcessingFees);
            var pendingtotal = chk.Where(aa => aa.Particulars.ToUpper().Contains("REQ")).Sum(aa => aa.ProcessingFees);
            var data = new
            {
                success = successtotal,
                failed = Failedtotal,
                pending = pendingtotal
            };
            return Json(data, JsonRequestBehavior.AllowGet);

        }
