        [HttpGet]
        public ActionResult Customer_Charge(string ddltype)
        {
            Models.Show_All_CustomerCharge ch = new Models.Show_All_CustomerCharge();
            ch.Prepaid = (from tbl in db.whitelabel_customer_prepaid_charge
                          select new Models.Prepaid
                          {
                              idno = tbl.idno,
                              commission = tbl.comm,
                              OperatorName = tbl.type
                          }).ToList();
            ch.Postpaid = (from tbl in db.whitelabel_customer_postpaid_charge
                           select new Models.Postpaid
                           {
                               idno = tbl.idno,
                               commission1 = tbl.comm1,
                               commission2 = tbl.comm2,
                               commission3 = tbl.comm3,
                               OperatorName = tbl.type
                           }).ToList();

            ch.IMPS = (from tbl in db.whitelabel_customer_IMPS_Charge
                       select new Models.IMPS
                       {
                           idno = tbl.idno,
                           commission = tbl.comm,
                           minimum = tbl.min,
                           maximum = tbl.max,
                           OperatorName = tbl.type
                       }).ToList();

            ViewData["type"] = ddltype;
            return View(ch);
        }
