        public ActionResult EditCustomerCharge(Models.Show_All_CustomerCharge show, string ID)
        {
            var ddltype = "";
            if (ID == "Prepaid")
            {
                foreach (var jj in show.Prepaid)
                {
                    ddltype = "Prepaid";
                    var idno = jj.idno;
                    var comm = jj.commission;
                    whitelabel_customer_prepaid_charge objCourse = (from p in db.whitelabel_customer_prepaid_charge where p.idno == idno select p).Single();
                    objCourse.comm = comm;
                    db.SaveChanges();
                }
            }
            else if (ID == "Postpaid")
            {
                foreach (var jj in show.Postpaid)
                {
                    ddltype = show.Postpaid[0].ddltype;
                    var idno = jj.idno;
                    var comm1 = jj.commission1;
                    var comm2 = jj.commission2;
                    var comm3 = jj.commission3;
                    whitelabel_customer_postpaid_charge obj = (from p in db.whitelabel_customer_postpaid_charge where p.idno == idno select p).Single();
                    obj.comm1 = comm1;
                    obj.comm2 = comm2;
                    obj.comm3 = comm3;
                    db.SaveChanges();
                }
            }
            else if (ID == "IMPS")
            {
                foreach (var jj in show.IMPS)
                {
                    ddltype = show.IMPS[0].ddltype;
                    var idno = jj.idno;
                    var comm = jj.commission;
                    whitelabel_customer_IMPS_Charge imps = (from p in db.whitelabel_customer_IMPS_Charge where p.idno == idno select p).Single();
                    imps.comm = comm;
                    db.SaveChanges();
                }
            }
            return RedirectToAction("Customer_Charge", new { ddltype = ID });
        }
        public ActionResult generateSlab()
        {
            ADMIN.Models.ResultSetViewModel viewModel = new ADMIN.Models.ResultSetViewModel();
            using (VastwebmultiEntities db = new VastwebmultiEntities())
            {
                var userid = User.Identity.GetUserId();
                viewModel.ResultSet = db.Slab_name.Where(aa => aa.createdby == userid).Select(aaa => new ADMIN.Models.Slab_name_model
                {
                    cdate = aaa.cdate,
                    createdby = aaa.createdby,
                    idno = aaa.idno,
                    SlabFor = aaa.SlabFor,
                    SlabName = aaa.SlabName
                }).ToList();
                List<SelectListItem> items = new List<SelectListItem>();
                items.Add(new SelectListItem
                {
                    Text = "Distributor",
                    Value = "Distributor"
                });


                ViewData["msg"] = TempData["msg"];
                ViewBag.slabfor = items;

                return View(viewModel);
            }
        }
