        public ActionResult Flight_Commission()
        {
            var userid = User.Identity.GetUserId();
            var whitelabelcomm = db.Flight_Commission_admin.Single().WhitelabelCommission;
            Show_all_flight_commission ch = new Show_all_flight_commission();
            ch.Flight1 = (from tbl in db.Flight_Commission_whitelabel
                          where tbl.WhitelabelId == userid
                          select new Flight1
                          {
                              idno = tbl.idno,
                              WRetailerCommission = tbl.WRetailerCommission,
                              WDealerCommission = tbl.WDealerCommission,
                              WhitelabelCommission = whitelabelcomm,
                          }).ToList();
            return View(ch);
        }
        public ActionResult EditFlightCommission(Show_all_flight_commission show, string ID)
        {
            if (ID == "Flight")
            {
                foreach (var jj in show.Flight1)
                {
                    var userid = User.Identity.GetUserId();
                    var idno = jj.idno;
                    var retailercomm = jj.WRetailerCommission;
                    var dealercomm = jj.WDealerCommission;
                    var whitecomm = jj.WhitelabelCommission;
                    var totaldealerandmdcomm = dealercomm + retailercomm;
                    if (whitecomm >= totaldealerandmdcomm)
                    {
                        var totalwhitelabelcomm = whitecomm - totaldealerandmdcomm;
                        Flight_Commission_whitelabel objCourse = (from p in db.Flight_Commission_whitelabel where p.idno == idno select p).Single();
                        objCourse.WRetailerCommission = retailercomm;
                        objCourse.WDealerCommission = dealercomm;
                        objCourse.WhitelabelCommission = totalwhitelabelcomm;
                        objCourse.WhitelabelId = userid;
                        db.SaveChanges();
                        TempData["flight"] = "Whitelabel Flight Commission Update Successfully.";
                    }
                    else
                    {
                        TempData["flight"] = "Whitelabel Commission Must Be Greater Then Dealer and Retailer Commission";
                    }
                }
            }
            return RedirectToAction("Flight_Commission");
        }

