        #region News and Notification
        public ActionResult Message()
        {
            var userid = User.Identity.GetUserId();

            var sts = (from hh in db.Whitelabel_Desktop_Popup.Where(a => a.whitelabelid == userid) select hh.sts).FirstOrDefault() ?? "N";
            ViewData["but"] = (sts == "Y") ? sts = "OPEN" : sts = "CLOSE";
            ViewBag.ImageURL = (from hh in db.Whitelabel_Desktop_Popup.Where(a => a.whitelabelid == userid) select hh.imageurl).FirstOrDefault() ?? "";
            ViewBag.headercontent = (from hh in db.Whitelabel_Desktop_Popup.Where(a => a.whitelabelid == userid) select hh.Heardercontent).FirstOrDefault() ?? "";
            ADMIN.Models.Whitelabel_Notify noti = new ADMIN.Models.Whitelabel_Notify();
            noti.Message_top = (from gg in db.Whitelabel_Message_top.Where(a => a.whitelabelid == userid) select gg).ToList();
            noti.tbl_Holiday = db.Whitelabel_tbl_Holiday.Where(a => a.whitelabelid == userid).ToList();
            return View(noti);
        }
        [HttpPost]
        public ActionResult Message(string ddltop, string txtmessage, string txtname)
        {
            var userid = User.Identity.GetUserId();
            try
            {
                var pp = db.Whitelabel_Message_top.Where(a => a.whitelabelid == userid && a.users == ddltop && a.name == txtname).FirstOrDefault();
                if (pp == null)
                {
                    DateTime now = DateTime.Now;
                    Whitelabel_Message_top objCourse = new Whitelabel_Message_top();
                    objCourse.whitelabelid = userid;
                    objCourse.users = ddltop;
                    objCourse.message = txtmessage;
                    objCourse.status = "Y";
                    objCourse.tdate = now;
                    objCourse.name = txtname;
                    db.Whitelabel_Message_top.Add(objCourse);
                    db.SaveChanges();
                }
                else
                {
                    Whitelabel_Message_top objCourse = (from p in db.Whitelabel_Message_top
                                                        where p.idno == pp.idno && p.whitelabelid == userid
                                                        select p).Single();
                    objCourse.users = string.IsNullOrWhiteSpace(ddltop) ? objCourse.users : ddltop;
                    objCourse.name = string.IsNullOrEmpty(txtname) ? objCourse.name : txtname;
                    objCourse.message = string.IsNullOrEmpty(txtmessage) ? objCourse.message : txtmessage;
                    db.SaveChanges();
                }
            }
            catch
            {

            }
            var ch = (from gg in db.Whitelabel_Message_top.Where(a => a.whitelabelid == userid) select gg).ToList();
            return Json(ch, JsonRequestBehavior.AllowGet);

        }
        [HttpPost]
        public ActionResult blockmessage(int id)
        {
            var userid = User.Identity.GetUserId();
            try
            {
                var chk = (from ff in db.Whitelabel_Message_top where ff.idno == id && ff.whitelabelid == userid select ff).Single().status.ToString();
                chk = (chk == "Y") ? chk = "N" : chk = "Y";

                Whitelabel_Message_top objCourse = (from p in db.Whitelabel_Message_top
                                                    where p.idno == id && p.whitelabelid == userid
                                                    select p).SingleOrDefault();
                objCourse.status = chk;
                db.SaveChanges();

            }
            catch { }

            var ch = (from gg in db.Whitelabel_Message_top.Where(a => a.whitelabelid == userid) select gg).ToList();
            return Json(ch, JsonRequestBehavior.AllowGet);
        }
