        public ActionResult Updateholiday(string type, DateTime date)
        {
            var userid = User.Identity.GetUserId();
            bool updateaeps = true; bool updatempos = true;
            var chk = db.Whitelabel_tbl_Holiday.Where(aa => aa.whitelabelid == userid && aa.HolidayDate == date).SingleOrDefault();
            bool aepssts = (bool)chk.isAepsBlocked;
            bool mpossts = (bool)chk.isMposBlocked;

            if (type == "AEPS")
            {
                if (aepssts == true)
                {
                    updateaeps = false;
                }
                chk.isAepsBlocked = updateaeps;
                db.SaveChanges();
            }
            else
            {
                if (mpossts == true)
                {
                    updatempos = false;
                }
                chk.isMposBlocked = updatempos;
                db.SaveChanges();
            }
            return Json("", JsonRequestBehavior.AllowGet);
        }

