        [HttpPost]
        public ActionResult UploadExcelfileforsendingsmstemplate(HttpPostedFileBase FileUpload)
        {

            List<string> data = new List<string>();
            if (FileUpload != null)
            {
                var whitelabelid = User.Identity.GetUserId();
                if (FileUpload.ContentType == "application/vnd.ms-excel" || FileUpload.ContentType == "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet")
                {
                    string filename = FileUpload.FileName;
                    string targetpath = Server.MapPath("~/Doc/");
                    FileUpload.SaveAs(targetpath + filename);
                    string pathToExcelFile = targetpath + filename;
                    var connectionString = "";
                    if (filename.EndsWith(".xls"))
                    {
                        connectionString = string.Format("Provider=Microsoft.Jet.OLEDB.4.0; data source={0}; Extended Properties=Excel 8.0;", pathToExcelFile);
                    }
                    else if (filename.EndsWith(".xlsx"))
                    {
                        connectionString = string.Format("Provider=Microsoft.ACE.OLEDB.12.0;Data Source={0};Extended Properties=\"Excel 12.0 Xml;HDR=YES;IMEX=1\";", pathToExcelFile);
                    }

                    var adapter = new OleDbDataAdapter("SELECT * FROM [Sheet1$]", connectionString);
                    var ds = new DataSet();
                    adapter.Fill(ds, "ExcelTable");
                    DataTable dtable = ds.Tables["ExcelTable"];
                    string sheetName = "Sheet1";
                    var excelFile = new ExcelQueryFactory(pathToExcelFile);
                    var artistAlbums = from a in excelFile.Worksheet<Sending_SMS_Templateslist>(sheetName) select a;

                    foreach (var a in artistAlbums)
                    {
                        try
                        {
                            var findapiname = db.whitelabel_apisms.Where(x => x.smsapi.Contains(a.SMSAPIID) && x.userfor == whitelabelid).FirstOrDefault();
                            if (findapiname != null)
                            {
                                int apiiddno = findapiname.id;
                                var apiname = findapiname.smsapi;
                                if (a.Templateid != "" && a.SMSAPIID != "" && a.SMS_TYPE != "" && a.Templates != "")
                                {
                                    var chksmstemplate = db.Whitelabel_Sending_SMS_Templates.Where(x => x.SMS_TYPE == a.SMS_TYPE && x.SMSAPIID == apiiddno && x.whitelabelId == whitelabelid).Any();
                                    if (chksmstemplate == false)
                                    {
                                        Whitelabel_Sending_SMS_Templates TU = new Whitelabel_Sending_SMS_Templates();
                                        TU.Templateid = a.Templateid;
                                        TU.SMSAPIID = apiiddno;
                                        TU.SMS_TYPE = a.SMS_TYPE;
                                        TU.Templates = a.Templates;
                                        TU.whitelabelId = whitelabelid;
                                        db.Whitelabel_Sending_SMS_Templates.Add(TU);
                                        db.SaveChanges();
                                    }
                                }
                                else
                                {
                                    data.Add("<ul>");
                                    if (a.Templateid == "" || a.Templateid == null) data.Add("<li> Templateid is required</li>");
                                    if (a.SMSAPIID == "" || a.SMSAPIID == null) data.Add("<li> SMSAPIID is required</li>");
                                    if (a.SMS_TYPE == "" || a.SMS_TYPE == null) data.Add("<li>SMS_TYPE is required</li>");
                                    if (a.Templates == "" || a.Templates == null) data.Add("<li>Templates is required</li>");

                                    data.Add("</ul>");
                                    data.ToArray();
                                    return Json(data, JsonRequestBehavior.AllowGet);
                                }
                            }

                        }
                        catch (System.Data.Entity.Validation.DbEntityValidationException ex)
                        {
                            foreach (var entityValidationErrors in ex.EntityValidationErrors)
                            {
                                foreach (var validationError in entityValidationErrors.ValidationErrors)
                                {
                                    Response.Write("Property: " + validationError.PropertyName + " Error: " + validationError.ErrorMessage);
                                }
                            }
                        }
                    }
                    //deleting excel file from folder
                    if ((System.IO.File.Exists(pathToExcelFile)))
                    {
                        System.IO.File.Delete(pathToExcelFile);
                    }
                    return RedirectToAction("SMSAPI");
                    // return Json("success", JsonRequestBehavior.AllowGet);
                }
                else
                {
                    //alert message for invalid file format
                    data.Add("<ul>");
                    data.Add("<li>Only Excel file format is allowed</li>");
                    data.Add("</ul>");
                    data.ToArray();
                    TempData["excelldata"] = data;
                    return RedirectToAction("SMSAPI");
                    // return Json(data, JsonRequestBehavior.AllowGet);
                }
            }
            else
            {
                data.Add("<ul>");
                if (FileUpload == null) data.Add("<li>Please choose Excel file</li>");
                data.Add("</ul>");
                data.ToArray();
                TempData["excelldata"] = data;
                return RedirectToAction("SMSAPI");
                //  return Json(data, JsonRequestBehavior.AllowGet);
            }
        }

        public ActionResult copypastedeveloper()
        {
            var whitelabelid = User.Identity.GetUserId();
            var smstpiid = db.whitelabel_apisms.Where(x => x.sts == "Y" && x.userfor == whitelabelid).FirstOrDefault();
            var stsoffsmsapi = db.whitelabel_apisms.Where(x => x.sts == "N" && x.userfor == whitelabelid).ToList();

            if (smstpiid != null)
            {
                var smstemlatelist = db.Whitelabel_Sending_SMS_Templates.Where(x => x.SMSAPIID == smstpiid.id && x.whitelabelId == whitelabelid).ToList();
                List<Whitelabel_Sending_SMS_Templates> tblsmstem = new List<Whitelabel_Sending_SMS_Templates>();

                foreach (var item in stsoffsmsapi)
                {
                    foreach (var smstemp in smstemlatelist)
                    {
                        var chekexist = db.Whitelabel_Sending_SMS_Templates.Where(x => x.SMSAPIID == item.id && x.SMS_TYPE == smstemp.SMS_TYPE && x.whitelabelId == whitelabelid).FirstOrDefault();
                        if (chekexist == null)
                        {
                            tblsmstem.Add(new Whitelabel_Sending_SMS_Templates { SMSAPIID = item.id, SMS_TYPE = smstemp.SMS_TYPE, Templates = smstemp.Templates, Templateid = smstemp.Templateid, whitelabelId = smstemp.whitelabelId });
                        }
                    }
                }

                db.Whitelabel_Sending_SMS_Templates.AddRange(tblsmstem);
                db.SaveChanges();
            }


            List<Sending_SMS_TemplatesViewmodel> vmodel = new List<Sending_SMS_TemplatesViewmodel>();

            var resultssss = GET_ALL_Template_list().OrderByDescending(x => x.idno);
            return PartialView("_SMS_TEMPLATE_Reports", resultssss);

            //db.SaveChanges();
            //   return RedirectToAction("SMSAPI");
        }


        public IEnumerable<Sending_SMS_TemplatesViewmodel> GET_ALL_Template_list()
        {
            List<Sending_SMS_TemplatesViewmodel> vmodel = new List<Sending_SMS_TemplatesViewmodel>();
            VastwebmultiEntities db = new VastwebmultiEntities();

            var smstemplateslist = (from a in db.Whitelabel_Sending_SMS_Templates
                                    join b in db.whitelabel_apisms on a.SMSAPIID equals b.id

                                    select new Sending_SMS_TemplatesViewmodel
                                    {
                                        SMSAPID = a.SMSAPIID.Value,
                                        Templateid = a.Templateid,
                                        SMS_TYPE = a.SMS_TYPE,
                                        SMSAPI = b.smsapi,
                                        idno = a.idno,
                                        Templates = a.Templates


                                    });

            if (smstemplateslist != null)
            {
                vmodel = new List<Sending_SMS_TemplatesViewmodel>();
                foreach (var i in smstemplateslist)
                {
                    Sending_SMS_TemplatesViewmodel con = new Sending_SMS_TemplatesViewmodel();
                    con.SMSAPI = i.SMSAPI;
                    con.SMSAPID = i.SMSAPID;
                    con.Templateid = i.Templateid;
                    con.Templates = i.Templates;
                    con.SMS_TYPE = i.SMS_TYPE;
                    con.idno = i.idno;
                    vmodel.Add(con);
                    // all.Add(con);
                }
            }
            return vmodel;
            //  return Json(new { IsSuccess = true, Message = "Details fetched successfully..", Data = emp }, JsonRequestBehavior.AllowGet);
            // return Json(new { Data=vmodel}, JsonRequestBehavior.AllowGet);
        }


