        [HttpPost]
        public ActionResult _APISMSHISTORY(string txt_frm_date, string txt_to_date, string txtmsg)
        {
            Whitelabel_SMSViewModel vmodel = new Whitelabel_SMSViewModel();

            ViewBag.chk = "post";

            DateTime frm = Convert.ToDateTime(txt_frm_date);
            DateTime to = Convert.ToDateTime(txt_to_date);
            txt_frm_date = frm.ToString("dd-MM-yyyy");
            txt_to_date = to.ToString("dd-MM-yyyy");
            var userid = User.Identity.GetUserId();
            string[] formats = new[] { "MM/dd/yyyy", "dd-MMM-yyyy",
                            "yyyy-MM-dd", "dd-MM-yyyy", "dd MMM yyyy" };
            DateTime dt = DateTime.ParseExact(!string.IsNullOrEmpty(txt_frm_date) ? txt_frm_date : DateTime.Now.ToString("yyyy-MM-dd"), formats, CultureInfo.InvariantCulture, DateTimeStyles.None);
            DateTime dt1 = DateTime.ParseExact(!string.IsNullOrEmpty(txt_to_date) ? txt_to_date : DateTime.Now.ToString("yyyy-MM-dd"), formats, CultureInfo.InvariantCulture, DateTimeStyles.None);
            DateTime frm_date = Convert.ToDateTime(dt).Date;
            DateTime to_date = Convert.ToDateTime(dt1).AddDays(1);
            vmodel.whitelabel_sms_api_entry = db.whitelabel_sms_api_entry.Where(aa => aa.m_date >= frm_date && aa.m_date <= to_date && aa.msg.Contains(txtmsg) && aa.userid == userid).OrderByDescending(aa => aa.idno).ToList();

            return PartialView("_APISMSHISTORY", vmodel);
        }

        [HttpPost]
        public ActionResult Send_API_SMS(string Userform1, string txtmobileNo, string txtMsgBody)
        {
            var userid = User.Identity.GetUserId();
            try
            {
                string s = "";
                if (!string.IsNullOrEmpty(Userform1))
                {
                    if (Userform1 == "Master")
                    {
                        var smsapilist = (from ff in db.whitelabel_apisms where ff.sts == "Y" && ff.userfor == userid select ff).Single().smsapi.ToString();
                        var usermobiles = db.Whitelabel_Superstokist_details.Where(a => a.Whitelabelid == userid).ToList();
                        foreach (var item in usermobiles)
                        {
                            string url = smsapilist.Replace("tttt", item.Mobile);
                            url = url.Replace("mmmm", txtMsgBody);
                            ServicePointManager.SecurityProtocol = (SecurityProtocolType)3072;
                            HttpWebRequest WebRequestObject = (HttpWebRequest)HttpWebRequest.Create(url);
                            WebRequestObject.Timeout = (System.Int32)TimeSpan.FromSeconds(10).TotalMilliseconds;
                            try
                            {

                                WebResponse Response = WebRequestObject.GetResponse();
                                Stream WebStream = Response.GetResponseStream();

                                StreamReader Reader = new StreamReader(WebStream);
                                string webcontent = Reader.ReadToEnd();

                                whitelabel_sms_api_entry sms = new whitelabel_sms_api_entry();
                                sms.apiname = url;
                                sms.msg = txtMsgBody;
                                sms.messagefor = userid;
                                sms.userid = userid;
                                sms.m_date = System.DateTime.Now;
                                sms.response = webcontent;
                                db.whitelabel_sms_api_entry.Add(sms);
                                db.SaveChanges();
                            }
