        [HttpPost]
        public ActionResult mailChangeOTP()
        {
            try
            {
                var userid = User.Identity.GetUserId();
                var email = db.WhiteLabel_userList.Where(x => x.WhiteLabelID == userid).SingleOrDefault().EmailId;

                string numbers = "0123456789";
                Random objrandom = new Random();
                string strrandom = string.Empty;
                for (int i = 0; i < 4; i++)
                {
                    int temp = objrandom.Next(0, numbers.Length);
                    strrandom += temp;
                }

                CommUtilEmail emailsend = new CommUtilEmail();
                emailsend.WhiteLabelEmailLimitChk(email, null, "OTP Verify of Users Email Changes", strrandom, "OTP NOT SAVING", userid);

                deleteuserotp saveOTP = new deleteuserotp();
                saveOTP.otp = Convert.ToInt32(strrandom);
                saveOTP.SentDate = DateTime.Now;
                saveOTP.userid = userid;
                db.deleteuserotps.Add(saveOTP);
                db.SaveChanges();

                return Json("Success", JsonRequestBehavior.AllowGet);
            }
            catch
            {
                return Json("Failed", JsonRequestBehavior.AllowGet);
            }
        }

        public JsonResult BlockLoginUsers(string UserRoleBlocklogin, string block_login_User)
        {
