        public ActionResult GetLoctaion(string Latitude, string Logitude)
        {
            //string latitude = "13.0988683";
            //string longitude = "80.2255067";
            string locationName = "";

            string url = string.Format("https://maps.google.com/maps/api/geocode/json?latlng=" + Latitude + "," + Logitude + "&sensor=false");
            HttpWebRequest WebRequestObject = (HttpWebRequest)HttpWebRequest.Create(url);
            WebRequestObject.ContentType = "application/json";

            WebResponse webResponse = WebRequestObject.GetResponse();
            Stream webStream = webResponse.GetResponseStream();
            StreamReader responseReader = new StreamReader(webStream);
            string response = responseReader.ReadToEnd();
            dynamic responseJson = JsonConvert.DeserializeObject(response);
            if (responseJson.status == "OK")
            {
                locationName = responseJson.results[0].formatted_address;
                return Json(JsonConvert.SerializeObject(locationName), JsonRequestBehavior.AllowGet);
            }
            else
            {
                return Json(JsonConvert.SerializeObject(locationName), JsonRequestBehavior.AllowGet);
            }
        }

