        public ActionResult CashDepositCharge()
        {
            var userid = User.Identity.GetUserId();
            Whitelabel_CashDepositeAndBank_Info_VM CashBank = new Whitelabel_CashDepositeAndBank_Info_VM();
            var entry = db.Whitelabel_PurchaseOrderCashDepositCharge.Where(a => a.Whitelabelid == userid).ToList();
