            var WLTUNLDCharge = db.Whitelabel_WalletToBankAmountTransferCharge.Where(aa => aa.UserRole == "Retailer" && aa.Whitelabelid == userid).ToList();

            string txt_frm_date = DateTime.Now.ToString();
            string txt_to_date = DateTime.Now.ToString();
            DateTime frm_date = Convert.ToDateTime(txt_frm_date).Date;
            DateTime to_date = Convert.ToDateTime(txt_to_date).Date.AddDays(1);
            ViewBag.RetailerId1 = new SelectList(db.Whitelabel_Retailer_Details.Where(a => a.Whitelabelid == userid), "RetailerId", "Frm_Name", null);
            var sts = db.whitelabel_walletunloadsts.Where(a => a.Status == "Y" && a.WhitelabelID == userid).ToList();
            ViewBag.sts = sts.FirstOrDefault().Status;
