        public ActionResult UnblockWallet()
        {
            var userid = User.Identity.GetUserId();
            var chk = db.Whitelabel_Wallet_unload_sts.Where(a => a.Whitelabelid == userid).SingleOrDefault();
            bool? sts1 = false;
            if (chk != null)
            {
                sts1 = chk.sts;
                if (sts1 == false)
                {
                    chk.sts = true;
                }
                else
                {
                    chk.sts = false;
                }
                db.SaveChanges();
            }
            else
            {
                Whitelabel_Wallet_unload_sts sts = new Whitelabel_Wallet_unload_sts();
                sts.Whitelabelid = userid;
                sts.sts = true;
                sts.type = "Retailer";
                db.Whitelabel_Wallet_unload_sts.Add(sts);
                db.SaveChanges();
            }
            return Json(chk.sts, JsonRequestBehavior.AllowGet);
        }
