        [HttpPost]
        public ActionResult AcceptWalletToBank(int idNo, string txnpass, string RRN, string txtcomment)
        {
            try
            {
                var userid = User.Identity.GetUserId();
                //var password = Encrypt(txnpass);
                //var transpass = db.Whitelabel_Trans_HighSecu_Pass.Where(w => w.WhitelabelId == userid && w.transpass == password).Count();
                //var tranpass = (from paa in db.admin_new_pass where paa.transpass == password select paa).Count();
                if (true)
                {
                    var count = db.Whitelabel_WalletToBankAmountTransferRequests.Where(a => a.Idno == idNo).ToList();
                    if (db.VendorWalletToBankAmountTransferRequests.Any(a => a.Idno == idNo))
                    {
                        var entry = db.VendorWalletToBankAmountTransferRequests.Where(a => a.Idno == idNo).FirstOrDefault();
                        entry.Status = "Success";
                        entry.BankRRN = RRN ?? "";
                        entry.Remark = txtcomment ?? "";
                        entry.type = entry.type;
                        db.SaveChanges();
                    }
                    if (count.Count > 0)
                    {
                        var entry = db.Whitelabel_WalletToBankAmountTransferRequests.Where(a => a.Idno == idNo).FirstOrDefault();
                        entry.Status = "Success";
                        entry.BankRRN = RRN ?? "";
                        entry.Remark = txtcomment ?? "";
                        entry.Type = entry.Type;
                        db.SaveChanges();
                    }
                    else
                    {
                        var Type = db.Whitelabel_WalletToBankAmountTransferRequestsToAdmin.Where(a => a.Idno == idNo).SingleOrDefault().type;
                        if (Type == "Admin")
                        {
                            var requestidwhitelabel = db.Whitelabel_WalletToBankAmountTransferRequestsToAdmin.Where(a => a.Idno == idNo).SingleOrDefault().RequestId;
                            var requestidRetailerwhitelabel = db.Whitelabel_WalletToBankAmountTransferRequests.Where(a => a.RequestId == requestidwhitelabel).SingleOrDefault().RequestId;
                            if (requestidwhitelabel == requestidRetailerwhitelabel)
                            {
                                var entry1 = db.Whitelabel_WalletToBankAmountTransferRequestsToAdmin.Where(a => a.Idno == idNo).FirstOrDefault();
                                entry1.Status = "Success";
                                entry1.BankRRN = RRN ?? "";
                                entry1.Remark = txtcomment ?? "";
                                entry1.type = entry1.type;
                                db.SaveChanges();
                                var entry11 = db.Whitelabel_WalletToBankAmountTransferRequests.Where(a => a.RequestId == requestidwhitelabel).FirstOrDefault();
                                entry11.Status = "Success";
                                //entry11.BankRRN = RRN ?? "";
                                //entry11.Remark = txtcomment ?? "";
                                entry11.Type = entry11.Type;
                                db.SaveChanges();
                            }
                            else
                            {
                                var ViewResponse1 = new { status = "Failed", Message = "Whitelabel and Whitelabel Retailer Request Id is Not Match." };
                                return Json(JsonConvert.SerializeObject(ViewResponse1));
                            }
                        }
                        else
                        {
                            var entry1 = db.Whitelabel_WalletToBankAmountTransferRequestsToAdmin.Where(a => a.Idno == idNo).FirstOrDefault();
                            if(entry1 != null)
                            {
                                entry1.Status = "Success";
                                entry1.BankRRN = RRN ?? "";
                                entry1.Remark = txtcomment ?? "";
                                entry1.type = entry1.type;
                                db.SaveChanges();
                            }
                            
                        }
                    }
                    var ViewResponse = new { status = "Success", Message = "Accepted successfully." };
                    return Json(JsonConvert.SerializeObject(ViewResponse));
                }
                else
                {
                    var ViewResponse = new { status = "Failed", Message = "Transaction Password is Wrong" };
                    return Json(JsonConvert.SerializeObject(ViewResponse));
                }
            }
            catch (Exception ex)
            {
                var ViewResponse = new { status = "Failed", Message = ex.Message };
                return Json(JsonConvert.SerializeObject(ViewResponse));
            }

        }

        [HttpPost]
        public PartialViewResult Unload_Retailer_Wallet(string ddlusers, string RetailerId, string VendorId, string Whitelabel, string ddlstatus, string txt_frm_date, string txt_to_date)
        {
            Whitelabel_CashDepositeAndBank_Info_VM WltUnLd = new Whitelabel_CashDepositeAndBank_Info_VM();
            var currUserid = User.Identity.GetUserId();
            var userid = "";
            if (ddlusers == "Retailer")
            {
                if (RetailerId == "" || RetailerId == null)
                {
                    userid = "ALL";
                }
                else
                {
                    userid = RetailerId;
                }
            }
            ViewBag.chk = "post";
            ViewBag.RetailerId1 = new SelectList(db.Whitelabel_Retailer_Details.Where(a => a.Whitelabelid == userid), "RetailerId", "Frm_Name", null).ToList();

            DateTime frm = Convert.ToDateTime(txt_frm_date);
            DateTime to = Convert.ToDateTime(txt_to_date);
            txt_frm_date = frm.ToString("dd-MM-yyyy");
            txt_to_date = to.ToString("dd-MM-yyyy");
            string[] formats = new[] { "MM/dd/yyyy", "dd-MMM-yyyy",
                            "yyyy-MM-dd", "dd-MM-yyyy", "dd MMM yyyy" };
            DateTime dt = !string.IsNullOrWhiteSpace(txt_frm_date) ? DateTime.ParseExact(txt_frm_date, formats, CultureInfo.InvariantCulture, DateTimeStyles.None) : DateTime.Now;
            DateTime dt1 = !string.IsNullOrWhiteSpace(txt_to_date) ? DateTime.ParseExact(txt_to_date, formats, CultureInfo.InvariantCulture, DateTimeStyles.None) : DateTime.Now;
            DateTime frm_date = Convert.ToDateTime(dt).Date;
            DateTime to_date = Convert.ToDateTime(dt1).Date.AddDays(1);
            var sts = db.whitelabel_walletunloadsts.Where(a => a.Status == "Y" && a.WhitelabelID == currUserid).ToList();
            ViewBag.sts = sts.FirstOrDefault().Status;
            ViewBag.type = sts.FirstOrDefault().Type;

            var entries = db.spWhitelabel_WalletUnloadReport(Convert.ToDateTime(frm_date), Convert.ToDateTime(to_date), ddlusers, userid, ddlstatus, currUserid).ToList();
            WltUnLd.Whitelabel_WalletUnloadReport = entries;
            return PartialView("Unload_Retailer_Wallet", WltUnLd);
        }

        [HttpPost]
