            {
                var resultss = (from p in db.Whitelabel_WalletToBankAmountTransferRequests
                                join wrem in db.Whitelabel_Retailer_Details
                                on p.WhitelabelId equals wrem.Whitelabelid
                                where p.WhitelabelId == userid && p.Idno == Idno
                                select new WhitelabelGetDetailsWalletUnload
                                {
