        public ActionResult EditWalletToBankSlab1(int Idno, decimal AmtFromTatkal, decimal AmtToTatkal, decimal TimeTakesTatkal, decimal chargeTatkal, decimal chargeTatkalNEFT, string Role)
        {
            var userid = User.Identity.GetUserId();
            if (ModelState.IsValid)
            {
                var entry = db.Whitelabel_WalletToBankAmountTransferCharge.Where(a => a.Whitelabelid == userid).FirstOrDefault(a => a.Idno == Idno);

                try
                {
                    entry.AmtFromTatkal = AmtFromTatkal;
                    entry.AmtToTatkal = AmtToTatkal;
                    entry.TimeTakesTatkal = TimeTakesTatkal;
                    entry.chargeTatkal = chargeTatkal;
                    entry.chargeTatkalNEFT = chargeTatkalNEFT;
                    db.SaveChanges();
                }
                catch
                {

                }
            }
            Whitelabel_CashDepositeAndBank_Info_VM CashBank = new Whitelabel_CashDepositeAndBank_Info_VM();
            CashBank.WulChargeList = db.Whitelabel_WalletToBankAmountTransferCharge.Where(aa => aa.Whitelabelid == userid && aa.UserRole == Role).ToList();
            return PartialView("_WalletToBankSlabList", CashBank);
        }

        [HttpGet]
        public ActionResult DeleteWalletToBankSlab(int id, string Role)
        {
            var userid = User.Identity.GetUserId();
            Whitelabel_CashDepositeAndBank_Info_VM CashBank = new Whitelabel_CashDepositeAndBank_Info_VM();
            var entry = db.Whitelabel_WalletToBankAmountTransferCharge.Where(a => a.Whitelabelid == userid).FirstOrDefault(a => a.Idno == id);
            if (entry != null)
            {
                db.Whitelabel_WalletToBankAmountTransferCharge.Remove(entry);
                db.SaveChanges();
            }
            return new EmptyResult();
        }
