        [HttpPost]
        public ActionResult _prepaid_comm(PrepaidSlab model)
        {
            var userid = User.Identity.GetUserId();
            foreach (var item in model.common)
            {
                var entry = db.prepaid_whitelabel_common_comm.Find(item.idno);
                entry.mastercomm = item.mastercomm;
                entry.dealercomm = item.dlmcomm;
                entry.retailercomm = item.retailercomm;
                db.SaveChanges();
            }
            PrepaidSlab pmodel = new PrepaidSlab();
            pmodel.common =
           (from p in db.prepaid_whitelabel_common_comm.Where(a => a.whitelabelid == userid)
            join opt in db.Operator_Code on p.optcode equals opt.Operator_id.ToString()
