        #region Postpaid and Utility Slab Setting
        public ActionResult PostpaidUtility_Slab_setting()
        {
            var userid = User.Identity.GetUserId();
            PostpaidUtilitySlab model = new PostpaidUtilitySlab();
            model.common =
           (from p in db.utility_whitelabel_common_comm.Where(a => a.whitelabelid == userid)
            join opt in db.Operator_Code on p.optcode equals opt.Operator_id.ToString()
            where opt.Operator_type == "Broadband"
            select new PostpaidCommon
            {
                idno = p.idno,
                optcode = p.optcode,
                OperatorName = opt.operator_Name,
                mastercomm = p.mastercomm,
                dlmcomm = p.dealercomm,
                retailercomm = p.retailercomm,
                dlm_rem_comm = p.dlm_rem_comm,
                gst = p.gst,
                surcharge = p.SurCharge,
                opttype = opt.Operator_type
            }).OrderBy(aa => aa.opttype).ToList();
            var opttype = db.Operator_Code.Where(
            aa => aa.Operator_type == "Broadband" || aa.Operator_type == "Electricity"
            || aa.Operator_type == "Gas" || aa.Operator_type == "Insurance"
            || aa.Operator_type == "Landline" || aa.Operator_type == "Loan"
            || aa.Operator_type == "PostPaid" || aa.Operator_type == "Water" || aa.Operator_type == "LPG Gas" || aa.Operator_type == "Fastag").OrderBy(aa => aa.Operator_type).ToList();
            var list = opttype.Select(a => new SelectListItem { Text = a.Operator_type, Value = a.Operator_type });
            model.OPttype = list.GroupBy(x => x.Text).Select(x => x.First()).ToList();
            return View(model);
        }

        [HttpPost]
        public ActionResult _common_utility_comm(PostpaidUtilitySlab model, string ddlVal)
        {
            var userid = User.Identity.GetUserId();
            if (ddlVal == "" || ddlVal == null)
            {
                ddlVal = "Broadband";
            }
            if (model.common != null)
            {
                var optid = 0;
                foreach (var item in model.common)
                {
                    var entry = db.utility_whitelabel_common_comm.Find(item.idno);
                    optid = Convert.ToInt32(entry.optcode);
                    entry.mastercomm = item.mastercomm;
                    entry.dealercomm = item.dlmcomm;
                    entry.dlm_rem_comm = item.dlm_rem_comm;
                    entry.retailercomm = item.retailercomm;
                    entry.gst = item.gst;
                    entry.SurCharge = item.surcharge;
                    db.SaveChanges();
                }
                ddlVal = db.Operator_Code.Where(aa => aa.Operator_id == optid).SingleOrDefault().Operator_type;
            }
            PostpaidUtilitySlab model1 = new PostpaidUtilitySlab();
            model1.common =
           (from p in db.utility_whitelabel_common_comm.Where(a => a.whitelabelid == userid)
            join opt in db.Operator_Code on p.optcode equals opt.Operator_id.ToString()
            where opt.Operator_type == ddlVal
            select new PostpaidCommon
            {
                idno = p.idno,
                optcode = p.optcode,
                OperatorName = opt.operator_Name,
                mastercomm = p.mastercomm,
                dlmcomm = p.dealercomm,
                dlm_rem_comm = p.dlm_rem_comm,
                retailercomm = p.retailercomm,
                gst = p.gst,
                surcharge = p.SurCharge,
                opttype = opt.Operator_type
            }).OrderBy(aa => aa.opttype).ToList();
            var opttype = db.Operator_Code.Where(
            aa => aa.Operator_type == "Broadband" || aa.Operator_type == "Electricity"
            || aa.Operator_type == "Gas" || aa.Operator_type == "Insurance"
            || aa.Operator_type == "Landline" || aa.Operator_type == "Loan"
            || aa.Operator_type == "PostPaid" || aa.Operator_type == "Water" || aa.Operator_type == "LPG Gas" || aa.Operator_type == "Fastag").OrderBy(aa => aa.Operator_type).ToList();
            var list = opttype.Select(a => new SelectListItem { Text = a.Operator_type, Value = a.Operator_type, Selected = a.Operator_type == ddlVal ? true : false });
            model1.OPttype = list.GroupBy(x => x.Text).Select(x => x.First()).ToList();
            return PartialView(model1);
        }

