                            var list1 = db.Whitelabel_Retailer_Details.Where(aa => aa.Whitelabelid == CurrUserid && aa.DealerId == dlmid).Select(a => new SelectListItem { Text = a.Frm_Name, Value = a.RetailerId, Selected = a.RetailerId == userid ? true : false }).ToList();

                            model.UserId = list;
                            model.RetailerId = list1;
                            model.Email = rem.Where(aa => aa.RetailerId == userid).SingleOrDefault().Email;
                            model.Name = rem.Where(aa => aa.RetailerId == userid).SingleOrDefault().RetailerName;
                            model.Phone = rem.Where(aa => aa.RetailerId == userid).SingleOrDefault().Mobile;
                            model.role = "Retailer";
                        }
                        else
                        {
                            model.dlmremuser =
                     (from m in db.Whitelabel_utility_dlm_rem_comm.Where(a => a.whitelabelid == CurrUserid)
                      join u in db.Users on m.userid equals u.UserId
                      join opt in db.Operator_Code on m.optcode equals opt.Operator_id.ToString()
                      where m.userid == userid && opt.Operator_type == ddlVal
                      select new PostpaiddlmRetailer
                      {
                          idno = m.idno,
                          userid = m.userid,
                          optcode = m.optcode,
                          OperatorName = opt.operator_Name,
                          comm = m.comm,
                          Email = u.Email,
                          RolesName = "Retailer"
                      }).OrderBy(p => p.OperatorName).ToList();

                            var list = db.whitelabel_Dealer_Details.Where(a => a.Whitelabelid == CurrUserid).Select(a => new SelectListItem { Text = a.FarmName, Value = a.DealerId, Selected = a.DealerId == userid ? true : false }).ToList();
                            var list1 = db.Whitelabel_Retailer_Details.Where(aa => aa.Whitelabelid == CurrUserid && aa.DealerId == userid).Select(a => new SelectListItem { Text = a.Frm_Name, Value = a.RetailerId }).ToList();

                            model.UserId = list;
                            model.RetailerId = list1;
                            model.Email = "";
                            model.Name = "";
                            model.Phone = "";
                            model.role = "Retailer";
                        }
                    }
                    model.UpdateRetailer =
                     (from com in db.utility_whitelabel_common_comm.Where(a => a.whitelabelid == CurrUserid)
                      join opt in db.Operator_Code on com.optcode equals opt.Operator_id.ToString()
                      where opt.Operator_type == ddlVal
                      select new UpdatePostpaidRetailer
                      {
                          idno = com.idno,
                          OperatorName = opt.operator_Name,
                          comm = com.retailercomm,
                          gst = com.gst,
                          optcode = com.optcode,
                          surcharge = com.SurCharge,
                          opttype = opt.Operator_type
                      }).OrderBy(aa => aa.opttype).ToList();
                }
                //end
                var opttype = db.Operator_Code.Where(
                aa => aa.Operator_type == "Broadband" || aa.Operator_type == "Electricity"
                || aa.Operator_type == "Gas" || aa.Operator_type == "Insurance"
                || aa.Operator_type == "Landline" || aa.Operator_type == "Loan"
                || aa.Operator_type == "PostPaid" || aa.Operator_type == "Water" || aa.Operator_type == "LPG Gas" || aa.Operator_type == "Fastag").OrderBy(aa => aa.Operator_type).ToList();
                var listopt = opttype.Select(a => new SelectListItem { Text = a.Operator_type, Value = a.Operator_type, Selected = a.Operator_type == ddlVal ? true : false });
                model.OPttype = listopt.GroupBy(x => x.Text).Select(x => x.First()).ToList();
                return PartialView(model);
            }
            //End User

        }
        [HttpPost]
        public ActionResult _UpdatePostpaidUtilitySlab(PostpaidUtilitySlab model, string ddlUserId, string role, string Retailerid)
        {
            var userid = User.Identity.GetUserId();
            if (role == "Master")
            {
                if (ddlUserId != "")
                {
                    foreach (var item in model.Materuser)
                    {
                        var entry = db.Whitelabel_utility_master_comm.Where(a => a.whitelabelid == userid).Single(a => a.userid == ddlUserId && a.optcode == item.optcode);
                        entry.comm = item.comm;
                        entry.gst = item.gst;
                        db.SaveChanges();
                    }
                }
                else
                {
                    foreach (var item in model.UpdateMaster)
                    {
                        db.spWhitelabel_Update_All_PostpaidandUtility_comm("Master", item.optcode, item.comm, item.gst, "", 0, userid);
                    }
                }
            }
            if (role == "Dealer")
            {
                if (ddlUserId != "")
                {
                    foreach (var item in model.Dealeruser)
                    {
                        var entry = db.utility_whitelabel_dealer_comm.Where(a => a.whitelabelid == userid).Single(a => a.userid == ddlUserId && a.optcode == item.optcode);
                        entry.comm = item.comm;
                        entry.gst = item.gst;
                        db.SaveChanges();
                    }
                }
                else
                {
                    foreach (var item in model.UpdateDealer)
                    {
                        db.spWhitelabel_Update_All_PostpaidandUtility_comm("Dealer", item.optcode, item.comm, item.gst, "", 0, userid);
                    }
                }
            }
            if (role == "Retailer")
            {
                if (Retailerid != "")
                {
                    if (model.Retaileruser != null)
                    {
                        foreach (var item in model.Retaileruser)
                        {
                            var entry = db.utility_whitelabel_retailer_comm.Where(a => a.whitelabelid == userid).Single(a => a.userid == Retailerid && a.optcode == item.optcode);
                            entry.comm = item.comm;
                            entry.gst = item.gst;
                            entry.SurCharge = item.surcharge;
                            db.SaveChanges();
                        }
                    }
                }
                else
                {
                    foreach (var item in model.UpdateRetailer)
                    {
                        db.spWhitelabel_Update_All_PostpaidandUtility_comm("Retailer", item.optcode, item.comm, item.gst, ddlUserId, item.surcharge, userid);
                    }
                }
            }
            return RedirectToAction("PostpaidUtility_Slab_setting");
        }
