        [HttpPost]
        public ActionResult _utility_charge_type(string usertype, string rchtype)
        {
            var userid = User.Identity.GetUserId();
            if (rchtype != null)
            {
                bool esp = true;
                var chk = db.Whitelabel_Utility_Charge_type.Where(aa => aa.userid == userid && aa.rch_type == rchtype && aa.user_type == usertype).SingleOrDefault();
                if (chk.Fixedrs == true)
                {
                    esp = false;
                }
                chk.Fixedrs = esp;
                db.SaveChanges();
            }
            PostpaidUtilitySlab model = new PostpaidUtilitySlab();
            model.chargetype = (from com in db.Whitelabel_Utility_Charge_type.Where(a => a.userid == userid)
                                select new chargetypecomm
                                {
                                    rch_type = com.rch_type,
                                    user_type = com.user_type,
                                    fixedrs = com.Fixedrs
                                }).ToList();

            return PartialView(model);
        }
