        public ActionResult Pancard_Slab_Setting()
        {
            var userid = User.Identity.GetUserId();

            var commslab = db.Pancard_whitelabel_CommonAll_comm.Where(a => a.whitelabelid == userid).ToList();
            PancardSlabModel model = new PancardSlabModel();
