            return View(model);
        }
        [HttpPost]
        public ActionResult _Common_pancard(PancardSlabModel model)
        {
            var userid = User.Identity.GetUserId();

            foreach (var item in model.common)
            {
                var entry = db.Pancard_whitelabel_CommonAll_comm.Find(item.idno);
                entry.tokenvalueDigital = item.tokenvalueDigital;
                entry.masterdigital = item.masterdigital;
                entry.dealerDigital = item.dealerDigital;
                entry.retailerDigital = item.retailerDigital;
                entry.PurchaseDigital = item.PurchaseDigital;

                entry.tokenvaluePhysical = item.tokenvaluePhysical;
                entry.masterphysical = item.masterphysical;
                entry.dealerPhysical = item.dealerPhysical;
                entry.retailerPhysical = item.retailerPhysical;
                entry.PurchasePhysical = item.PurchasePhysical;

                entry.dlmremvaluedigital = item.dlmremvaluedigital;
                entry.dlmremvaluephysical = item.dlmremvaluephysical;
                entry.gst = item.gst;
                db.SaveChanges();
            }
            return PartialView(model);
        }
