            {
                PancardSlabModel model = new PancardSlabModel();
                //List<imps_master_comm> masteruser = null;
                //Master User
                if (role == "Master")
                {
                    if (string.IsNullOrWhiteSpace(userid))
                    {
                        model.Materuser =
                     (from m in db.Pancard_whitelabel_master_comm
                      join u in db.Users on m.userid equals u.UserId
                      where m.userid == userid && m.whitelabelid == whitelabelid
                      select new MasterPanComm
                      {
                          idno = m.idno,
                          userid = m.userid,
                          tokenvalueDigital = m.tokenvalueDigital,
                          commDigital = m.commDigital,
