        [HttpPost]
        public ActionResult _UpdatePANSlab(PancardSlabModel model, string ddlUserId, string role)
        {
            var whitelabelid = User.Identity.GetUserId();
            //master User
            if (role == "Master")
            {
                if (ddlUserId != "")
                {
                    foreach (var item in model.Materuser)
                    {
                        var entry = db.Pancard_whitelabel_master_comm.Where(a => a.whitelabelid == whitelabelid).Single(a => a.userid == ddlUserId);
                        entry.tokenvalueDigital = item.tokenvalueDigital;
                        entry.tokenvaluePhysical = item.tokenvaluePhysical;
                        entry.commDigital = item.commDigital;
                        entry.commPhysical = item.commPhysical;
                        entry.gst = item.gst;
                        db.SaveChanges();
                    }
                }
                else
                {
                    foreach (var item in model.UpdateMaster)
                    {
                        db.spWhitelabel_Update_Pancard_All_userSlab(whitelabelid, "Master", item.tokenvalueDigital, item.commDigital, item.tokenvaluePhysical, item.commPhysical, item.gst);
                    }


                }
            }
            //Dealer User
            if (role == "Dealer")
            {
                if (ddlUserId != "")
                {
                    foreach (var item in model.Dealeruser)
                    {
                        var entry = db.Pancard_whitelabel_dealer_comm.Where(a => a.whitelabelid == whitelabelid).Single(a => a.userid == ddlUserId);
                        entry.tokenvalueDigital = item.tokenvalueDigital;
                        entry.commDigital = item.commDigital;
                        entry.tokenvaluePhysical = item.tokenvaluePhysical;
                        entry.commPhysical = item.commPhysical;
                        entry.gst = item.gst;
                        db.SaveChanges();
                    }
                }
                else
                {
                    foreach (var item in model.UpdateDealer)
                    {
                        db.spWhitelabel_Update_Pancard_All_userSlab(whitelabelid, "Dealer", item.tokenvalueDigital, item.commDigital, item.tokenvaluePhysical, item.commPhysical, item.gst);
                    }


                }
            }
            //end dealer user

            //Retailer User
            if (role == "Retailer")
            {
                if (ddlUserId != "")
                {
                    foreach (var item in model.Retaileruser)
                    {
                        var entry = db.Pancard_whitelabel_retailer_comm.Where(a => a.whitelabelid == whitelabelid).Single(a => a.userid == ddlUserId);
                        entry.tokenvalueDigital = item.tokenvalueDigital;
                        entry.commDigital = item.commDigital;
                        entry.tokenvaluePhysical = item.tokenvaluePhysical;
                        entry.commPhysical = item.commPhysical;
                        entry.gst = item.gst;
                        db.SaveChanges();
                    }
                }
                else
                {
                    foreach (var item in model.UpdateRetailer)
                    {
                        db.spWhitelabel_Update_Pancard_All_userSlab(whitelabelid, "Retailer", item.tokenvalueDigital, item.commDigital, item.tokenvaluePhysical, item.commPhysical, item.gst);
                    }


                }
            }
            //end Retailer user

            return RedirectToAction("Pancard_Slab_Setting");
        }
