        #region SlabAeps
        public ActionResult AepsSlab()
        {
            var whitelabelid = User.Identity.GetUserId();
            WhitelabelAEPSCommonModel model = new WhitelabelAEPSCommonModel();
            try
            {
                var commonSlab = db.Whitelabel_Aeps_common_comm_new.Where(a => a.whitelabelid == whitelabelid).ToList();

                model.common = commonSlab;
                model.UserId = new List<SelectListItem>() { new SelectListItem { Text = "No data", Value = "No Data" } };
                return View(model);
            }
            catch { return View(model); }
        }
        [HttpPost]
        public ActionResult _common_aeps(WhitelabelAEPSCommonModel model)
        {
            var whitelabelid = User.Identity.GetUserId();
            foreach (var item in model.common)
            {
                var entry = db.Whitelabel_Aeps_common_comm_new.Find(item.idno);
                entry.comm = item.comm;
                entry.maxrs = item.maxrs;
                entry.minvalue = item.minvalue;
                entry.M_statement = item.M_statement;
                entry.aadharpay = item.aadharpay;
                db.SaveChanges();
            }
            var commonSlab = db.Whitelabel_Aeps_common_comm_new.Where(a => a.whitelabelid == whitelabelid).ToList();
            model.common = commonSlab;
            return PartialView(model);
        }
