                   (from m in db.Whitelabel_Aeps_dlm_rem_comm.Where(a => a.whitelabelid == whitelabelid)
                    join u in db.Users on m.userid equals u.UserId
                    where m.userid == dlmid
                    select new AEPSRetailerComm
                    {
                        idno = m.idno,
                        userid = m.userid,
                        comm = m.comm,
                        maxrs = m.maxrs,
                        minbal = m.minvalue,
                        Email = u.Email,
                        M_statement = m.M_statement,
                        aadharpay = m.aadharpay,
                        RolesName = "Retailer"
                    }).ToList();

                            var list = db.whitelabel_Dealer_Details.Where(a => a.Whitelabelid == whitelabelid).Select(a => new SelectListItem { Text = a.FarmName, Value = a.DealerId, Selected = a.DealerId == dlmid ? true : false }).ToList();
                            var rem = db.Whitelabel_Retailer_Details.Where(a => a.Whitelabelid == whitelabelid);
                            var list1 = rem.Where(aa => aa.DealerId == dlmid).Select(a => new SelectListItem { Text = a.Frm_Name, Value = a.RetailerId }).ToList();

                            model.UserId = list;
                            model.Retailerid = list1;
                            model.Name = "";
                            model.Phone = "";
                            model.Email = "";
                            model.role = "Retailer";
                        }
                    }
                    else
                    {
                        var upchk = "REM";
                        //
                        var dlmchk = db.whitelabel_Dealer_Details.Where(aa => aa.DealerId == userid && aa.Whitelabelid == whitelabelid).SingleOrDefault();
                        if (dlmchk != null)
                        {
                            upchk = "DLM";
                            var remchk = db.Whitelabel_Retailer_Details.Where(aa => aa.RetailerId == ddlUserIdrem && aa.Whitelabelid == whitelabelid).SingleOrDefault();
                            if (remchk != null)
                            {
                                upchk = "REM";
                            }
                        }
                        if (upchk == "DLM")
                        {
                            model.Retaileruser =
                        (from m in db.Whitelabel_Aeps_dlm_rem_comm.Where(a => a.whitelabelid == whitelabelid)
                         join u in db.Users on m.userid equals u.UserId
                         where m.userid == userid
                         select new AEPSRetailerComm
                         {
                             idno = m.idno,
                             userid = m.userid,
                             comm = m.comm,
                             maxrs = m.maxrs,
                             minbal = m.minvalue,
                             Email = u.Email,
                             M_statement = m.M_statement,
                             aadharpay = m.aadharpay,
                             RolesName = "Retailer"
                         }).ToList();
                            var list = db.whitelabel_Dealer_Details.Where(a => a.Whitelabelid == whitelabelid).Select(a => new SelectListItem { Text = a.FarmName, Value = a.DealerId, Selected = a.DealerId == userid ? true : false }).ToList();
                            var rem = db.Whitelabel_Retailer_Details.Where(a => a.Whitelabelid == whitelabelid);
                            var list1 = rem.Where(aa => aa.DealerId == userid).Select(a => new SelectListItem { Text = a.Frm_Name, Value = a.RetailerId }).ToList();

                            model.UserId = list;
                            model.Retailerid = list1;
                            model.Name = "";
                            model.Phone = "";
                            model.Email = "";
                            model.role = "Retailer";
                        }
                        else
                        {
                            model.Retaileruser =
                            (from m in db.Whitelabel_Aeps_comm_new.Where(a => a.Whitelabelid == whitelabelid)
                             join u in db.Users on m.userid equals u.UserId
                             where m.userid == ddlUserIdrem
                             select new AEPSRetailerComm
                             {
                                 idno = m.idno,
                                 userid = m.userid,
                                 comm = m.comm,
                                 maxrs = m.maxrs,
                                 minbal = m.minvalue,
                                 Email = u.Email,
                                 M_statement = m.M_statement,
                                 aadharpay = m.aadharpay,
                                 RolesName = "Retailer"
                             }).ToList();
                            var list = db.whitelabel_Dealer_Details.Where(a => a.Whitelabelid == whitelabelid).Select(a => new SelectListItem { Text = a.FarmName, Value = a.DealerId, Selected = a.DealerId == userid ? true : false }).ToList();
                            var rem = db.Whitelabel_Retailer_Details.Where(a => a.Whitelabelid == whitelabelid);
                            var list1 = rem.Where(aa => aa.DealerId == userid).Select(a => new SelectListItem { Text = a.Frm_Name, Value = a.RetailerId, Selected = a.RetailerId == ddlUserIdrem ? true : false }).ToList();

                            model.UserId = list;
                            model.Retailerid = list1;
                            model.Name = rem.Where(aa => aa.RetailerId == ddlUserIdrem).SingleOrDefault().RetailerName;
                            model.Phone = rem.Where(aa => aa.RetailerId == ddlUserIdrem).SingleOrDefault().Mobile;
                            model.Email = rem.Where(aa => aa.RetailerId == ddlUserIdrem).SingleOrDefault().Email;
                            model.role = "Retailer";
                        }
                    }
                    var UpdateAllMaster = (from mstcomm in db.Whitelabel_Aeps_common_comm_new.Where(a => a.whitelabelid == whitelabelid)
                                           where mstcomm.usertype == "Distributor-Rem"
                                           select new AEPSUpdateRetailerComm
                                           {
                                               idno = 0,
                                               comm = mstcomm.comm,
                                               maxrs = mstcomm.maxrs,
                                               minbal = mstcomm.minvalue,
                                               M_statement = mstcomm.M_statement,
                                               aadharpay = mstcomm.aadharpay,
                                           }).ToList();
                    model.UpdateRetailer = UpdateAllMaster;

                }
                //End Retailer
                return PartialView(model);
            }
        }
        [HttpPost]
        public ActionResult AepsUserWise(WhitelabelAEPSCommonModel model, string ddlUserId, string role)
        {
            var whitelabelid = User.Identity.GetUserId();
            //master User
            if (role == "Master")
            {
                if (ddlUserId != "")
                {
                    foreach (var item in model.Materuser)
                    {
                        var entry = db.Whitelabel_Aeps_comm_new.Where(a => a.Whitelabelid == whitelabelid).Single(a => a.userid == ddlUserId);
                        entry.comm = item.comm;
                        entry.minvalue = item.minbal;
                        entry.maxrs = item.maxrs;

                        db.SaveChanges();
                    }
                }
                else
                {
                    foreach (var item in model.UpdateMaster)
                    {
                        db.spWhitelabel_Update_AEPS_All_userSlab_new(whitelabelid, "Master", item.comm, item.maxrs, item.minbal, item.M_statement, item.aadharpay);
                    }

                }
            }
            //Dealer User
            if (role == "Dealer")
            {
                if (ddlUserId != "")
                {
                    foreach (var item in model.Dealeruser)
                    {
                        var entry = db.Whitelabel_Aeps_comm_new.Where(a => a.Whitelabelid == whitelabelid).Single(a => a.userid == ddlUserId);
                        entry.comm = item.comm;
                        entry.minvalue = item.minbal;
                        entry.maxrs = item.maxrs;

                        db.SaveChanges();
                    }
                }
                else
                {
                    foreach (var item in model.UpdateDealer)
                    {
                        db.spWhitelabel_Update_AEPS_All_userSlab_new(whitelabelid, "Dealer", item.comm, item.maxrs, item.minbal, item.M_statement, item.aadharpay);
                    }
                }
            }
            //end dealer user
            //Retailer User
            if (role == "Retailer")
            {
                if (ddlUserId != "")
                {
                    foreach (var item in model.Retaileruser)
                    {
                        var entry = db.Whitelabel_Aeps_comm_new.Where(a => a.Whitelabelid == whitelabelid).Single(a => a.userid == ddlUserId);
                        entry.comm = item.comm;
                        entry.minvalue = item.minbal;
                        entry.maxrs = item.maxrs;

                        db.SaveChanges();
                    }
                }
                else
                {
                    foreach (var item in model.UpdateRetailer)
                    {
                        db.spWhitelabel_Update_AEPS_All_userSlab_new(whitelabelid, "Retailer", item.comm, item.maxrs, item.minbal, item.M_statement, item.aadharpay);
                    }
                }
            }
            //end Retailer user
            return RedirectToAction("AepsSlab");
        }
