        #region MIcro_atm
        public ActionResult Micro_Atm()
        {
            var whitelabelid = User.Identity.GetUserId();
            var data = TempData.Peek("data");

            MicroAtmSlabModel model = new MicroAtmSlabModel();
            try
            {
                var commonSlab = db.Whitelabel_Common_Microatm_comm.Where(a => a.WhitelabelId == whitelabelid).ToList();

                model.common = commonSlab;

                model.UserId = new List<SelectListItem>() { new SelectListItem { Text = "No data", Value = "No Data" } };

                var mpossstatus0 = db.mpos_gst_tds_status.SingleOrDefault(aa => aa.type_ == "Cash");

                var mpossstatus = db.Whitelabel_mpos_gst_tds_status.Where(a => a.WhitelabelId == whitelabelid).SingleOrDefault(aa => aa.type_ == "Cash");
                ViewBag.Cashgststatus = mpossstatus == null ? false : mpossstatus.gststatus;
                ViewBag.Cashtdsstatus = mpossstatus == null ? false : mpossstatus.tdsstaus;
                var mpossstatus1 = db.Whitelabel_mpos_gst_tds_status.Where(a => a.WhitelabelId == whitelabelid).SingleOrDefault(aa => aa.type_ == "Sale");
                ViewBag.Salegststatus = mpossstatus1 == null ? false : mpossstatus1.gststatus;
                ViewBag.Saletdsstatus = mpossstatus1 == null ? false : mpossstatus1.tdsstaus;
            }
            catch { }
            return View(model);
        }
        [HttpPost]
        public ActionResult _Common_Microatm(MicroAtmSlabModel model)
        {
            var whitelabelid = User.Identity.GetUserId();
            foreach (var item in model.common)
            {
                var entry = db.Whitelabel_Common_Microatm_comm.Find(item.idno);
                entry.Charge = item.Charge;
                db.SaveChanges();
            }
            var commonSlab = db.Whitelabel_Common_Microatm_comm.Where(a => a.WhitelabelId == whitelabelid).ToList();
            model.common = commonSlab;
            return PartialView(model);

        }
        [HttpPost]
        public PartialViewResult _UserMicroatmSlab(string role, string userid, MicroAtmSlabModel model12, string ddlUserId, string credite_type, string credite_typeAll, string Button, string ddlUserIdrem, string dlmid)
        {
            var whitelabelid = User.Identity.GetUserId();

            List<SelectListItem> Provinces = new List<SelectListItem>();
            MicroAtmSlabModel model = new MicroAtmSlabModel();
            if (ddlUserId == null)
            {
                if (role == "Master")
                {
                    if (string.IsNullOrWhiteSpace(userid))
                    {
                        model.MasterMicroatmUser =
                        (from m in db.Whitelabel_MicroAtm_comm_details
                         join u in db.Users on m.userid equals u.UserId
                         where m.userid == userid && m.WhitelabelId == whitelabelid
                         select new MasterMicroatmComm
                         {
                             idno = m.idno,
                             userid = m.userid,
                             usertype = m.usertype,
                             cardtype = m.cardtype,
                             cardcategorytype = m.cardcategorytype,
                             cardname = m.cardname,
                             minvalue = m.minvalue,
                             maxvalue = m.maxvalue,
                             charge = m.charge,
                             chargetype = m.chargetype,
                             Email = u.Email
                         }).ToList();
                        var master = db.Whitelabel_Superstokist_details.Where(a => a.Whitelabelid == whitelabelid);
                        model.UserId = master.Select(a => new SelectListItem { Text = a.FarmName, Value = a.SSId, Selected = a.SSId == userid ? true : false }).ToList();
                        model.Retailerid = Provinces;
                        model.Name = "";
                        model.Phone = "";
                        model.Email = "";

                    }
                    else
                    {
                        model.MasterMicroatmUser =
                         (from m in db.Whitelabel_MicroAtm_comm_details
                          join u in db.Users on m.userid equals u.UserId
                          where m.userid == userid && m.WhitelabelId == whitelabelid
                          select new MasterMicroatmComm
