        [HttpPost]
        public ActionResult _common_Microatm_cash(MicroatmcashCommonModel model)
        {
            var whitelabelid = User.Identity.GetUserId();

            foreach (var item in model.common)
            {
                var entry = db.WhitelabelId_Microatmcash_common_comm_new.Find(item.idno);
                entry.comm = item.comm;
                entry.maxrs = item.maxrs;
                entry.minvalue = item.minvalue;
                db.SaveChanges();
            }
            var commonSlab = db.WhitelabelId_Microatmcash_common_comm_new.Where(a => a.WhitelabelId == whitelabelid).ToList();
            model.common = commonSlab;
            return PartialView(model);
        }
