        [HttpPost]
        public ActionResult MicroAtm_Cash_UserWise(MicroatmcashCommonModel model, string ddlUserId, string role)
        {
            var whitelabelid = User.Identity.GetUserId();

            if (role == "Master")
            {
                if (ddlUserId != "")
                {
                    foreach (var item in model.Materuser)
                    {
                        var entry = db.Whitelabel_Microatmcash_comm_new.Where(a => a.userid == ddlUserId && a.WhitelabelId == whitelabelid).Single();
                        entry.comm = item.comm;
                        entry.minvalue = item.minbal;
                        entry.maxrs = item.maxrs;

                        db.SaveChanges();
                    }
                }
                else
                {
                    foreach (var item in model.UpdateMaster)
                    {
                        db.spWhitelabel_Update_Microatmcash_All_userSlab_new(whitelabelid, "Master", item.comm, item.maxrs, item.minbal);
                    }

                }
            }
            if (role == "Dealer")
            {
                if (ddlUserId != "")
                {
                    foreach (var item in model.Dealeruser)
                    {
                        var entry = db.Whitelabel_Microatmcash_comm_new.Where(a => a.userid == ddlUserId && a.WhitelabelId == whitelabelid).Single();
                        entry.comm = item.comm;
                        entry.minvalue = item.minbal;
                        entry.maxrs = item.maxrs;

                        db.SaveChanges();
                    }
                }
                else
                {
                    foreach (var item in model.UpdateDealer)
                    {
                        db.spWhitelabel_Update_Microatmcash_All_userSlab_new(whitelabelid, "Dealer", item.comm, item.maxrs, item.minbal);
                    }
                }
            }
            if (role == "Retailer")
            {
                if (ddlUserId != "")
                {
                    foreach (var item in model.Retaileruser)
                    {
                        var entry = db.Whitelabel_Microatmcash_comm_new.Where(a => a.userid == ddlUserId && a.WhitelabelId == whitelabelid).Single();
                        entry.comm = item.comm;
                        entry.minvalue = item.minbal;
                        entry.maxrs = item.maxrs;

                        db.SaveChanges();
                    }
                }
                else
                {
                    foreach (var item in model.UpdateRetailer)
                    {
                        db.spWhitelabel_Update_Microatmcash_All_userSlab_new(whitelabelid, "Retailer", item.comm, item.maxrs, item.minbal);
                    }
                }
            }
            return RedirectToAction("AepsSlab");
        }
