        #region Gift card Slab Setting
        public ActionResult Giftcard_Slab_setting()
        {
            var userid = User.Identity.GetUserId();
            Whitelabel_GiftcardSlab model = new Whitelabel_GiftcardSlab();
            model.common =
           (from p in db.Whitelabel_gift_common_comm.Where(a => a.whitelabelid == userid)
            join opt in db.Operator_Code on p.optcode equals opt.Operator_id.ToString()
            select new GiftcardCommon
            {
                idno = p.idno,
                optcode = p.optcode,
                OperatorName = opt.operator_Name,
                mastercomm = p.mastercomm,
                dlmcomm = p.dealercomm,
                retailercomm = p.retailercomm
            }).ToList();
            return View(model);
        }
        [HttpPost]
        public ActionResult _common_giftCard(Whitelabel_GiftcardSlab model)
        {
            var userid = User.Identity.GetUserId();
            foreach (var item in model.common)
            {
                var entry = db.Whitelabel_gift_common_comm.Find(item.idno);
                entry.mastercomm = item.mastercomm;
                entry.dealercomm = item.dlmcomm;
                entry.retailercomm = item.retailercomm;
                db.SaveChanges();
            }
            model.common =
           (from p in db.Whitelabel_gift_common_comm.Where(a => a.whitelabelid == userid)
            join opt in db.Operator_Code on p.optcode equals opt.Operator_id.ToString()
            select new GiftcardCommon
            {
                idno = p.idno,
                optcode = p.optcode,
                OperatorName = opt.operator_Name,
                mastercomm = p.mastercomm,
                dlmcomm = p.dealercomm,
                retailercomm = p.retailercomm

            }).ToList();
            return PartialView(model);
        }
