        [HttpPost]
        public ActionResult _UpdateGiftcardSlab(Whitelabel_GiftcardSlab model, string ddlUserId, string role, string Retailerid)
        {
            var userid = User.Identity.GetUserId();
            if (role == "Master")
            {
                if (ddlUserId != "")
                {
                    foreach (var item in model.Materuser)
                    {
                        var entry = db.Whitelabel_giftcard_master_comm.Where(a => a.whitelabelid == userid).Single(a => a.masterid == ddlUserId && a.opt_code == item.optcode);
                        entry.comm = item.comm;
                        db.SaveChanges();
                    }
                }
                else
                {
                    foreach (var item in model.UpdateMaster)
                    {
                        db.spWhitelabel_Update_All_Giftcard_comm("Master", item.optcode, item.comm, "", userid);
                    }
                }
            }
            if (role == "Dealer")
            {
                if (ddlUserId != "")
                {
                    foreach (var item in model.Dealeruser)
                    {
                        var entry = db.Whitelabel_giftcard_dealer_comm.Where(a => a.whitelabelid == userid).Single(a => a.dealerid == ddlUserId && a.optcode == item.optcode);
                        entry.comm = item.comm;
                        db.SaveChanges();
                    }
                }
                else
                {
                    foreach (var item in model.UpdateDealer)
                    {
                        db.spWhitelabel_Update_All_Giftcard_comm("Dealer", item.optcode, item.comm, "", userid);
                    }
                }
            }
            if (role == "Retailer")
            {
                if (Retailerid != "")
                {
                    if (model.Retaileruser != null)
                    {
                        foreach (var item in model.Retaileruser)
                        {
                            var entry = db.Whitelabel_giftcard_retailer_comm.Where(a => a.whitelabelid == userid).Single(a => a.retailerid == Retailerid && a.optcode == item.optcode);
                            entry.comm = item.comm;
                            db.SaveChanges();
                        }
                    }
                }
                else
                {
                    foreach (var item in model.UpdateRetailer)
                    {
                        db.update_All_Giftcard_comm("Retailer", item.optcode, item.comm, ddlUserId);
                    }
                }
            }

            return RedirectToAction("Giftcard_Slab_setting");
        }
