        public ActionResult Security_Slab_setting()
        {
            var userid = User.Identity.GetUserId();
            Whitelabel_SecuritySlab model = new Whitelabel_SecuritySlab();
            model.common =
           (from p in db.Whitelabel_Security_common_comm.Where(a => a.whitelabelid == userid)
            select new SecurityCommon
            {
                idno = p.idno,
                optcode = "Norton",
                OperatorName = "Norton",
                mastercomm = p.mastercomm,
                dlmcomm = p.dlmcomm,
                dlm_rem_comm = p.dlm_rem_comm
            }).ToList();
            return View(model);
        }
        [HttpPost]
        public ActionResult _Security_comm(Whitelabel_SecuritySlab model)
        {
            var userid = User.Identity.GetUserId();
            foreach (var item in model.common)
            {
                var entry = db.Whitelabel_Security_common_comm.Find(item.idno);
                entry.mastercomm = item.mastercomm;
                entry.dlmcomm = item.dlmcomm;
                entry.dlm_rem_comm = item.dlm_rem_comm;
                db.SaveChanges();
            }
            Whitelabel_SecuritySlab pmodel = new Whitelabel_SecuritySlab();
            pmodel.common =
           (from p in db.Whitelabel_Security_common_comm.Where(a => a.whitelabelid == userid)
            select new SecurityCommon
            {
                idno = p.idno,
                optcode = "Norton",
                OperatorName = "Norton",
                mastercomm = p.mastercomm,
                dlmcomm = p.dlmcomm,
                dlm_rem_comm = p.dlm_rem_comm
            }).ToList();
            return PartialView(pmodel);
            // return RedirectToAction("Prepaid_Slab_setting");
        }
