        [HttpGet]
        public ActionResult OperatorIndex()
        {
            var userid = User.Identity.GetUserId();

            var itemTypesList = new List<SelectListItem>();
            itemTypesList.AddRange(Enum.GetValues(typeof(Whitelabel_CategoryService)).Cast<Whitelabel_CategoryService>().Select(
                        (item, index) => new SelectListItem
                        {
                            Text = item.ToString(),
                            Value = item.ToString()

                        }).ToList());
            ViewBag.RequiredCategory = itemTypesList;

            ViewBag.retailer = new SelectList(db.Whitelabel_Retailer_Details.Where(a => a.Whitelabelid == userid), "RetailerId", "RetailerName", null);
            vmWhitelabel_OperatorIndex vmodel = new vmWhitelabel_OperatorIndex();

            var Opt_List = (from OptCode in db.Operator_Code.Where(z => z.Operator_type == "PrePaid" || z.Operator_type == "DTH").ToList()
                            join WtOptCode in db.whitelabel_operator_code.Where(x => x.whitelabelid == userid)
                            on OptCode.Operator_id.ToString() equals WtOptCode.optid
                            select new OperatorList
                            {
                                Operator_Id = OptCode.Operator_id.ToString(),
                                Operator_Name = OptCode.operator_Name,
                                Operator_type = OptCode.Operator_type,
                                status = WtOptCode.status,
                                opt_code = OptCode.new_opt_code
                            }).ToList();

            vmodel.OptCodeList = Opt_List;

            var Utility_Opt_List = (from OptCode in db.Operator_Code.Where(z => z.Operator_type == "PostPaid" || z.Operator_type == "Electricity" || z.Operator_type == "Landline"
                                    || z.Operator_type == "Broadband" || z.Operator_type == "Water" || z.Operator_type == "Gas").ToList()
                                    join WtOptCode in db.whitelabel_operator_code.Where(x => x.whitelabelid == userid)
                                    on OptCode.Operator_id.ToString() equals WtOptCode.optid
                                    select new OperatorList
                                    {
                                        Operator_Id = OptCode.Operator_id.ToString(),
                                        Operator_Name = OptCode.operator_Name,
                                        Operator_type = OptCode.Operator_type,
                                        status = WtOptCode.status,
                                        opt_code = OptCode.new_opt_code
                                    }).ToList();

            vmodel.UitlityOptList = Utility_Opt_List;

            var Financial_Opt_List = (from OptCode in db.Operator_Code.Where(z => z.Operator_type == "Money" || z.Operator_type == "INDO NEPAL"
                                      || z.Operator_type == "PAN" || z.Operator_type == "Loan" || z.Operator_type == "DigitalVoucher" || z.Operator_type == "Insurance")
                                      join WtOptCode in db.whitelabel_operator_code.Where(x => x.whitelabelid == userid)
                                      on OptCode.Operator_id.ToString() equals WtOptCode.optid
                                      select new OperatorList
                                      {
                                          Operator_Id = OptCode.Operator_id.ToString(),
                                          Operator_Name = OptCode.operator_Name,
                                          Operator_type = OptCode.Operator_type,
                                          status = WtOptCode.status,
                                          opt_code = OptCode.new_opt_code
                                      }).ToList();

            vmodel.FinancialOptList = Financial_Opt_List;

            var Travels_Opt_List = (from OptCode in db.Operator_Code.Where(z => z.Operator_type == "Bus" || z.Operator_type == "Hotel" || z.Operator_type == "Flight")
                                    join WtOptCode in db.whitelabel_operator_code.Where(x => x.whitelabelid == userid)
                                    on OptCode.Operator_id.ToString() equals WtOptCode.optid
                                    select new OperatorList
                                    {
                                        Operator_Id = OptCode.Operator_id.ToString(),
                                        Operator_Name = OptCode.operator_Name,
                                        Operator_type = OptCode.Operator_type,
                                        status = WtOptCode.status,
                                        opt_code = OptCode.new_opt_code
                                    }).ToList();

            vmodel.TravelsOptList = Travels_Opt_List;

            var Others_Opt_List = (from OptCode in db.Operator_Code.Where(z => z.Operator_type == "DTH-Booking")
                                   join WtOptCode in db.whitelabel_operator_code.Where(x => x.whitelabelid == userid)
                                   on OptCode.Operator_id.ToString() equals WtOptCode.optid
                                   select new OperatorList
                                   {
                                       Operator_Id = OptCode.Operator_id.ToString(),
                                       Operator_Name = OptCode.operator_Name,
                                       Operator_type = OptCode.Operator_type,
                                       status = WtOptCode.status,
                                       opt_code = OptCode.new_opt_code
                                   }).ToList();

            vmodel.OthersOptList = Others_Opt_List;

            var optype = db.Operator_Code.Select(a => a.Operator_type).Distinct().ToList();
            IEnumerable<SelectListItem> selectoptypetlist = from g in optype
                                                            select new SelectListItem
                                                            {
                                                                Value = g,
                                                                Text = g
                                                            };
            ViewBag.onlyoptype = new SelectList(selectoptypetlist, "Value", "Text");
            return View(vmodel);
        }
        public JsonResult FillOperatorType(string name)
        {
            var userid = User.Identity.GetUserId();

            if (name == "PrePaid")
            {
                IEnumerable<SelectListItem> selectoptlist = (from opt in db.Operator_Code.ToList()
                                                             join wopt in db.whitelabel_operator_code.Where(a => a.whitelabelid == userid)
                                                             on opt.Operator_id.ToString() equals wopt.optid
                                                             where opt.Operator_type == name || opt.Operator_type == "DTH"
                                                             select new SelectListItem
                                                             {
                                                                 Value = opt.Operator_id.ToString(),
                                                                 Text = opt.operator_Name
                                                             });

                ViewBag.Operatorsname = new SelectList(selectoptlist, "Value", "Text");
                return Json(ViewBag.Operatorsname, JsonRequestBehavior.AllowGet);
            }
            else if (name == "PostPaid" || name == "Electricity" || name == "PostPaid" || name == "Landline" || name == "Broadband" || name == "Water" || name == "Gas")
            {
                IEnumerable<SelectListItem> selectoptlist = (from opt in db.Operator_Code.ToList()
                                                             join wopt in db.whitelabel_operator_code.Where(a => a.whitelabelid == userid)
                                                             on opt.Operator_id.ToString() equals wopt.optid
                                                             where opt.Operator_type == name
                                                             select new SelectListItem
                                                             {
