        [HttpPost]
        public ActionResult BlockDealerUser(string Distributorlist, string DOperator, string DCategory, string DService)
        {
            var userid = User.Identity.GetUserId();

            int status = 0;
            if (DCategory == "PrePaid" || DService == "Utility")
            {
                if (DOperator == "")
                {
                    var myList = (from a in db.Whitelabel_dlm_opt_code.Where(a => a.whitelabel_id == userid)
                                  join c in db.Operator_Code on a.optid equals c.Operator_id.ToString()
                                  where c.Operator_type == DCategory || c.Operator_type == "DTH" && a.dlmid == Distributorlist
                                  select a).ToList();
                    if (myList != null)
                    {
                        myList.ForEach(x => x.status = false);
                    }
                }
                else if (DOperator != "")
                {
                    var result = db.Whitelabel_dlm_opt_code.Where(x => x.whitelabel_id == userid && x.dlmid == Distributorlist && x.optid == DOperator).FirstOrDefault();
                    if (result != null)
                    {
                        result.status = false;
                        db.Entry(result).State = EntityState.Modified;
                    }
                }
            }

            else if (DService == "PostPaid" || DService == "Electricity" || DService == "Gas" || DService == "Broadband" || DService == "Landline" || DService == "Insurance" || DService == "Loan" || DService == "DTH-Booking")
            {

                var myList = (from a in db.Whitelabel_dlm_opt_code.Where(a => a.whitelabel_id == userid)
                              join c in db.Operator_Code on a.optid equals c.Operator_id.ToString()
                              where c.Operator_type == DService && a.dlmid == Distributorlist
                              select a).ToList();
                myList.ForEach(x => x.status = false);
            }

            else
            {
