        public ActionResult StatusupdateOnCredit(int? id, string rem, string opertype)
        {
            var userid = User.Identity.GetUserId();
            int status = 0;
            if (id.Value == 0)
            {
                var result = db.Whitelabel_Retailer_Details.Where(x => x.Whitelabelid == userid && x.RetailerId == rem).FirstOrDefault();
                if (result != null)
                {
                    if (opertype == "DMT")
                    {
                        result.moneyCreaditsts = true;
                        db.Entry(result).State = EntityState.Modified;
                    }
                    else if (opertype == "PAN")
                    {
                        result.pancardCreaditsts = true;
                        db.Entry(result).State = EntityState.Modified;
                    }
                    if (opertype == "AEPS")
                    {
                        result.AepsMposCreaditstatus = true;
                        db.Entry(result).State = EntityState.Modified;
                    }
                    else if (opertype == "MPOS")
                    {
                        result.MposCreaditsts = true;
                        db.Entry(result).State = EntityState.Modified;
                    }
                    if (opertype == "Flight")
                    {
                        result.FlighCreaditsts = true;
                        db.Entry(result).State = EntityState.Modified;
                    }
                    else if (opertype == "Bus")
                    {
                        result.BusCreaditsts = true;
                        db.Entry(result).State = EntityState.Modified;
                    }
                    if (opertype == "Hotel")
                    {
                        result.HotelCreaditsts = true;
                        db.Entry(result).State = EntityState.Modified;
                    }
                    else if (opertype == "Indo Nepal")
                    {
                        result.IndonepalCreaditsts = true;
                        db.Entry(result).State = EntityState.Modified;
                    }
                    if (opertype == "Digital Voucher")
                    {
                        result.giftcardCreaditsts = true;
                        db.Entry(result).State = EntityState.Modified;
                    }
                    status = db.SaveChanges();
                }
            }
            else
            {
                var result = db.Whitelabel_retailer_operator_code.Where(x => x.whitelabelid == userid && x.idno == id.Value).FirstOrDefault();
                if (result != null)
                {
                    result.CreaditStatus = true;
                    db.Entry(result).State = EntityState.Modified;
                    status = db.SaveChanges();
                }
            }
            var myList = db.block_operator_list();

            return Json(new { status = status, list = myList }, JsonRequestBehavior.AllowGet);
        }
