                                   opt_code = OptCode.new_opt_code
                               }).ToList();

            var result = new SelectList(resulttable, "Operator_id", "operator_Name", null);

            return Json(result, JsonRequestBehavior.AllowGet);

        }
        public PartialViewResult BindTableOperatorname(string name, string opertype)
        {
            var userid = User.Identity.GetUserId();

            vmWhitelabel_OperatorIndex vmodel = new vmWhitelabel_OperatorIndex();
            var resulttable = (from OptCode in db.Operator_Code.ToList()
                               join woptcode in db.whitelabel_operator_code.Where(a => a.whitelabelid == userid).ToList()
                               on OptCode.Operator_id.ToString() equals woptcode.optid
                               select new OperatorList
                               {
                                   Operator_Id = OptCode.Operator_id.ToString(),
                                   Operator_Name = OptCode.operator_Name,
                                   Operator_type = OptCode.Operator_type,
                                   status = OptCode.status == "Y" ? true : false,
                                   opt_code = OptCode.new_opt_code
                               }).ToList();
            //var resulttable = db.Operator_Code.ToList();
            if (opertype == "Postpaid")
            {

                if (name != null && name != "")
                {
                    vmodel.UitlityOptList = resulttable.Where(z => z.Operator_type == name).ToList();
                }
                else
                {
                    vmodel.UitlityOptList = resulttable.Where(z => z.Operator_type == "PostPaid" ||
           z.Operator_type == "Electricity" || z.Operator_type == "Landline"
           || z.Operator_type == "Broadband" || z.Operator_type == "Water"
           || z.Operator_type == "Gas").ToList();

                }

                return PartialView("_UtilityAllServices", vmodel);
            }

            if (opertype == "Finance")
            {
                if (!string.IsNullOrEmpty(name))
                {
                    vmodel.FinancialOptList = resulttable.Where(aa => aa.Operator_type == name).ToList();
                }

                else
                {
                    vmodel.FinancialOptList = resulttable.Where(z => z.Operator_type == "Money" ||
                z.Operator_type == "INDO NEPAL" || z.Operator_type == "PAN"
                || z.Operator_type == "Loan" || z.Operator_type == "DigitalVoucher"
                || z.Operator_type == "Insurance").ToList();
                }
                return PartialView("_FinanceAllServices", vmodel);
            }
            if (opertype == "Other")
            {
                if (!string.IsNullOrEmpty(name))
                {
                    vmodel.OthersOptList = resulttable.Where(aa => aa.Operator_type == name).ToList();
                }

                else
                {
                    vmodel.OthersOptList = resulttable.Where(z => z.Operator_type == "DTH-Booking").ToList();
                }
                return PartialView("_OthersRelatedServices", vmodel);
            }
            if (opertype == "Travel")
            {
                if (!string.IsNullOrEmpty(name))
                {
                    vmodel.TravelsOptList = (from OptCode in db.Operator_Code.Where(z => z.Operator_type == name).ToList()
                                             join woptcode in db.whitelabel_operator_code.Where(a => a.whitelabelid == userid).ToList()
                                             on OptCode.Operator_id.ToString() equals woptcode.optid
                                             select new OperatorList
                                             {
                                                 Operator_Id = OptCode.Operator_id.ToString(),
                                                 Operator_Name = OptCode.operator_Name,
                                                 Operator_type = OptCode.Operator_type,
                                                 status = OptCode.status == "Y" ? true : false,
                                                 opt_code = OptCode.new_opt_code
                                             }).ToList();

                }
                else
                {
                    vmodel.TravelsOptList = (from OptCode in db.Operator_Code.Where(z => z.Operator_type == "Bus" || z.Operator_type == "Hotel" || z.Operator_type == "Flight").ToList()
                                             join woptcode in db.whitelabel_operator_code.Where(a => a.whitelabelid == userid).ToList()
                                             on OptCode.Operator_id.ToString() equals woptcode.optid
                                             select new OperatorList
                                             {
                                                 Operator_Id = OptCode.Operator_id.ToString(),
                                                 Operator_Name = OptCode.operator_Name,
                                                 Operator_type = OptCode.Operator_type,
                                                 status = OptCode.status == "Y" ? true : false,
                                                 opt_code = OptCode.new_opt_code
                                             }).ToList();
                }
                return PartialView("_TravelsServices", vmodel);
            }
            else if (opertype == "PrePaid")
            {
                if (name != null && name != "")
                {
                    vmodel.OptCodeList = resulttable.Where(aa => aa.Operator_type == name).ToList();
                }
                else
                {
                    vmodel.OptCodeList = resulttable.Where(aa => aa.Operator_type == "PrePaid" || aa.Operator_type == "DTH").ToList();
                }
                return PartialView("_PrePaidDTHService", vmodel);

            }
            return PartialView("_PrePaidDTHService", resulttable);
        }
        public JsonResult BlockAllAPI(string name)
        {
            var userid = User.Identity.GetUserId();
            if (name == "retailer")
            {
                var whitelabelRetailers = db.Whitelabel_Retailer_Details.Where(a => a.Whitelabelid == userid).ToList();
                var idList = whitelabelRetailers.Where(x => x.moneysts == "0" || x.pancardsts == "N"
                || x.Mpossts == "N" || x.Indonepalsts == "N" || x.Hotelsts == "N" || x.giftcardsts == "N"
                || x.Flighsts == "N" || x.Bussts == "N" || x.AepsMposstatus == "N" || x.pancardCreaditsts == false
                || x.AepsMposCreaditstatus == false || x.MposCreaditsts == false || x.moneyCreaditsts == false || x.IndonepalCreaditsts == false
                || x.HotelCreaditsts == false || x.giftcardCreaditsts == false || x.BusCreaditsts == false || x.FlighCreaditsts == false).ToList();


                idList.ForEach(x =>
                {
                    x.moneysts = "1";
                    x.pancardsts = "Y";
                    x.Mpossts = "Y";
                    x.Indonepalsts = "Y";
                    x.Hotelsts = "Y";
                    x.giftcardsts = "Y";
                    x.Flighsts = "Y";
                    x.Bussts = "Y";
                    x.AepsMposstatus = "Y";
                    x.pancardCreaditsts = true;
                    x.AepsMposCreaditstatus = true;
                    x.MposCreaditsts = true;
                    x.moneyCreaditsts = true;
                    x.IndonepalCreaditsts = true;
                    x.HotelCreaditsts = true;
                    x.giftcardCreaditsts = true;
                    x.BusCreaditsts = true;
                    x.FlighCreaditsts = true;

                });

                var whitelabelOpt = db.Whitelabel_retailer_operator_code.Where(x => x.whitelabelid == userid).ToList();
                var apioperlist = whitelabelOpt.Where(x => x.status == false || x.CreaditStatus == false).ToList();
                apioperlist.ForEach(x => { x.status = true; x.CreaditStatus = true; });
                var res = db.SaveChanges();

                IEnumerable<spWhitelabel_block_operator_list_Result> mylist;
                mylist = db.spWhitelabel_block_operator_list(userid);
                return Json(new { status = res, list = mylist, user = 2 }, JsonRequestBehavior.AllowGet);
            }
            if (name == "Dealer")
            {
                var whitelabelDealers = db.whitelabel_Dealer_Details.Where(a => a.Whitelabelid == userid).ToList();
                var idList = whitelabelDealers.Where(x => x.moneysts == false || x.pancardsts == "N"
                || x.Mpossts == "N" || x.Hotelsts == "N" || x.giftcardsts == "N"
                || x.Flighsts == "N" || x.Bussts == "N" || x.AepsMposstatus == "N").ToList();


                idList.ForEach(x =>
                {
                    x.moneysts = true;
                    x.pancardsts = "Y";
                    x.Mpossts = "Y";
                    x.Hotelsts = "Y";
                    x.giftcardsts = "Y";
                    x.Flighsts = "Y";
                    x.Bussts = "Y";
                    x.AepsMposstatus = "Y";
                });

                var apioperlist = db.Whitelabel_dlm_opt_code.Where(x => x.status == false && x.whitelabel_id == userid).ToList();
                apioperlist.ForEach(x => x.status = true);
                var res = db.SaveChanges();
                IEnumerable<spWhitelabel_block_operatorDealer_list_Result> mylist;

                mylist = db.spWhitelabel_block_operatorDealer_list(userid);
                return Json(new { status = res, list = mylist, user = 4 }, JsonRequestBehavior.AllowGet);

            }
            int status = 0;
            return Json(status, JsonRequestBehavior.AllowGet);

        }


        public JsonResult BindDistributor()
        {
            var userid = User.Identity.GetUserId();

            ViewBag.dlm = new SelectList(db.whitelabel_Dealer_Details.Where(a => a.Whitelabelid == userid), "Dealerid", "DealerName", null);

            List<Whitelabel_CategoryService> myLevels = Enum.GetValues(typeof(Whitelabel_CategoryService)).Cast<Whitelabel_CategoryService>().ToList();

            var itemTypesList = new List<SelectListItem>();
            itemTypesList.AddRange(Enum.GetValues(typeof(Whitelabel_CategoryService)).Cast<Whitelabel_CategoryService>().Select(
                        (item, index) => new SelectListItem
                        {
                            Text = item.ToString(),
                            Value = item.ToString()

                        }).ToList());
            ViewBag.RequiredCategory = itemTypesList;

            return Json(new { dealer = ViewBag.dlm, list = ViewBag.RequiredCategory }, JsonRequestBehavior.AllowGet);
        }


        public ActionResult BlockOperatorPrepaid(int? id, string statuschk, string opertype, DateTime? blockdate = null)
        {
            vmWhitelabel_OperatorIndex vmodel = new vmWhitelabel_OperatorIndex();
            var userid = User.Identity.GetUserId();
            var optid = Convert.ToString(id.Value);
            var result = db.whitelabel_operator_code.FirstOrDefault(z => z.optid == optid && z.whitelabelid == userid);
            if (statuschk == "Y")
            {
                result.status = false;
            }
            else if (statuschk == "N")
            {
                result.status = true;
            }
            db.Entry(result).State = EntityState.Modified;


            var status = db.SaveChanges();

            var resulttable = db.Operator_Code.ToList();


            if (opertype == "Postpaid")
            {
                var Utility_Opt_List = (from OptCode in db.Operator_Code.Where(z => z.Operator_type == "PostPaid" || z.Operator_type == "Electricity" || z.Operator_type == "Landline"
                                    || z.Operator_type == "Broadband" || z.Operator_type == "Water" || z.Operator_type == "Gas").ToList()
                                        join WtOptCode in db.whitelabel_operator_code.Where(x => x.whitelabelid == userid)
                                        on OptCode.Operator_id.ToString() equals WtOptCode.optid
                                        select new OperatorList
                                        {
                                            Operator_Id = OptCode.Operator_id.ToString(),
                                            Operator_Name = OptCode.operator_Name,
                                            Operator_type = OptCode.Operator_type,
                                            status = WtOptCode.status,
                                            opt_code = OptCode.new_opt_code
                                        }).ToList();

                vmodel.UitlityOptList = Utility_Opt_List;

                return PartialView("_UtilityAllServices", vmodel);
            }
            else if (opertype == "Finance")
            {
                var Financial_Opt_List = (from OptCode in db.Operator_Code.Where(z => z.Operator_type == "Money" || z.Operator_type == "INDO NEPAL"
                                      || z.Operator_type == "PAN" || z.Operator_type == "Loan" || z.Operator_type == "DigitalVoucher" || z.Operator_type == "Insurance")
                                          join WtOptCode in db.whitelabel_operator_code.Where(x => x.whitelabelid == userid)
                                          on OptCode.Operator_id.ToString() equals WtOptCode.optid
                                          select new OperatorList
                                          {
                                              Operator_Id = OptCode.Operator_id.ToString(),
                                              Operator_Name = OptCode.operator_Name,
                                              Operator_type = OptCode.Operator_type,
                                              status = WtOptCode.status,
                                              opt_code = OptCode.new_opt_code
                                          }).ToList();

                vmodel.FinancialOptList = Financial_Opt_List;


                return PartialView("_FinanceAllServices", vmodel);
            }

            else if (opertype == "Other")
            {
                var Others_Opt_List = (from OptCode in db.Operator_Code.Where(z => z.Operator_type == "DTH-Booking")
                                       join WtOptCode in db.whitelabel_operator_code.Where(x => x.whitelabelid == userid)
                                       on OptCode.Operator_id.ToString() equals WtOptCode.optid
                                       select new OperatorList
                                       {
                                           Operator_Id = OptCode.Operator_id.ToString(),
                                           Operator_Name = OptCode.operator_Name,
                                           Operator_type = OptCode.Operator_type,
                                           status = WtOptCode.status,
                                           opt_code = OptCode.new_opt_code
                                       }).ToList();

                vmodel.OthersOptList = Others_Opt_List;

                return PartialView("_OthersRelatedServices", vmodel);
            }

            if (opertype == "Travel")
            {
                var Travels_Opt_List = (from OptCode in db.Operator_Code.Where(z => z.Operator_type == "Bus" || z.Operator_type == "Hotel" || z.Operator_type == "Flight")
                                        join WtOptCode in db.whitelabel_operator_code.Where(x => x.whitelabelid == userid)
                                        on OptCode.Operator_id.ToString() equals WtOptCode.optid
                                        select new OperatorList
                                        {
                                            Operator_Id = OptCode.Operator_id.ToString(),
                                            Operator_Name = OptCode.operator_Name,
                                            Operator_type = OptCode.Operator_type,
                                            status = WtOptCode.status,
                                            opt_code = OptCode.new_opt_code
                                        }).ToList();

                vmodel.TravelsOptList = Travels_Opt_List;

                return PartialView("_TravelsServices", vmodel);
            }

            else if (opertype == "PrePaid")
            {
                var Opt_List = (from OptCode in db.Operator_Code.Where(z => z.Operator_type == "PrePaid" || z.Operator_type == "DTH").ToList()
                                join WtOptCode in db.whitelabel_operator_code.Where(x => x.whitelabelid == userid)
                                on OptCode.Operator_id.ToString() equals WtOptCode.optid
                                select new OperatorList
                                {
                                    Operator_Id = OptCode.Operator_id.ToString(),
                                    Operator_Name = OptCode.operator_Name,
                                    Operator_type = OptCode.Operator_type,
                                    status = WtOptCode.status,
                                    opt_code = OptCode.new_opt_code
                                }).ToList();

                vmodel.OptCodeList = Opt_List;

                return PartialView("_PrePaidDTHService", vmodel);

            }

            return PartialView("_PrePaidDTHService", resulttable);
        }

