        public ActionResult Outside_logo()
        {
            var userid = User.Identity.GetUserId();

            JSONReadWrite readWrite = new JSONReadWrite();
            var red = readWrite.Read("LogoBackgroundColor.json", "~/Areas/WHITELABEL/Models/JsonFile/");
            dynamic people = JsonConvert.DeserializeObject(red);
            if (people != null)
            {
                ViewBag.colors = people.ColorCode.ToString();
            }
            var v = db.tblOutsideLogoes.Where(p => p.UserId == userid && p.Role == "WHITELABEL").ToList();
            ViewBag.logoimage = v;
            ViewBag.login = db.tblLoginContents.Where(p => p.UserId == userid).ToList();
            var vv = db.tblfavicons.Where(p => p.UserId == userid && p.Role == "WHITELABEL").ToList();
            ViewBag.faviconimage = vv;
            var vvv = db.tblHeaderLogoes.Where(p => p.UserId == userid && p.Role == "WHITELABEL").ToList();
            ViewBag.logoHeaderimage = vvv;

            var lg = db.tblWhiteLabelLoginBackImages.Where(p => p.UserID == userid && p.Role == "WHITELABEL").ToList();

            if (lg.Count > 0)
            {
                var repeatImg = lg.SingleOrDefault(a => a.UsedFor == "Repeat");
                ViewBag.showimg2 = repeatImg != null ? repeatImg.otherimage : null;

                var repeatStatus = lg.SingleOrDefault(a => a.UsedFor == "Repeat");
                ViewBag.Status2 = repeatStatus != null ? repeatStatus.StatusCheck : "N";

                var singleImg = lg.SingleOrDefault(a => a.UsedFor == "Single");
                ViewBag.showimg3 = singleImg != null ? singleImg.otherimage : null;

                var singleStatus = lg.SingleOrDefault(a => a.UsedFor == "Single");
                ViewBag.Status3 = singleStatus != null ? singleStatus.StatusCheck : "N";
            }

            var chk = lg.Where(a => a.StatusCheck == "Y").SingleOrDefault();
            ViewBag.sts = chk != null ? chk.UsedFor : "none";

            return View();
        }
