        public ActionResult AddColor(Vastwebmulti.Areas.WHITELABEL.Models.JsonFile.Whitelabel_LogoBackColor personModel)
        {
            var userid = User.Identity.GetUserId();

            var admin = "WHITELABEL";
            //changecolor cc = new changecolor();
            Vastwebmulti.Areas.WHITELABEL.Models.JsonFile.Whitelabel_LogoBackColor cc = new Vastwebmulti.Areas.WHITELABEL.Models.JsonFile.Whitelabel_LogoBackColor();

            List<Vastwebmulti.Areas.WHITELABEL.Models.JsonFile.Whitelabel_LogoBackColor> people = new List<Vastwebmulti.Areas.WHITELABEL.Models.JsonFile.Whitelabel_LogoBackColor>();
            JSONReadWrite readWrite = new JSONReadWrite();
            people = JsonConvert.DeserializeObject<List<Vastwebmulti.Areas.WHITELABEL.Models.JsonFile.Whitelabel_LogoBackColor>>(readWrite.Read("Whitelabel_LogoBackColor.json", "~/Areas/WHITELABEL/Models/JsonFile/"));

            var roletype = people.Where(p => p.UserId == userid).ToList();

            var role = roletype.Count == 0 ? "" : roletype.SingleOrDefault().Role;

            var v = people.Where(p => p.UserId == userid).FirstOrDefault();
            if (role == admin)
            {
                var id = (from tbl in people where tbl.UserId == userid select tbl).SingleOrDefault();

                id.UserId = string.IsNullOrWhiteSpace(userid) ? v.UserId : userid;
                id.Role = string.IsNullOrWhiteSpace(admin) ? v.Role : admin;
                id.ColorCode = string.IsNullOrWhiteSpace(personModel.ColorCode) ? v.ColorCode : personModel.ColorCode;

                people = JsonConvert.DeserializeObject<List<Vastwebmulti.Areas.WHITELABEL.Models.JsonFile.Whitelabel_LogoBackColor>>(readWrite.Read("Whitelabel_LogoBackColor.json", "~/Areas/WHITELABEL/Models/JsonFile/"));
                Vastwebmulti.Areas.WHITELABEL.Models.JsonFile.Whitelabel_LogoBackColor person = people.FirstOrDefault(x => x.UserId == userid);
                if (person == null)
                {
                    try
                    {
                        int NextId = people.LastOrDefault().Idno;
                        id.Idno = NextId + 1;
                        people.Add(id);
                    }
                    catch
                    {
                        id.Idno = 0;
                        people.Add(id);
                    }
                }
                else
                {
                    int index = people.FindIndex(x => x.UserId == userid);
                    people[index] = id;
                }
                string jSONString = JsonConvert.SerializeObject(people);
                readWrite.Write("Whitelabel_LogoBackColor.json", "~/Areas/WHITELABEL/Models/JsonFile/", jSONString);

                TempData["success"] = "Color Uploaded Sucessfully";
                return RedirectToAction("White_Outer_Color");
            }
            else
            {

                cc.UserId = userid;
                cc.Role = admin;
                cc.ColorCode = personModel.ColorCode;

                people = JsonConvert.DeserializeObject<List<Vastwebmulti.Areas.WHITELABEL.Models.JsonFile.Whitelabel_LogoBackColor>>(readWrite.Read("Whitelabel_LogoBackColor.json", "~/Areas/WHITELABEL/Models/JsonFile/"));
                Vastwebmulti.Areas.WHITELABEL.Models.JsonFile.Whitelabel_LogoBackColor person = people.FirstOrDefault(x => x.UserId == personModel.UserId);
                if (person == null)
                {
                    try
                    {
                        int NextId = (person == null) ? 0 : people.LastOrDefault().Idno;

                        cc.Idno = NextId + 1;
                        people.Add(cc);
                    }
                    catch { }
                }
                else
                {
                    int index = people.FindIndex(x => x.UserId == userid);
                    people[index] = cc;
                }
                string jSONString = JsonConvert.SerializeObject(people);
                readWrite.Write("Whitelabel_LogoBackColor.json", "~/Areas/WHITELABEL/Models/JsonFile/", jSONString);
                TempData["success"] = "Color Uploaded Sucessfully";
                return RedirectToAction("White_Outer_Color");
            }
        }
        [ValidateInput(false)]
        [HttpPost]
        public ActionResult AboutUsContext(Vastwebmulti.Areas.WHITELABEL.Models.JsonFile.AboutUs personModel)
        {
            var userid = User.Identity.GetUserId();

            List<Vastwebmulti.Areas.WHITELABEL.Models.JsonFile.AboutUs> people = new List<Vastwebmulti.Areas.WHITELABEL.Models.JsonFile.AboutUs>();
            JSONReadWrite readWrite = new JSONReadWrite();
            people = JsonConvert.DeserializeObject<List<Vastwebmulti.Areas.WHITELABEL.Models.JsonFile.AboutUs>>(readWrite.Read("AboutUs.json", "~/Areas/WHITELABEL/Models/JsonFile/"));
            Vastwebmulti.Areas.WHITELABEL.Models.JsonFile.AboutUs person = people.FirstOrDefault(x => x.AboutId == personModel.AboutId);
            person.UserId = userid;
            person.Role = "WHITELABEL";


            var id = (from tbl in people where tbl.UserId == userid select tbl).SingleOrDefault();
            id.UserId = string.IsNullOrWhiteSpace(userid) ? id.UserId : userid;
            id.AboutContent = string.IsNullOrWhiteSpace(personModel.AboutContent) ? id.AboutContent : personModel.AboutContent;
            id.Role = string.IsNullOrWhiteSpace(personModel.Role) ? id.Role : personModel.Role;

            if (person == null)
            {
                people.Add(id);
            }
            else
            {
                int index = people.FindIndex(x => x.AboutId == personModel.AboutId);
                people[index] = id;
            }
            string jSONString = JsonConvert.SerializeObject(people);
            readWrite.Write("AboutUs.json", "~/Areas/WHITELABEL/Models/JsonFile/", jSONString);
            return Json(people, JsonRequestBehavior.AllowGet);
        }

