            if (type != null)
            {
                var v = db.tblWhiteLabelLoginBackImages.Where(a => a.UserID == userid && a.UsedFor == type).FirstOrDefault();
                if (v != null)
                {
                    v.StatusCheck = "Y";
                    db.SaveChanges();
