                        imagePath = imagePath1.Replace(" ", string.Empty).Replace("(", string.Empty).Replace(")", string.Empty);

                        var imageThumbPath1 = @"\FooterImages\" + newFileName;
                        imageThumbPath = imageThumbPath1.Replace(" ", string.Empty).Replace("(", string.Empty).Replace(")", string.Empty);

                        if (usedfor == "Repeat")
                        {
                            photo.Resize(300, 300, false, true);
                        }
                        else if (usedfor == "Single")
                        {
                            photo.Resize(1600, 900, false, true);
                        }
                        photo.Save(@"~\" + imageThumbPath);
                    }
                }

                tblWhiteLabelLoginBackImage imagepath = new tblWhiteLabelLoginBackImage();
                var admin = "WHITELABEL";

                var roletype = db.tblWhiteLabelLoginBackImages.Where(p => p.UserID == userid && p.Role == admin && p.UsedFor == usedfor).ToList();
                var role = roletype.Count == 0 ? "" : roletype.SingleOrDefault().Role;
                if (role == admin && roletype.SingleOrDefault().UsedFor == usedfor)
                {
                    var id = (from tbl in db.tblWhiteLabelLoginBackImages where (tbl.UserID == userid && tbl.UsedFor == usedfor) select tbl).SingleOrDefault();
                    id.Role = string.IsNullOrWhiteSpace(admin) ? id.Role : admin;
                    id.UserID = string.IsNullOrWhiteSpace(userid) ? id.UserID : userid;
                    id.otherimage = string.IsNullOrWhiteSpace(imageThumbPath) ? id.otherimage : imageThumbPath;
                    db.SaveChanges();
                    TempData["success"] = "Login Background Image Uploaded Successfully";
                    return RedirectToAction("Outside_logo");
                }
                else
                {
                    imagepath.UserID = userid;
                    imagepath.Role = admin;
                    imagepath.otherimage = imageThumbPath;
                    imagepath.UsedFor = usedfor;
                    imagepath.StatusCheck = "N";
                    db.tblWhiteLabelLoginBackImages.Add(imagepath);
                    db.SaveChanges();
                    TempData["success"] = "Login Background Image Uploaded Successfully";
                    return RedirectToAction("Outside_logo");
                }
            }
            catch (Exception ex)
            {
                ViewBag.Message = "Error while uploading the files.";
            }
            ViewBag.login = db.tblLoginContents.Where(a => a.UserId == userid).ToList();
            return View();
        }
