        #region Bank_Info
        public ActionResult Bank_info()
        {
            var userid = User.Identity.GetUserId();
            Whitelabel_BankInfoList bank = new Whitelabel_BankInfoList();
            bank.bankinfo = db.Whitelabel_bank_info.Where(aa => aa.userid == userid).ToList();
            bank.walletinfo = db.Whitelabel_Wallet_info.Where(aa => aa.userid == userid).ToList();
            return View(bank);
        }
        public ActionResult AddBank(string Banknm, string BranchName, string ifsccode, string accountno, string accounttype, string accountholder, string City)
        {
            var userid = User.Identity.GetUserId();
            Whitelabel_bank_info bank = new Whitelabel_bank_info();
            bank.acno = accountno;
            bank.actype = accounttype;
            bank.address = City;
            bank.banknm = Banknm;
            bank.branch_nm = BranchName;
            bank.createdate = DateTime.Now;
            bank.holdername = accountholder;
            bank.ifsccode = ifsccode;
            bank.userid = userid;
            db.Whitelabel_bank_info.Add(bank);
            db.SaveChanges();
            return RedirectToAction("Bank_info");
        }
        public ActionResult Deletebank(int id)
        {
            var userid = User.Identity.GetUserId();
            var chk = db.Whitelabel_bank_info.Where(aa => aa.idno == id && aa.userid == userid).SingleOrDefault();
            db.Whitelabel_bank_info.Remove(chk);
            db.SaveChanges();
            return Json("", JsonRequestBehavior.AllowGet);
        }
        public ActionResult AddWallet(string walletnm, string walletno, string walletholdername)
        {
            var userid = User.Identity.GetUserId();

            Whitelabel_Wallet_info wall = new Whitelabel_Wallet_info();
            wall.createdate = DateTime.Now;
            wall.userid = userid;
            wall.walletholdername = walletholdername;
            wall.walletname = walletnm;
            wall.walletno = walletno;
            db.Whitelabel_Wallet_info.Add(wall);
            db.SaveChanges();
            return RedirectToAction("Bank_info");
        }

        public ActionResult Deletewallet(int id)
        {
            var userid = User.Identity.GetUserId();
            var chk = db.Whitelabel_Wallet_info.Where(aa => aa.walletid == id && aa.userid == userid).SingleOrDefault();
            db.Whitelabel_Wallet_info.Remove(chk);
            db.SaveChanges();
            return Json("", JsonRequestBehavior.AllowGet);
        }

