        //Change Password
        [HttpGet]
        public ActionResult ChangePassword()
        {
            return View();
        }
        //
        // POST: /Manage/ChangePassword
        [HttpPost]
        [ValidateAntiForgeryToken]
        public async Task<ActionResult> ChangePassword([Bind(Prefix = "Item1")] ChangePasswordViewModel model)
        {
            if (!ModelState.IsValid)
            {
                return View(model);
            }
            var result = await UserManager.ChangePasswordAsync(User.Identity.GetUserId(), model.OldPassword, model.NewPassword);
            if (result.Succeeded)
            {
                var user = await UserManager.FindByIdAsync(User.Identity.GetUserId());
                if (user != null)
                {
                    await SignInManager.SignInAsync(user, isPersistent: false, rememberBrowser: false);
                }

                TempData["Message"] = "Your Password has been Changed Successfully..";
                return RedirectToAction("ChangePassword");
            }
            AddErrors(result);
            return View(model);
        }

        [HttpPost]
        public ActionResult Resend_Transactionpass(string txtemail)
        {
            string userid = User.Identity.GetUserId();
            var chk = db.WhiteLabel_userList.Any(a => a.EmailId == txtemail && a.WhiteLabelID == userid);
            if (chk == true)
            {
                int pin = new Random().Next(1000, 10000);
                var msg = Encrypt(pin.ToString());

                var id = db.Whitelabel_Trans_HighSecu_Pass.Where(s => s.WhitelabelId == userid).SingleOrDefault();
                if (id != null)
                {
                    id.transpass = msg;
                }
                else
                {
                    Whitelabel_Trans_HighSecu_Pass wtp = new Whitelabel_Trans_HighSecu_Pass();
                    wtp.WhitelabelId = userid;
                    wtp.transpass = msg;
                }
                db.SaveChanges();
                var emailid = db.WhiteLabel_userList.Where(a => a.WhiteLabelID == userid).Single().EmailId;
                try
                {
                    CommUtilEmail emailsend = new CommUtilEmail();
                    emailsend.WhiteLabelEmailLimitChk(emailid, emailid, "Transaction Password", "Your Transaction Password Is  " + pin, "No CallBackUrl", userid);
                }
                catch { }
                TempData["success"] = "Your Transaction Password Send Successfully in Your Mail Id . Please Check Your Mail Id.";
            }
            else
            {
                TempData["success"] = "Your Email Not Verify.Please Enter Your Correct Registered Email";
            }

            //TempData["success"] = "Your Transaction Password Send Successfully in Your Mail Id . Please Check Your Mail Id.";
            return RedirectToAction("ChangePassword");
        }
