        [HttpPost]
        public ActionResult Edit_Transactionpass([Bind(Prefix = "Item2")] ChangeTransactionViewModel model)
        {
            try
            {
                string userid = User.Identity.GetUserId();
                var securitypass = db.Whitelabel_Trans_HighSecu_Pass.Where(w => w.WhitelabelId == userid).SingleOrDefault();
                if (securitypass == null)
                {
                    throw new Exception("Something went wrong!");
                }
                var oldpin = securitypass.transpass;

                if (oldpin != Encrypt(model.Oldtransactionpass))
                {
                    TempData["error"] = "Your Old Transaction Password does Not Match .Please Re-Enter Your Old Transaction Password ";
                    return RedirectToAction("ChangePassword");
                }
                var msg = Encrypt(model.Newtransactionpass);

                var id = db.Whitelabel_Trans_HighSecu_Pass.Where(s => s.WhitelabelId == userid).SingleOrDefault();
                id.transpass = msg;
                db.SaveChanges();
                var emailid = db.WhiteLabel_userList.Where(a => a.WhiteLabelID == userid).Single().EmailId;

                CommUtilEmail emailsend = new CommUtilEmail();
                emailsend.WhiteLabelEmailLimitChk(emailid, emailid, "Transaction Password", "Your New Transaction Password Is  " + model.Newtransactionpass, "No CallBackUrl", userid);

                TempData["success"] = "Your Transaction Password Send Successfully in Your Mail Id . Please Check Your Mail Id.";
                return RedirectToAction("ChangePassword");
            }
            catch (Exception ex)
            {
                TempData["error"] = ex.Message;
                return RedirectToAction("ChangePassword");
            }
        }

