        #region Set Target
        public ActionResult Set_target()
        {
            var userid = User.Identity.GetUserId();
            ADMIN.ViewModel.Whitelabel_TargetSetviewmodel vmodel = new ADMIN.ViewModel.Whitelabel_TargetSetviewmodel();
            try
            {

                List<SelectListItem> giftlist = new List<SelectListItem>();
                foreach (var gift in db.Whitelabel_PruductGift.Where(a => a.Whitelabelid == userid))
                {
                    giftlist.Add(new SelectListItem { Text = gift.ProductName, Value = gift.productId.ToString() });
                }

                List<SelectListItem> AllCategory = new List<SelectListItem>();
                foreach (var Category in db.Whitelabel_RetailerSetTarget.Where(a => a.WhitelabelId == userid))
                {
                    AllCategory.Add(new SelectListItem { Text = Category.Categories, Value = Category.Categories });
                }

                IEnumerable<SelectListItem> selectretailerList = from s in db.Whitelabel_Retailer_Details.Where(a => a.Whitelabelid == userid).ToList()
                                                                 select new SelectListItem
                                                                 {
                                                                     Value = s.RetailerId,
                                                                     Text = s.Frm_Name == "" ? s.RetailerName : s.Frm_Name
                                                                 };
                ViewBag.allretailers = new SelectList(selectretailerList, "Value", "Text");

                IEnumerable<SelectListItem> dlmtListss = from s in db.whitelabel_Dealer_Details.Where(a => a.Whitelabelid == userid).ToList()
                                                         select new SelectListItem
                                                         {
                                                             Value = s.DealerId,
                                                             Text = s.FarmName == "" ? s.DealerName : s.FarmName
                                                         };
                ViewBag.alldealers = new SelectList(dlmtListss, "Value", "Text");


                IEnumerable<SelectListItem> mdList = from s in db.Whitelabel_Superstokist_details.Where(a => a.Whitelabelid == userid).ToList()
                                                     select new SelectListItem
                                                     {
                                                         Value = s.SSId,
                                                         Text = s.FarmName == "" ? s.SuperstokistName : s.FarmName
                                                     };
                ViewBag.allmasters = new SelectList(mdList, "Value", "Text");

                DateTime todaysDate = DateTime.Now.Date;
                int month = todaysDate.Month;
                int year = todaysDate.Year;

                dynamic NotVal = null;

                vmodel.tblproductlist = giftlist;
                vmodel.remTargetCategory = db.Whitelabel_RetailerSetTarget.Where(a => a.Date.Value.Month == month && a.Date.Value.Year == year).ToList();
                vmodel.dlmTargetCategory = NotVal;
                vmodel.mdTargetCategory = NotVal;
                ViewBag.Category = AllCategory.ToList();
                vmodel.RoleName = "Retailer";

                return View(vmodel);
            }
            catch
            {
                dynamic NotVal = null;

                vmodel.tblproductlist = NotVal;
                vmodel.remTargetCategory = NotVal;
                vmodel.dlmTargetCategory = NotVal;
                vmodel.mdTargetCategory = NotVal;
                ViewBag.Category = NotVal;
                vmodel.RoleName = "Retailer";

                return View(vmodel);
            }
        }
        public ActionResult UpdateSetTargerRetailer(int targetID, string settarget, string offertype, string txt60achive, string txt70achive, string txt80achive, string txt90achive, string txt100achive, string ddl60achive, string ddl70achive, string ddl80achive, string ddl90achive, string ddl100achive)
        {
            var userid = User.Identity.GetUserId();
            try
            {
                if (offertype == "Fixrupees")
                {
                    ddl60achive = null; ddl70achive = null; ddl80achive = null; ddl90achive = null; ddl100achive = null;
                }
                else if (offertype == "Giftitem")
                {
                    txt60achive = null; txt70achive = null; txt80achive = null; txt90achive = null; txt100achive = null;
                }
                txt60achive = txt60achive == null ? ddl60achive : txt60achive;
                txt70achive = txt70achive == null ? ddl70achive : txt70achive;
                txt80achive = txt80achive == null ? ddl80achive : txt80achive;
                txt90achive = txt90achive == null ? ddl90achive : txt90achive;
                txt100achive = txt100achive == null ? ddl100achive : txt100achive;

                if (targetID > 0)
                {
                    var model = db.Whitelabel_RetailerSetTarget.Where(x => x.targetID == targetID && x.WhitelabelId == userid).FirstOrDefault();
                    if (model != null)
                    {
                        model.settarget = decimal.Parse(settarget);
                        model.Achived60 = txt60achive;
                        model.Achived70 = txt70achive;
                        model.Achived80 = txt80achive;
                        model.Achived90 = txt90achive;
                        model.Achived100 = txt100achive;
                        model.OfferType = offertype;
                        db.SaveChanges();
                    }
                    return Json("Success", JsonRequestBehavior.AllowGet);
                }
                return Json("", JsonRequestBehavior.AllowGet);
            }
            catch { return Json("", JsonRequestBehavior.AllowGet); }
        }
