        public ActionResult TargetAchiveStatus(int targetId, string userRole)
        {
            var userid = User.Identity.GetUserId();
            try
            {
                if (userRole == "retailer")
                {
                    var remId = db.Whitelabel_RetailerSetTarget.Where(x => x.targetID == targetId && x.WhitelabelId == userid).FirstOrDefault();
                    if (remId != null)
                    {
                        remId.Status = remId.Status == true ? false : true;
                        db.SaveChanges();
                    }
                    return Json(remId.Status, JsonRequestBehavior.AllowGet);
                }
                else if (userRole == "dealer")
                {
                    var dlmmodel = db.Whitelabel_DealerSetTarget.Where(x => x.dealertargetid == targetId && x.WhitelabelId == userid).FirstOrDefault();
                    if (dlmmodel != null)
                    {
                        dlmmodel.Status = dlmmodel.Status == true ? false : true;
                        db.SaveChanges();
                    }
                    return Json(dlmmodel.Status, JsonRequestBehavior.AllowGet);
                }
                else if (userRole == "master")
                {
                    var mdmodel = db.Whitelabel_superstockistsettarget.Where(x => x.supersettargetid == targetId && x.WhitelabelId == userid).FirstOrDefault();
                    if (mdmodel != null)
                    {
                        mdmodel.Status = mdmodel.Status == true ? false : true;
                        db.SaveChanges();
                    }
                    return Json(mdmodel.Status, JsonRequestBehavior.AllowGet);
                }
                else
                {
                    return Json("", JsonRequestBehavior.AllowGet);
                }
            }
            catch { return Json("", JsonRequestBehavior.AllowGet); }
        }
        public ActionResult ShowRetailerMonthWiseSetTarget(string monthVal)
        {
            var userid = User.Identity.GetUserId();
            try
            {
                if (monthVal != "" || monthVal != null)
                {
                    if (monthVal == "LastMonth")
                    {
                        DateTime todaysDate = DateTime.Now.AddMonths(-1).Date;

                        int month = todaysDate.Month;
                        int year = todaysDate.Year;

                        ADMIN.ViewModel.Whitelabel_TargetSetviewmodel vmodel = new ADMIN.ViewModel.Whitelabel_TargetSetviewmodel();
                        var LastMonthTarget = db.Whitelabel_RetailerSetTarget.Where(a => a.Date.Value.Month == month && a.Date.Value.Year == year && a.WhitelabelId == userid).ToList();

                        vmodel.remTargetCategory = LastMonthTarget;

                        List<SelectListItem> giftlist = new List<SelectListItem>();
                        foreach (var gift in db.Whitelabel_PruductGift.Where(a => a.Whitelabelid == userid))
                        {
                            giftlist.Add(new SelectListItem { Text = gift.ProductName, Value = gift.productId.ToString() });
                        }
                        vmodel.tblproductlist = giftlist;
                        vmodel.RoleName = "Retailer";
                        return PartialView("_LastMonth", vmodel);
                    }
                    else if (monthVal == "NextMonth")
                    {
                        DateTime todaysDate = DateTime.Now.AddMonths(1).Date;

                        int month = todaysDate.Month;
                        int year = todaysDate.Year;

                        ADMIN.ViewModel.Whitelabel_TargetSetviewmodel vmodel = new ADMIN.ViewModel.Whitelabel_TargetSetviewmodel();
                        var NextMonthTarget = db.Whitelabel_RetailerSetTarget.Where(a => a.Date.Value.Month == month && a.Date.Value.Year == year && a.WhitelabelId == userid).ToList();
                        if (NextMonthTarget.Count == 0) { db.spWhitelabel_InsertDefaultTarget(userid, "Whitelabelretailer", "nextmonth", month, year); }
                        vmodel.remTargetCategory = NextMonthTarget;

                        List<SelectListItem> giftlist = new List<SelectListItem>();
                        foreach (var gift in db.Whitelabel_PruductGift.Where(a => a.Whitelabelid == userid))
                        {
                            giftlist.Add(new SelectListItem { Text = gift.ProductName, Value = gift.productId.ToString() });
                        }
                        vmodel.tblproductlist = giftlist;
                        vmodel.RoleName = "Retailer";
                        return PartialView("_NextMonth", vmodel);
                    }
                    else
                    {
                        DateTime todaysDate = DateTime.Now.Date;

                        int month = todaysDate.Month;
                        int year = todaysDate.Year;

                        ADMIN.ViewModel.Whitelabel_TargetSetviewmodel vmodel = new ADMIN.ViewModel.Whitelabel_TargetSetviewmodel();
                        var CurrentMonthTarget = db.Whitelabel_RetailerSetTarget.Where(a => a.Date.Value.Month == month && a.Date.Value.Year == year && a.WhitelabelId == userid).ToList();
                        if (CurrentMonthTarget.Count == 0) { db.spWhitelabel_InsertDefaultTarget(userid, "Whitelabelretailer", "currentmonth", month, year); }
                        vmodel.remTargetCategory = CurrentMonthTarget;

                        List<SelectListItem> giftlist = new List<SelectListItem>();
                        foreach (var gift in db.Whitelabel_PruductGift.Where(a => a.Whitelabelid == userid))
                        {
                            giftlist.Add(new SelectListItem { Text = gift.ProductName, Value = gift.productId.ToString() });
                        }
                        vmodel.tblproductlist = giftlist;
                        vmodel.RoleName = "Retailer";
                        return PartialView("_CurrentAndNextMonth", vmodel);
                    }
                }
                else
                {
                    return Json("", JsonRequestBehavior.AllowGet);
                }
            }
            catch { return Json("", JsonRequestBehavior.AllowGet); }
        }
