        public ActionResult AchivedHistory(string monthVal, string userRole, string UserId, string ddlcategory)
        {
            var wAdmin = User.Identity.GetUserId();
            ADMIN.ViewModel.Whitelabel_TargetSetviewmodel vmodel = new ADMIN.ViewModel.Whitelabel_TargetSetviewmodel();
            try
            {
                if (monthVal != "" || monthVal != null)
                {
                    int month = monthVal == "LastMonth" ? DateTime.Now.AddMonths(-1).Date.Month : DateTime.Now.Date.Month;
                    int year = monthVal == "LastMonth" ? DateTime.Now.AddMonths(-1).Date.Year : DateTime.Now.Date.Year;

                    IQueryable<Whitelabel_AchivedTarget_History> uu = Enumerable.Empty<Whitelabel_AchivedTarget_History>().AsQueryable();

                    ddlcategory = ddlcategory == "" ? null : ddlcategory;
                    UserId = UserId == "" ? null : UserId;

                    if (ddlcategory != null && UserId != null)
                    {
                        uu = db.Whitelabel_AchivedTarget_History.AsQueryable().Where(a => a.WhitelabelId == wAdmin && a.Achived_Date.Value.Month == month && a.Achived_Date.Value.Year == year && a.userid == UserId && a.Opt_Type == ddlcategory);
                    }
                    else if (UserId != null)
                    {
                        uu = db.Whitelabel_AchivedTarget_History.AsQueryable().Where(a => a.WhitelabelId == wAdmin && a.Achived_Date.Value.Month == month && a.Achived_Date.Value.Year == year && a.userid == UserId);
                    }
                    else if (ddlcategory != null)
                    {
                        uu = db.Whitelabel_AchivedTarget_History.AsQueryable().Where(a => a.WhitelabelId == wAdmin && a.Achived_Date.Value.Month == month && a.Achived_Date.Value.Year == year && a.Role == userRole && a.Opt_Type == ddlcategory);
                    }
                    else
                    {
                        uu = db.Whitelabel_AchivedTarget_History.AsQueryable().Where(a => a.WhitelabelId == wAdmin && a.Achived_Date.Value.Month == month && a.Achived_Date.Value.Year == year && a.Role == userRole);
                    }


                    IQueryable<ADMIN.Models.UsersWise> userDetails = Enumerable.Empty<ADMIN.Models.UsersWise>().AsQueryable();
                    if (userRole == "Retailer")
                    {
                        userDetails = (from rrt in db.Whitelabel_Retailer_Details.Where(a => a.Whitelabelid == wAdmin)
                                       select new ADMIN.Models.UsersWise
                                       {
                                           FarmName = rrt.Frm_Name == "" ? rrt.RetailerName : rrt.Frm_Name,
                                           Name = rrt.RetailerName,
                                           UserId = rrt.RetailerId
                                       });
                    }
                    else if (userRole == "Dealer")
                    {
                        userDetails = (from ddt in db.whitelabel_Dealer_Details.Where(a => a.Whitelabelid == wAdmin)
                                       select new ADMIN.Models.UsersWise
                                       {
                                           FarmName = ddt.FarmName == "" ? ddt.DealerName : ddt.FarmName,
                                           Name = ddt.DealerName,
                                           UserId = ddt.DealerId
                                       });
                    }
                    else if (userRole == "Master")
                    {
                        userDetails = (from mmt in db.Whitelabel_Superstokist_details.Where(a => a.Whitelabelid == wAdmin)
                                       select new ADMIN.Models.UsersWise
                                       {
                                           FarmName = mmt.FarmName == "" ? mmt.SuperstokistName : mmt.FarmName,
                                           Name = mmt.SuperstokistName,
                                           UserId = mmt.SSId
                                       });
                    }
                    //else if (userRole == "Api")
                    //{
                    //    userDetails = (from aat in db.api_user_details
                    //                   select new ADMIN.Models.UsersWise
                    //                   {
                    //                       FarmName = aat.farmname == "" ? aat.username : aat.farmname,
                    //                       Name = aat.username,
                    //                       UserId = aat.apiid
                    //                   });
                    //}
                    var Histlist = (from rem in userDetails
                                    join achHis in uu
                                    on rem.UserId equals achHis.userid
                                    select new ADMIN.Models.AchiveHistory
                                    {
                                        FarmName = rem.FarmName,
                                        Name = rem.Name,
                                        Role = achHis.Role,
                                        Total_TargetSet = achHis.Total_TargetSet,
                                        Opt_Type = achHis.Opt_Type,
                                        Total_Txn_amt = achHis.Total_Txn_amt,
                                        Target_Type = achHis.Target_Type,
                                        Achived_Perce = achHis.Achived_Perce,
                                        Received_Perce = achHis.Received_Perce,
                                        rem_pre = achHis.rem_pre,
                                        rem_post = achHis.rem_post,
                                        total_achived_amt = achHis.total_achived_amt,
                                        Admin_Pre = achHis.Admin_Pre,
                                        Admin_Post = achHis.Admin_Post,
                                        GST = achHis.GST,
                                        TDS = achHis.TDS,
                                        Achived_Date = achHis.Achived_Date
                                    });

                    dynamic NotVal = null;
                    vmodel.AchivedTarget_His = userRole == null || userRole == "" ? NotVal : Histlist;
                }
                return PartialView("_achivedhistory", vmodel);
            }
            catch
            {
                dynamic NotVal = null;
                vmodel.AchivedTarget_His = NotVal;
                return PartialView("_achivedhistory", vmodel);
            }
        }
