        [HttpPost]
        public ActionResult InserProductinsetTarget()
        {
            var userid = User.Identity.GetUserId();
            try
            {
                var images = Request.Files["Productfile"];
                var extn = Path.GetExtension(images.FileName);
                var PName = Request["productname"].ToString();
                var aliasname = Guid.NewGuid().ToString();
                var newname = aliasname + "" + extn;
                var path = Path.Combine(Server.MapPath("~/images/"), newname);

                var generatecode = RandomString(6);
                var duplicatecodechk = db.Whitelabel_PruductGift.Where(x => x.CoupanCode == generatecode).Any();
                if (duplicatecodechk)
                {
                    generatecode = RandomString(6);
                }
                Whitelabel_PruductGift model = new Whitelabel_PruductGift();
                model.Whitelabelid = userid;
                model.ProductName = PName;
                model.ProductImages = newname;
                model.CoupanCode = generatecode;
                db.Whitelabel_PruductGift.Add(model);
                int i = db.SaveChanges();
                if (i > 0)
                {
                    images.SaveAs(path);
                    return Json("Success", JsonRequestBehavior.AllowGet);
                }
                return Json("Failed", JsonRequestBehavior.AllowGet);
            }
            catch { return Json("Failed", JsonRequestBehavior.AllowGet); }
        }
