        public ActionResult DeleteProductGiftImage(int id)
        {
            var userid = User.Identity.GetUserId();
            try
            {

                var result = db.Whitelabel_PruductGift.Where(a => a.Whitelabelid == userid && a.productId == id).SingleOrDefault();
                string idnotargetset = result.ProductName;

                var retexist = db.Whitelabel_RetailerSetTarget.Where(x => x.WhitelabelId == userid && x.Achived60 == idnotargetset || x.Achived70 == idnotargetset || x.Achived80 == idnotargetset || x.Achived90 == idnotargetset || x.Achived100 == idnotargetset && x.OfferType == "Giftitem").FirstOrDefault();

                if (retexist == null)
                {
                    var dealerexist = db.Whitelabel_DealerSetTarget.Where(x => x.WhitelabelId == userid && x.Achive_60 == idnotargetset || x.Achive_70 == idnotargetset || x.Achive_80 == idnotargetset || x.Achive_90 == idnotargetset || x.Achive_100 == idnotargetset && x.OfferType == "Giftitem").FirstOrDefault();
                    if (dealerexist == null)
                    {
                        var superExist = db.Whitelabel_superstockistsettarget.Where(x => x.WhitelabelId == userid && x.Achive_60 == idnotargetset || x.Achive_70 == idnotargetset || x.Achive_80 == idnotargetset || x.Achive_90 == idnotargetset || x.Achive_100 == idnotargetset && x.OfferType == "Giftitem").FirstOrDefault();
                        if (superExist == null)
                        {
                            if (superExist == null)
                            {
                                var imgname = result.ProductImages;
                                if (result != null)
                                {
                                    db.Whitelabel_PruductGift.Remove(result);
                                    int i = db.SaveChanges();
                                    if (i > 0)
                                    {
                                        System.IO.File.Delete(Request.PhysicalApplicationPath + "images/" + imgname);
                                        return Json("Success", JsonRequestBehavior.AllowGet);
                                    }
                                }
                            }
                        }
                    }
                }
                return Json("Failed", JsonRequestBehavior.AllowGet);
            }
            catch { return Json("Failed", JsonRequestBehavior.AllowGet); }
        }
