        [HttpGet]
        public new ActionResult Profile()
        {
            var userid = User.Identity.GetUserId();
            var userDetails = db.Users.Where(a => a.UserId == userid).SingleOrDefault();
            var admindetails = db.WhiteLabel_userList.Where(a => a.WhiteLabelID == userid).SingleOrDefault();
            ViewBag.admin = admindetails;
            ViewBag.image = admindetails.Photo;
            //state 
            int state = Convert.ToInt32(admindetails.state);
            int district = Convert.ToInt32(admindetails.district);
            ViewBag.ddlstate = db.State_Desc.Where(a => a.State_id == state).SingleOrDefault().State_name;
            ViewBag.dddistrict = db.District_Desc.Where(a => a.Dist_id == district && a.State_id == state).SingleOrDefault().Dist_Desc;
            ViewBag.Sate = db.State_Desc.Select(a => new SelectListItem { Text = a.State_name, Value = a.State_id.ToString() }).ToList();
            ViewBag.District = db.District_Desc.Where(a => a.State_id == state).Select(a => new SelectListItem { Text = a.Dist_Desc, Value = a.Dist_id.ToString() }).ToList();

            ViewData["msg"] = TempData["success"];
            TempData.Remove("success");
            ViewBag.RoleStatus = db.WhitelabelProfileAllUserOTPs.ToList();
            return View(userDetails);
        }

        [HttpPost]
        public ActionResult UpdateAddressProfile(int hdidadmin, int? txtid, string txtcompany, string txtaddress, int txtzipcode, int State, int District)
        {
            var userid = User.Identity.GetUserId();
            try
            {
                var ad = db.WhiteLabel_userList.Where(a => a.WhiteLabelID == userid && a.Idno == hdidadmin).SingleOrDefault();
                ad.FrmName = string.IsNullOrWhiteSpace(txtcompany) ? ad.FrmName : txtcompany;
                ad.Address = string.IsNullOrWhiteSpace(txtaddress) ? ad.Address : txtaddress;
                ad.Pincode = txtzipcode;
                ad.state = State;
                ad.district = District;
                db.SaveChanges();
            }
            catch
            {

            }
            TempData["success"] = "Update Successfully.";

            var userDetails = db.Users.Where(a => a.UserId == userid).SingleOrDefault();
            var admindetails = db.WhiteLabel_userList.Where(a => a.WhiteLabelID == userid).SingleOrDefault();
            var Sates = db.State_Desc.FirstOrDefault(a => a.State_id == admindetails.state).State_name;
            var Districtname = db.District_Desc.FirstOrDefault(a => a.Dist_id == admindetails.district && a.State_id == admindetails.state).Dist_Desc;

            return Json(new { admindetails, statename = Sates, district = Districtname }, JsonRequestBehavior.AllowGet);
        }

