        [HttpPost]
        public ActionResult Uploadprofileimage()
        {
            var userid = User.Identity.GetUserId();
            try
            {
                WebImage photo = null;
                var newFileName = "";
                var imagePath = "";

                if (Request.HttpMethod == "POST")
                {
                    HttpFileCollectionBase files = Request.Files;

                    photo = WebImage.GetImageFromRequest();
                    if (photo != null)
                    {
                        newFileName = Guid.NewGuid().ToString() + "_" +
                       Path.GetFileName(photo.FileName);
                        imagePath = @"\Retailer_image\" + newFileName;

                        photo.Save(@"~\" + imagePath);
                    }
                }
                var ad = db.WhiteLabel_userList.Where(a => a.WhiteLabelID == userid).SingleOrDefault();
                ad.Photo = string.IsNullOrWhiteSpace(imagePath) ? ad.Photo : imagePath;
                db.SaveChanges();
                TempData["success"] = "Image Upload Successfully.";
            }
            catch
            {

            }
            return RedirectToAction("Profile");
        }

