        [HttpPost]
        public async Task<JsonResult> DisableTwoFactor(string UserRole, string btnVal, string UserrId)
        {
            if (UserRole.Contains("Whitelabelmaster"))
            {
                var RoleId = db.Roles.Where(a => a.Name == UserRole).SingleOrDefault().RoleId;
                var ch = db.UserRoles.Where(a => a.RoleId == RoleId).ToList();
                if (btnVal == "Y")
                {
                    foreach (var item in ch)
                    {
                        await UserManager.SetTwoFactorEnabledAsync(item.UserId, true);
                    }
                }
                else
                {
                    foreach (var item in ch)
                    {
                        await UserManager.SetTwoFactorEnabledAsync(item.UserId, false);
                    }
                }
            }
            else if (UserRole.Contains("Whitelabeldealer"))
            {
                var RoleId = db.Roles.Where(a => a.Name == UserRole).SingleOrDefault().RoleId;
                var ch = db.UserRoles.Where(a => a.RoleId == RoleId).ToList();
                if (btnVal == "Y")
                {
                    foreach (var item in ch)
                    {
                        await UserManager.SetTwoFactorEnabledAsync(item.UserId, true);
                    }
                }
                else
                {
                    foreach (var item in ch)
                    {
                        await UserManager.SetTwoFactorEnabledAsync(item.UserId, false);
                    }
                }

            }
            else if (UserRole.Contains("Whitelabelretailer"))
            {
                var RoleId = db.Roles.Where(a => a.Name == UserRole).SingleOrDefault().RoleId;
                var ch = db.UserRoles.Where(a => a.RoleId == RoleId).ToList();
                if (btnVal == "Y")
                {
                    foreach (var item in ch)
                    {
                        await UserManager.SetTwoFactorEnabledAsync(item.UserId, true);
                    }
                }
                else
                {
                    foreach (var item in ch)
                    {
                        await UserManager.SetTwoFactorEnabledAsync(item.UserId, false);
                    }
                }

            }
            else
            {
                if (btnVal == "Y")
                {
                    if (UserrId != null || UserrId != "")
                    {
                        await UserManager.SetTwoFactorEnabledAsync(UserrId, true);

                        var RoleName = UserManager.GetRoles(UserrId);
                        return Json(RoleName, JsonRequestBehavior.AllowGet);
                    }

                }
                else
                {
                    if (UserrId != null || UserrId != "")
                    {
                        await UserManager.SetTwoFactorEnabledAsync(UserrId, false);

                        var RoleName = UserManager.GetRoles(UserrId);
                        return Json(RoleName, JsonRequestBehavior.AllowGet);
                    }
                }
            }
            return Json("Success", JsonRequestBehavior.AllowGet);
        }
        public JsonResult GetTwoFactor(string UserRole)
        {
            var userid = User.Identity.GetUserId();
            if (UserRole.Contains("Whitelabelmaster"))
            {
                var results = (from users in db.Users
                               join master in db.Whitelabel_Superstokist_details.Where(a => a.Whitelabelid == userid) on users.UserId equals master.SSId.ToString()
                               select new ADMIN.Models.TwoFactorEnabled
                               {
                                   UserId = users.UserId,
                                   Email = string.IsNullOrEmpty(master.FarmName) ? master.SuperstokistName : master.FarmName,
                                   Mobile = master.Mobile,
                                   TwoFactorEnable = users.TwoFactorEnabled,
                                   UserRole = "Whitelabelmaster"
                               }).ToList();
                return Json(results, JsonRequestBehavior.AllowGet);

            }
            else if (UserRole.Contains("Whitelabeldealer"))
            {
                var results = (from users in db.Users
                               join dealer in db.whitelabel_Dealer_Details.Where(a => a.Whitelabelid == userid) on users.UserId equals dealer.DealerId.ToString()
                               select new ADMIN.Models.TwoFactorEnabled
                               {
                                   UserId = users.UserId,
                                   Email = string.IsNullOrEmpty(dealer.FarmName) ? dealer.DealerName : dealer.FarmName,
                                   Mobile = dealer.Mobile,
                                   TwoFactorEnable = users.TwoFactorEnabled,
                                   UserRole = "Whitelabeldealer"
                               }).ToList();
                return Json(results, JsonRequestBehavior.AllowGet);

            }
            else if (UserRole.Contains("Whitelabelretailer"))
            {
                var results = (from users in db.Users
                               join retailer in db.Whitelabel_Retailer_Details.Where(a => a.Whitelabelid == userid) on users.UserId equals retailer.RetailerId.ToString()
                               select new ADMIN.Models.TwoFactorEnabled
                               {
                                   UserId = users.UserId,
                                   Email = string.IsNullOrEmpty(retailer.Frm_Name) ? retailer.RetailerName : retailer.Frm_Name,
                                   Mobile = retailer.Mobile,
                                   TwoFactorEnable = users.TwoFactorEnabled,
                                   UserRole = "Whitelabelretailer"
                               }).ToList();
                return Json(results, JsonRequestBehavior.AllowGet);

            }
            else
            {
                var results = (from users in db.Users
                               join master in db.Whitelabel_Superstokist_details.Where(a => a.Whitelabelid == userid) on users.UserId equals master.SSId.ToString()
                               select new ADMIN.Models.TwoFactorEnabled
                               {
                                   UserId = users.UserId,
                                   Email = string.IsNullOrEmpty(master.FarmName) ? master.SuperstokistName : master.FarmName,
                                   Mobile = master.Mobile,
                                   TwoFactorEnable = users.TwoFactorEnabled,
                                   UserRole = "master"
                               }).ToList();
                return Json(results, JsonRequestBehavior.AllowGet);
            }
        }

        [ValidateInput(false)]
        [HttpPost]
        public ActionResult AdminOTPStatus(string RoleName, string Status)
        {
            var UserStatus = db.WhitelabelProfileAllUserOTPs.Where(a => a.RoleName == RoleName).SingleOrDefault();
            var CurrStatus = "";
            if (UserStatus != null)
            {
                CurrStatus = UserStatus.Status;
                if (CurrStatus == "Y")
                {
                    Vastwebmulti.Models.WhitelabelProfileAllUserOTP obj = (from pp in db.WhitelabelProfileAllUserOTPs
                                                                           where pp.RoleName == RoleName
                                                                           select pp).SingleOrDefault();
                    obj.Status = "N";
                    db.SaveChanges();
                }
                else if (CurrStatus == "N")
                {
                    Vastwebmulti.Models.WhitelabelProfileAllUserOTP obj = (from pp in db.WhitelabelProfileAllUserOTPs
                                                                           where pp.RoleName == RoleName
                                                                           select pp).SingleOrDefault();
                    obj.Status = "Y";
                    db.SaveChanges();
                }
            }

            return Json(new { RoleName = RoleName, Status = CurrStatus == "Y" ? "N" : "Y" });

        }
