        #region EmailSecurity
        public ActionResult Email_Security()
        {
            var userid = User.Identity.GetUserId();
            ViewBag.chkPopUp = TempData["data1"];
            TempData.Remove("data1");

            DateTime frm = DateTime.Now.Date;
            DateTime to = DateTime.Now;
            string txt_frm_date = frm.ToString("dd-MM-yyyy");
            string txt_to_date = to.ToString("dd-MM-yyyy");
            string[] formats = new[] { "MM/dd/yyyy", "dd-MMM-yyyy",
                            "yyyy-MM-dd", "dd-MM-yyyy", "dd MMM yyyy" };
            DateTime dt = !string.IsNullOrWhiteSpace(txt_frm_date) ? DateTime.ParseExact(txt_frm_date, formats, CultureInfo.InvariantCulture, DateTimeStyles.None) : DateTime.Now;
            DateTime dt1 = !string.IsNullOrWhiteSpace(txt_to_date) ? DateTime.ParseExact(txt_to_date, formats, CultureInfo.InvariantCulture, DateTimeStyles.None) : DateTime.Now;
            DateTime frm_date = Convert.ToDateTime(dt).Date;
            DateTime to_date = Convert.ToDateTime(dt1).Date.AddDays(1);

            var Login_details = (db.Whitelabel_Sent_Mail_History.Where(aa => aa.SentDate >= frm_date && aa.SentDate <= to_date).OrderByDescending(aa => aa.Idno)).ToList();
            Email_ViewModel viewmodel = new Email_ViewModel();
            viewmodel.priorityEmail = db.Whitelabel_priorityEmail.Where(a => a.Userid == userid).ToList();
            viewmodel.Sent_Mail_History = Login_details.Where(a => a.UserId == userid).ToList();
            return View(viewmodel);

        }

        [HttpPost]
        public ActionResult Email_Security(string SMTPHost, string EmailID, string Paswrd, int Port)
        {
            var userid = User.Identity.GetUserId();
            try
            {
                string status = "";
                var CHKSTS = db.Whitelabel_priorityEmail.Where(a => a.Userid == userid).ToList();
                if (CHKSTS.Count < 5)
                {
                    if (CHKSTS.Any(a => a.Status == "Y"))
                    {
                        status = "N";
                    }
                    else
                    {
                        status = "Y";
                    }


                    Whitelabel_priorityEmail ch = new Whitelabel_priorityEmail();
                    ch.Userid = userid;
                    ch.Password = Paswrd;
                    ch.Smpthost = SMTPHost;
                    ch.Email = EmailID;
                    ch.Port = Port;
                    ch.Enablessl = "false";
                    ch.Status = status;
                    ch.Send_Limit = 1000;
                    db.Whitelabel_priorityEmail.Add(ch);
                    db.SaveChanges();

                    return Json(new { status = "Success", Message = "Email Added Successfully." });
                }
                else
                {
                    return Json(new { status = "Failed", Message = "We cannot add more than 5 business mail." });
                }
            }
            catch (Exception ex)
            {
                var userFrindlyMSG = ex.InnerException.InnerException.Message.Contains("UniqueEmail");
                if (userFrindlyMSG)
                {
                    return Json(new { status = "Failed", Message = "Cannot Insert Duplicate Mail is " + EmailID });
                }
                else
                {
                    return Json(new { status = "Failed", Message = "Something Went Wrong !!!" });
                }
            }
        }
        public ActionResult DeleteEmail(int idno)
        {
            var userid = User.Identity.GetUserId();
            try
            {
                var CHKEntry = db.Whitelabel_priorityEmail.Where(a => a.Userid == userid).ToList();
