        [HttpPost]
        public JsonResult SendEmail(SendMail SM)
        {
            var userid = User.Identity.GetUserId();

            try
            {

                if (!string.IsNullOrEmpty(SM.Userform1))
                {
                    if (SM.Userform1 == "Master")
                    {
                        var useremail = db.Superstokist_details.ToList();
                        foreach (var item in useremail)
                        {
                            SM.txtEmail = item.Email;
                            var ToCC = db.Admin_details.FirstOrDefault().email;
                            CommUtilEmail emailsend = new CommUtilEmail();
                            emailsend.WhiteLabelEmailLimitChk(SM.txtEmail, ToCC, SM.txtSubject, SM.txtMsgBody, "No CallBackUrl", userid);
                        }
                    }
                    else if (SM.Userform1 == "Dealer")
                    {
                        var smsapilist = (from ff in db.apisms where ff.sts == "Y" select ff).FirstOrDefault();
                        if (smsapilist != null)
                        {
                            var usermobiles = db.whitelabel_Dealer_Details.Where(a => a.Whitelabelid == userid).ToList();
                            foreach (var item in usermobiles)
                            {
                                SM.txtEmail = item.Email;
                                var ToCC = db.Admin_details.FirstOrDefault().email;
                                CommUtilEmail emailsend = new CommUtilEmail();
                                emailsend.WhiteLabelEmailLimitChk(SM.txtEmail, ToCC, SM.txtSubject, SM.txtMsgBody, "No CallBackUrl", userid);
                            }
                        }
                        else
                        {
                            return Json("Email Not Sent", JsonRequestBehavior.AllowGet);
                        }
                    }
                    else if (SM.Userform1 == "Retailer")
                    {
                        var smsapilist = (from ff in db.apisms where ff.sts == "Y" select ff).FirstOrDefault();
                        if (smsapilist != null)
                        {
                            var usermobiles = db.Whitelabel_Retailer_Details.Where(a => a.Whitelabelid == userid).ToList();

                            foreach (var item in usermobiles)
                            {
                                SM.txtEmail = item.Email;
                                var ToCC = db.Admin_details.FirstOrDefault().email;
