                                diff1 = (db.Whitelabel_to_super_balance.Where(aa => aa.SuperStokistID == DealerId).OrderByDescending(aa => aa.ID).Select(c => c.cr).FirstOrDefault());
                                var remainmaster = db.Remain_whitelabel_superstokist_balance.Where(p => p.superstokistid == DealerId && p.whitelabelid == userid).SingleOrDefault().remainbalance;
                                //var statusAdmin = db.PushNotificationStatus.Where(a => a.UserRole == "Whitelabel").SingleOrDefault().Status;
                                //var statusMaster = db.PushNotificationStatus.Where(a => a.UserRole == "Master").SingleOrDefault().Status;
                                var statusSendSmsMasterFundTransfer = db.Whitelabel_SMSSendAll.Where(a => a.ServiceName == "Admintomasterfundtrans" && a.Whitelabelid == userid).SingleOrDefault().Status;
                                var statusSendEmailMasterFundTransfer = db.Whitelabel_EmailSendAll.Where(a => a.ServiceName == "Admintomasterfundtrans1" && a.Whitelabelid == userid).SingleOrDefault().Status;
                                var AdminToCC = db.Admin_details.SingleOrDefault().email;

                                var MasterDetails = db.Whitelabel_Superstokist_details.Where(a => a.SSId == DealerId && a.Whitelabelid == userid).SingleOrDefault();
                                //var mastername = MasterDetails.SuperstokistName;
                                var Adminname = db.WhiteLabel_userList.Where(a => a.WhiteLabelID == userid).SingleOrDefault().Name;
                                //var RemainAdmin = db.White_label_remainbal.Where(p => p.userid == userid).Single().remainbal;
                                if (type == "Credit")
                                {
                                    smssend.sms_init_whitelabel(userid, statusSendSmsMasterFundTransfer, "N", "FUNDTRANSFERMESSAGE_CREDIT", MasterDetails.Mobile, amount1, remainmaster, diff1);

                                    if (statusSendEmailMasterFundTransfer == "Y")
                                    {
                                        smssend.SendWhitelabelEmailAll(MasterDetails.Email, "Credit Received Rs." + amount1 + ".New Balance is " + remainmaster + ".Your O/s Credit is " + diff1 + "", "Fund Transfer", AdminToCC, userid);
                                    }
                                    ch = "Fund Transfer Successful.";
                                    tp = "success";
                                    ch = "Fund Transfer Successful.";
                                    tp = "success";
                                }
                                else
                                {

                                    smssend.sms_init_whitelabel(userid, statusSendSmsMasterFundTransfer, "N", "FUNDTRANSFERMESSAGE_CREDIT", MasterDetails.Mobile, amount1, remainmaster, diff1);

                                    if (statusSendEmailMasterFundTransfer == "Y")
                                    {
                                        smssend.SendWhitelabelEmailAll(MasterDetails.Mobile, "Cash Paid Rs." + amount1 + " to " + Adminname + ". New Balance is " + remainmaster + ". Your O/s Credit is " + diff1 + "", "Fund Transfer", AdminToCC, userid);
                                    }
                                    ch = "Fund Transfer Successful.";
                                    tp = "success";
                                }
                            }

                            TempData["BalanceTransferMsg"] = ch;
                            TempData["BalanceTransfertype"] = tp;
                            TempData.Remove("dlmid");
                            TempData.Remove("bal");
                            TempData.Remove("dl_commission");
                            TempData.Remove("comment");
                            return Json(ch, JsonRequestBehavior.AllowGet);
                        }
                        else
                        {
                            return Json("Your Previous Request IN Process Please Try After SomeTime", JsonRequestBehavior.AllowGet);
                        }
                        //  return RedirectToAction("Admin_to_master_Dealer");
                    }
                    else
                    {
                        var counts = db.spWhitelabel_FundTransfercount(userid, userid, DealerId, type, amount1, "Admintodealer").SingleOrDefault().msg;
                        int msgcount = Convert.ToInt32(counts);
                        if (msgcount == 0)
                        {
                            msgcount = 60001;
                        }
                        int max_limit = 60000;
                        if (msgcount > max_limit)
                        {

                            decimal amount = Convert.ToDecimal(balance);

                            ch = db.spWhitelabel_admin_to_dealer_balance(userid, DealerId, amount, type, comment, "Whitelabel", collectionby, bankname, adminacco, "Direct", output).Single().msg;

                            if (ch == "ok")
                            {
                                var diff2 = (db.Whitelabel_to_Dealer.Where(aa => aa.dealerid == DealerId && aa.WhitelabelId == userid).OrderByDescending(aa => aa.idno).Select(c => c.cr).FirstOrDefault());
                                var remaindealer = db.Whitelabel_Remain_dealer_balance.Where(p => p.DealerID == DealerId && p.whitelabelid == userid).Single().Remainamount;
                                //var statusAdmin = db.PushNotificationStatus.Where(a => a.UserRole == "Admin").SingleOrDefault().Status;
                                //var statusDealer = db.PushNotificationStatus.Where(a => a.UserRole == "Distributor").SingleOrDefault().Status;
                                var statusSendSmsDealerFundTransfer = db.Whitelabel_SMSSendAll.Where(a => a.ServiceName == "Admintodlmfundtrans" && a.Whitelabelid == userid).SingleOrDefault().Status;
                                var statusSendEmailDealerFundTransfer = db.Whitelabel_EmailSendAll.Where(a => a.ServiceName == "Admintodlmfundtrans1" && a.Whitelabelid == userid).SingleOrDefault().Status;

                                var DealerDetails = db.whitelabel_Dealer_Details.Where(a => a.DealerId == DealerId && a.Whitelabelid == userid).SingleOrDefault();
                                //var Dealername = db.Dealer_Details.Where(p => p.DealerId == DealerId).Single().DealerName;
                                var AdminDetails = db.Admin_details.Single();
                                //var RemainAdmin = db.Remain_Admin_balance.Where(p => p.admin == userid).Single().RemainAmount;
                                if (type == "Credit")
                                {
                                    smssend.sms_init_whitelabel(userid, statusSendSmsDealerFundTransfer, "N", "FUNDTRANSFERMESSAGE_CREDIT", DealerDetails.Mobile, amount, remaindealer, diff2);

                                    if (statusSendEmailDealerFundTransfer == "Y")
                                    {
                                        smssend.SendWhitelabelEmailAll(DealerDetails.Email, "Credit Received Rs." + amount + ".New Balance is " + remaindealer + ".Your O/s Credit is " + diff2 + "", "Fund Transfer", AdminDetails.email, userid);
                                    }
                                    ch = "Fund Transfer Successful.";
                                    tp = "success";
                                }
                                else
                                {
                                    var dealername = DealerDetails.DealerName;
                                    //var Adminname = db.Admin_details.Single().Name;

                                    smssend.sms_init_whitelabel(userid, statusSendSmsDealerFundTransfer, "N", "FUNDTRANSFERMESSAGE_CASH", DealerDetails.Mobile, amount, AdminDetails.Name, remaindealer, diff2);

                                    if (statusSendEmailDealerFundTransfer == "Y")
                                    {
                                        smssend.SendWhitelabelEmailAll(DealerDetails.Email, "Cash Paid Rs." + amount + " to " + AdminDetails.Name + ". New Balance is " + remaindealer + ". Your O/s Credit is " + diff2 + "", "Fund Transfer", AdminDetails.email, userid);
                                    }
                                    ch = "Fund Transfer Successful.";
                                    tp = "success";
                                }
                            }
                            //}
                            //else
                            //{
                            //    ch = "Amount is not Zero";
                            //    tp = "error";
                            //}
                            TempData["BalanceTransferMsg"] = ch;
                            TempData["BalanceTransfertype"] = tp;
                            TempData.Keep("BalanceTransferMsg");
                            TempData.Remove("dlmid");
                            TempData.Remove("bal");
                            TempData.Remove("dl_commission");
                            TempData.Remove("comment");
                            // return RedirectToAction("Admin_to_Dealer");

                            return Json(ch, JsonRequestBehavior.AllowGet);

                        }
                        else
                        {
                            return Json("Please Try After SomeTime", JsonRequestBehavior.AllowGet);
                        }


                    }
                }
                else
                {
                    ViewData["MSG"] = "Transaction Password is Wrong.";
                    ch = "Transaction Password is Wrong.";
                    //  return View();
                    return Json(ch, JsonRequestBehavior.AllowGet);
                }
                //return Json(ch, JsonRequestBehavior.AllowGet);
            }
            catch (Exception ex)
            {
                return Json(ex.Message, JsonRequestBehavior.AllowGet);
            }
        }

