        public ActionResult Fund_User()
        {
            var userid = User.Identity.GetUserId();
            Whitelabel_FundUserViewModel vmodel = new Whitelabel_FundUserViewModel();

            var dbData = db.Whitelabel_Superstokist_details.Where(s => s.Whitelabelid == userid).ToList();
            vmodel.Masters = GetMasterSelectListItems(dbData);

            vmodel.master_to_dealer_report_BYAdmin_Result = db.spWhitelabel_Master_to_dealer_report_BYAdmin(userid, DateTime.Today, DateTime.Today.AddDays(1), "ALL", "ALL", 1, 5000).ToList();

            var dbdealerData = db.whitelabel_Dealer_Details.Where(s => s.Whitelabelid == userid).ToList();
            vmodel.Dealesrs = GetDealerlistSelectListItems(dbdealerData);

            var dbRetailerData = db.Whitelabel_Retailer_Details.Where(s => s.Whitelabelid == userid).ToList();
            vmodel.Retailerslist = GetRetailerlistSelectListItems(dbRetailerData);

            return View(vmodel);
        }

