        public ActionResult PurchasertequestWhiteLabelToadmin(string hdSuperstokistID, string hdMDDLM, string hdPaymentMode,
    string hdPaymentAmount, string hdMDDepositeSlipNo, string hdMDTransferType, string hdMDcollection, string hdMDComments,
    string hdMDBank, string hdsupraccno, string hdMDaccountno, string hdMDutrno, string hdMDwallet,
    string hdMDwalletno, string hdMDtransationno, string hdMDsettelment, string hdMDCreditDetail, string hdMDsubject)
        {
            string msg = string.Empty;
            using (VastwebmultiEntities db = new VastwebmultiEntities())
            {
                WebImage photo = null;
                var newFileName = "";
                var imagePath = "";
                try
                {

                    if (Request.HttpMethod == "POST")
                    {
                        photo = WebImage.GetImageFromRequest();
                        if (photo != null)
                        {
                            newFileName = Guid.NewGuid().ToString() + "_" +
                                          Path.GetFileName(photo.FileName);
                            imagePath = @"PurchaseOrderImg\" + newFileName;

                            photo.Save(@"~\" + imagePath);
                        }
                    }

                }
                catch (Exception e)
                {
                    Console.WriteLine(e);
                    throw;
                }

                decimal balance = Convert.ToDecimal(hdPaymentAmount);
                string type = hdPaymentMode;
                string comment = hdMDComments;
                var DealerId = hdMDDLM;
                // string utrno = hdMDcollection == null ? hdMDutrno : hdMDcollection;
                string collectionby = hdMDcollection == null ? hdMDtransationno : hdMDcollection;
                collectionby = collectionby == null ? hdMDutrno : collectionby;
                collectionby = collectionby == null ? hdMDtransationno : collectionby;
                collectionby = collectionby == null ? hdMDsettelment : collectionby;
                collectionby = collectionby == null ? hdMDCreditDetail : collectionby;
                collectionby = collectionby == null ? hdMDsubject : collectionby;
                collectionby = collectionby == null ? hdMDDepositeSlipNo : collectionby;
                string bankname = hdMDBank == null ? hdMDwallet : hdMDBank;
                string adminacco = hdMDaccountno == null ? hdMDwalletno : hdMDaccountno;


                string userid = User.Identity.GetUserId();

                if (db.Whitelabel_master_purchase.Count(aa => aa.masterid.ToLower() == userid.ToLower() && aa.sts == "Pending") < 1)
                {
                    var diff1 = (db.whitelabel_Balance_transfer.Where(aa => aa.WhiteLabelID == userid).OrderByDescending(aa => aa.id).Select(c => c.cr).FirstOrDefault());
                    diff1 = diff1 ?? 0;
                    decimal diff = Convert.ToDecimal(diff1);
                    var amount = Convert.ToDecimal(hdPaymentAmount);
                    if (amount > 0)
                    {
                        decimal disCharge = 0;
                        var chargeEntryss = db.creditchargewhitelabels.FirstOrDefault(a => a.type == hdPaymentMode && a.userid == userid);

                        if (chargeEntryss != null)
                        {
                            disCharge = (amount * Convert.ToDecimal(chargeEntryss.charge)) / 100;
                        }
                        db.insert_whitelabel_to_admin_purchageorder(userid, hdPaymentMode, collectionby, bankname, "", hdMDComments, Convert.ToDecimal(balance), "", type, "", adminacco, @"/PurchaseOrderImg/" + newFileName, "", "", "", disCharge, amount - disCharge);

                        //  return Json("Purchase Order Successfully", JsonRequestBehavior.AllowGet);
                        return WLTOADMIN("PurchaseOreder", null, null, msg = "Purchase Order Successfully");
                    }
                    else
                    {
                        TempData["show"] = "Amount should be not zero";
                        return WLTOADMIN("PurchaseOreder", null, null, msg = "Amount should be not zero");
                    }
                }
                else
                {
                    TempData["show"] = "Your purcharge Order Allready Pending.";
                }
                return WLTOADMIN("PurchaseOreder", null, null, msg = "Your purcharge Order Allready Pending.");
            }
        }

        public PartialViewResult WLTOADMIN(string tabtype, string txt_frm_date, string txt_to_date, string msg = "")
        {
            DateTime fromdate;
            DateTime Todate;

            if (string.IsNullOrEmpty(txt_frm_date) && string.IsNullOrEmpty(txt_to_date))
            {
                fromdate = DateTime.Now.AddDays(-1);
                Todate = DateTime.Now.AddDays(1);
            }
            else
            {

                string[] formats = new[] { "MM/dd/yyyy", "dd-MMM-yyyy",
                                "yyyy-MM-dd", "dd-MM-yyyy", "dd MMM yyyy" };

                DateTime dt = !string.IsNullOrWhiteSpace(txt_frm_date) ? DateTime.ParseExact(txt_frm_date, formats, CultureInfo.InvariantCulture, DateTimeStyles.None) : DateTime.Now;
                DateTime dt1 = !string.IsNullOrWhiteSpace(txt_to_date) ? DateTime.ParseExact(txt_to_date, formats, CultureInfo.InvariantCulture, DateTimeStyles.None) : DateTime.Now;
                fromdate = Convert.ToDateTime(dt).Date;
                Todate = Convert.ToDateTime(dt1).Date.AddDays(1);


            }

            FundTransferWhitelabelToDLM vmodel = new FundTransferWhitelabelToDLM();

            string userid = User.Identity.GetUserId();
            vmodel.WhitelabelPurchaseOrder = db.select_whitelabel_master_pur_order(userid, "ALL", Convert.ToDateTime(fromdate), Convert.ToDateTime(Todate)).ToList();
            if (!string.IsNullOrEmpty(msg))
            {
                vmodel.message = msg;
            }

            return PartialView("_FundTransferWhiteLabelToDlmPartial", vmodel);

        }

        public ActionResult R_Creditchk()
        {
            string userid = User.Identity.GetUserId();

            var diff1 = db.total_Retailer_outstanding_by_admin(userid).FirstOrDefault().totaloutstanding;

            if(db.whitelabel_Balance_transfer.Any(s => s.WhiteLabelID == userid))
            {
                diff1 = (decimal)db.whitelabel_Balance_transfer.Where(s => s.WhiteLabelID == userid).OrderByDescending(s => s.id).Take(1).Single().cr;
            }

            var accunt1 = (from acc in db.Whitelabel_bank_info.Where(a => a.userid == "Admin" || a.userid == userid) select new { acno = acc.acno, acnooo = acc.banknm });
            var bank = new SelectList(accunt1, "acno", "acnooo", null);
            var wallet = (from wll in db.tblwallet_info.Where(a => a.userid == "Admin") select new { wallid = wll.walletno, wllnooo = wll.walletname });
            var walletsss = new SelectList(wallet, "wallid", "wllnooo", null);
            return Json(new { listbank = bank, walletinfo = walletsss, diff = diff1 }, JsonRequestBehavior.AllowGet);

        }

