        [HttpPost]
        public ActionResult Api_Operator(string apinm, string txtidno, string txtapinm, string txtoptnm, string txtapiopt, string txtpurcharge, string purchasetype, string[] myCategories)
        {
            var whitelabelid = User.Identity.GetUserId();

            if (txtidno != null || txtidno != "")
            {
                db.spWhitelabel_SRS_update_api(whitelabelid, Convert.ToInt32(txtidno), txtapinm, "", "", txtapiopt, Convert.ToDecimal(txtpurcharge), 0, 0, purchasetype);
            }
            if (apinm == "")
            {
                apinm = "Y";
            }

            var query = (from o in db.whitelabel_api_name.Where(a => a.whitelabelid == whitelabelid) select o).Distinct().OrderBy(x => x.apiname);
            ViewBag.apinm = new SelectList(query, "apiname", "apiname", null);
            TempData["edit"] = "Update Successfully.";

            IEnumerable<SelectListItem> ldidList = db.Operator_Code.Select(c => new SelectListItem
            {
                Value = c.Operator_type,
                Text = c.Operator_type
            }).Distinct();
            ViewBag.OptCategories = ldidList.Where(a => a.Text == "Prepaid" || a.Text == "DTH");


            List<spWhitelabel_select_api_info_Result> firstlist = new List<spWhitelabel_select_api_info_Result>();
            if ((myCategories != null) && (apinm != null || apinm != ""))
            {
                dynamic ch = (object)null;

                foreach (var item in myCategories)
                {
                    ch = db.spWhitelabel_select_api_info(whitelabelid, apinm, item).ToList();
                    firstlist.AddRange(ch);
                }
            }
            else
            {
                var ch1 = db.spWhitelabel_select_api_info(whitelabelid, apinm, "").ToList();
                firstlist.AddRange(ch1);
            }
            var chList = firstlist.DistinctBy(a => a.opt_code).ToList();
            return View(chList);
        }
