        public ActionResult GSTSettingSave(string[] ch)
        {
            var userid = User.Identity.GetUserId();
            foreach (var item in ch)
            {
                var groupname1 = item.Split(',');

                var Status = groupname1[1].ToString();
                var name = groupname1[0].ToString();
                GSTSettingStatusWhitelabel obj = (from pp in db.GSTSettingStatusWhitelabels
                                                  where pp.UserRole == name && pp.Whitelabelid == userid
                                                  select pp).SingleOrDefault();
                obj.Whitelabelid = userid;
                obj.Status = Status;
                db.SaveChanges();
            }
            return Json(new { status = "Success", Message = "GST Status Set Successfully !" });
        }
