        [HttpPost]
        public ActionResult Broadband_Slab_setting(Models.Broadbandslab model)
        {
            var userid = User.Identity.GetUserId();
            foreach (var item in model.common)
            {
                Broandband_whitelabel_common_comm entry = (from p in db.Broandband_whitelabel_common_comm where p.whitelabelid == userid && p.idno == item.idno select p).Single();
