        [HttpPost]
        public PartialViewResult _UserBoradbandSlab(string role, string userid, string Retailerid)
        {
            Models.Broadbandslab model = new Models.Broadbandslab();
            var whitelabelid = User.Identity.GetUserId();
            //Dealer User
            if (role == "Dealer")
            {
                if (string.IsNullOrWhiteSpace(userid))
                {

                    model.Dealeruser =
                 (from m in db.Broandband_whitelabel_dealer_comm
                  join u in db.Users on m.userid equals u.UserId
                  join opt in db.Operator_Code on m.optcode equals opt.Operator_id.ToString()
                  where m.whitelabelid == whitelabelid
                  select new Models.BroandbandDealer
                  {
                      idno = m.idno,
                      userid = m.userid,
                      optcode = m.optcode,
                      OperatorName = opt.operator_Name,
                      whitelabelid = whitelabelid,
                      comm = m.comm,
                      gst = m.gst,
                      Email = u.Email,
                      RolesName = "Dealer"
                  }).OrderByDescending(p => p.idno).ToList();

                    var list = db.whitelabel_Dealer_Details.Where(a => a.Whitelabelid == whitelabelid).Select(a => new SelectListItem { Text = a.Email, Value = a.DealerId, Selected = a.DealerId == userid ? true : false }).ToList();
                    model.UserId = list;


                }
                else
                {
                    model.Dealeruser =
                     (from m in db.Broandband_whitelabel_dealer_comm
                      join u in db.Users on m.userid equals u.UserId
                      join opt in db.Operator_Code on m.optcode equals opt.Operator_id.ToString()
                      where m.userid == userid && m.whitelabelid == whitelabelid
                      select new Models.BroandbandDealer
                      {
                          idno = m.idno,
                          userid = m.userid,
                          optcode = m.optcode,
                          OperatorName = opt.operator_Name,
                          comm = m.comm,
                          whitelabelid = whitelabelid,
                          gst = m.gst,
                          Email = u.Email,
                          RolesName = "Dealer"
                      }).OrderByDescending(g => g.idno).ToList();
                    var list = db.whitelabel_Dealer_Details.Where(a => a.Whitelabelid == whitelabelid).Select(a => new SelectListItem { Text = a.Email, Value = a.DealerId, Selected = a.DealerId == userid ? true : false }).ToList();
                    model.UserId = list;
                }
                model.UpdateDealer =
                 (from com in db.Broandband_whitelabel_common_comm
                  join opt in db.Operator_Code on com.optcode equals opt.Operator_id.ToString()
                  where com.whitelabelid == whitelabelid
                  select new Models.UpdateBroadbandDealer
                  {
                      idno = com.idno,
                      OperatorName = opt.operator_Name,
                      comm = com.dealercomm,
                      gst = com.gst,
                      whitelabelid = whitelabelid,
                      optcode = com.optcode,


                  }).OrderByDescending(a => a.idno).Distinct().ToList();

            }
            //End User
            //Retailer User
            if (role == "Retailer")
            {
                if (string.IsNullOrWhiteSpace(userid) && string.IsNullOrWhiteSpace(Retailerid))
                {
                    model.Retaileruser = null;
                    var list1 = db.whitelabel_Dealer_Details.Where(a => a.Whitelabelid == whitelabelid).Select(a => new SelectListItem { Text = a.Email, Value = a.DealerId, Selected = a.DealerId == userid ? true : false }).ToList();
                    model.UserId = list1;
                }
                else if (userid != "" && userid != null)
                {

                    var list = db.Whitelabel_Retailer_Details.Where(a => a.DealerId == userid).Select(a => new SelectListItem { Text = a.Email, Value = a.RetailerId, Selected = a.RetailerId == userid ? true : false }).ToList();
                    model.RetailerId = list;
                    var list1 = db.whitelabel_Dealer_Details.Where(a => a.Whitelabelid == whitelabelid).Select(a => new SelectListItem { Text = a.Email, Value = a.DealerId, Selected = a.DealerId == userid ? true : false }).ToList();
                    model.UserId = list1;
                }
                else
                {
                    model.Retaileruser =
                     (from m in db.Broandband_whitelabel_retailer_comm
                      join u in db.Users on m.userid equals u.UserId
                      join opt in db.Operator_Code on m.optcode equals opt.Operator_id.ToString()
                      where m.userid == Retailerid && m.whitelabelid == whitelabelid
                      select new Models.BroadbandRetailer
                      {
                          idno = m.idno,
                          userid = m.userid,
                          optcode = m.optcode,
                          OperatorName = opt.operator_Name,
                          comm = m.comm,
                          gst = m.gst,
                          whitelabelid = whitelabelid,
                          Email = u.Email,
                          RolesName = "Retailer"
                      }).OrderByDescending(g => g.idno).ToList();
                    var retailerid = (from tbl in db.WhiteLabel_userList
                                      join tbl1 in db.whitelabel_Dealer_Details on tbl.WhiteLabelID equals tbl1.Whitelabelid
                                      join tbl2 in db.Whitelabel_Retailer_Details on tbl1.DealerId equals tbl2.DealerId
