        public ActionResult Finanicalsts(string id)
        {
            var sts = (from pp in db.Whitelabel_Retailer_Details where pp.RetailerId == id select pp).Single().moneysts;
            if (sts == "Y")
            {
                sts = "N";
            }
            else
            {
                sts = "Y";
            }
            Whitelabel_Retailer_Details obj = (from dd in db.Whitelabel_Retailer_Details
                                               where dd.RetailerId == id
                                               select dd).SingleOrDefault();
            obj.moneysts = sts;
            db.SaveChanges();
            return RedirectToAction("Retailer_list");
        }

        #region  Gst_Invocing_Dealer_report
        public ActionResult Gst_Invocing_Dealer_report()
        {
            var userid = User.Identity.GetUserId();
            DateTime txt_frm_date = DateTime.Now;
            DateTime to_date = DateTime.Now;
            DateTime date = DateTime.Now;
            string OldMonth = date.AddMonths(-1).ToString("MMMM");
            ViewBag.alldealer = new SelectList(db.select_whitelabel_DealerName_for_ddl(userid), "Dealerid", "DealerName", null).ToList();

            ViewBag.OldMonth = OldMonth;
            txt_frm_date = new DateTime(date.AddMonths(-1).Year, date.AddMonths(-1).Month, 1);
            to_date = new DateTime(date.Year, date.Month, 1);
            var show = db.GST_Monthly_wDealer(Convert.ToDateTime(txt_frm_date), Convert.ToDateTime(to_date)).ToList();
            return View(show);
        }
        [HttpPost]
        public ActionResult Gst_Invocing_Dealer_report(string alldealer)
        {
            var userid = User.Identity.GetUserId();
            DateTime txt_frm_date = DateTime.Now;
            DateTime to_date = DateTime.Now;
            DateTime date = DateTime.Now;
            string OldMonth = date.AddMonths(-1).ToString("MMMM");

            ViewBag.alldealer = new SelectList(db.select_whitelabel_DealerName_for_ddl(userid), "Dealerid", "DealerName", null).ToList();
            ViewBag.OldMonth = OldMonth;
            txt_frm_date = new DateTime(date.AddMonths(-1).Year, date.AddMonths(-1).Month, 1);
            to_date = new DateTime(date.Year, date.Month, 1);
            if (alldealer == "" || alldealer.Contains("All Dealer"))
            {
                var show = db.GST_Monthly_wDealer(Convert.ToDateTime(txt_frm_date), Convert.ToDateTime(to_date)).ToList();
                return View(show);
            }
            else
            {
                var show = db.GST_Monthly_wDealer(Convert.ToDateTime(txt_frm_date), Convert.ToDateTime(to_date)).Where(a => a.apiid == alldealer).ToList();
                return View(show);
            }

        }

