        [HttpPost]
        public ActionResult UPICharges(string ddlname, string Retailerid, string Dealerid, string Masterid, string Whitelabelid, string ddlstatus, DateTime txt_frm_date, DateTime txt_to_date, string ddlfiltertable)
        {
            var useridd = User.Identity.GetUserId();
            ViewBag.chk = "post";
            var remlist = db.Whitelabel_select_retailer_for_ddl("Admin", useridd);
            ViewBag.Retailerid = new SelectList(remlist, "RetailerId", "Frm_Name", null);
            ViewBag.Retailerid1 = new SelectList(db.select_retailer_for_ddl("Admin"), "RetailerId", "Frm_Name", null);
            var fill = db.whitelabel_Dealer_Details.Where(a => a.Whitelabelid == useridd).ToList();
            var fill1 = db.Whitelabel_Superstokist_details.Where(a => a.Whitelabelid == useridd).ToList();
            var fill2 = db.WhiteLabel_userList.ToList();

            IEnumerable<SelectListItem> selectListss = from s in fill
                                                       select new SelectListItem
                                                       {
                                                           Value = s.DealerId,
                                                           Text = s.FarmName.ToString()
                                                       };
            ViewBag.Dealerid = new SelectList(selectListss, "Value", "Text");
            ViewBag.Dealerid1 = new SelectList(selectListss, "Value", "Text");
            IEnumerable<SelectListItem> selectListss1 = from s in fill1
                                                        select new SelectListItem
                                                        {
                                                            Value = s.SSId,
                                                            Text = s.FarmName.ToString()
                                                        };
            ViewBag.Masterid = new SelectList(selectListss1, "Value", "Text");
            ViewBag.Masterid1 = new SelectList(selectListss1, "Value", "Text");
            IEnumerable<SelectListItem> selectListss2 = from s in fill2
                                                        select new SelectListItem
                                                        {
                                                            Value = s.WhiteLabelID,
                                                            Text = s.FrmName.ToString()
                                                        };
            ViewBag.whitelabelid = new SelectList(selectListss2, "Value", "Text");
            ViewBag.whitelabelid1 = new SelectList(selectListss2, "Value", "Text");

            var userid = "ALL";

            if (ddlname == "Retailer")
            {
                if (Retailerid != "")
                {
                    userid = Retailerid;
                }
            }
            else if (ddlname == "Distributor")
            {
                if (Dealerid != "")
                {
                    userid = Dealerid;
                }
            }
            else if (ddlname == "Master")
            {
                if (Masterid != "")
                {
                    userid = Masterid;
                }
            }
            else if (ddlname == "Whitelabel")
            {
                if (Whitelabelid != "")
                {
                    userid = Whitelabelid;
                }
            }
            else if (ddlname == "ALL")
            {
                ddlname = "Admin";
            }
            DateTime to = txt_to_date.AddDays(1);
            upiChargeAndgateway model = new upiChargeAndgateway();
            var ch = db.Whitelabel_show_upi_txn_details(useridd, ddlname, userid, ddlstatus, txt_frm_date, to).ToList();
            var chk1 = db.Whitelabel_Upi_slab.Where(u => u.whitelabelid == useridd).ToList();
            model.UPIREPORT = ch;
            if (ddlfiltertable == "VASTBAZAAR")
            {
                model.UPIREPORT = ch.Where(x => x.Apinm == null || x.Apinm == "VASTBAZAAR");
            }
            else if (ddlfiltertable == "SELF")
            {
                model.UPIREPORT = ch.Where(x => x.Apinm == "SELF");
            }

            model.msg = "";
            model.Upi_slabs = chk1;
            model.Admin_UPIs = db.Whitelabel_Admin_UPI.Where(u => u.whitelabelid == useridd).ToList();
            ViewBag.CHKUPI = db.Whitelabel_Hidw_Show.Where(p => p.UseFor == "UPI" && p.whitelabelid == useridd).SingleOrDefault();
            return View(model);
        }

