        public ActionResult AddUpiCharge(decimal min, decimal charge)
        {
            var userid = User.Identity.GetUserId();
            var chk = db.Whitelabel_Upi_slab.Where(s => s.whitelabelid == userid).SingleOrDefault();
            upiChargeAndgateway model = new upiChargeAndgateway();
            if (chk == null)
            {
                Whitelabel_Upi_slab slab = new Whitelabel_Upi_slab();
                slab.Charge = charge;
                slab.min = min;
                slab.whitelabelid = userid;
                db.Whitelabel_Upi_slab.Add(slab);
                db.SaveChanges();
                model.msg = "DONE";
            }
            else
            {
                model.msg = "Already Add";
            }

            var chk1 = db.Whitelabel_Upi_slab.Where(u => u.whitelabelid == userid).ToList();
            model.Upi_slabs = chk1;
            model.Admin_UPIs = db.Whitelabel_Admin_UPI.Where(u => u.whitelabelid == userid).ToList();
            return PartialView("_upi_slabList", model);
        }
