            model.msg = "OTPSEND SUCCESSFULLY";
            return PartialView("_upi_SelfList", model);
        }
        public ActionResult AddUpiSelf(string upiid, decimal min, string otp, decimal max)
        {
            var userid = User.Identity.GetUserId();
            var lastotp = db.MobileOtps.Where(aa => aa.Userid == "ADMIN" && aa.Type == "UPISELF").OrderByDescending(aa => aa.idno).FirstOrDefault().Otp;
            upiChargeAndgateway model = new upiChargeAndgateway();
            if (lastotp == otp)
            {
                var chk = db.Whitelabel_Admin_UPI.Where(u => u.whitelabelid == userid).SingleOrDefault();
                if (chk == null)
                {
                    Whitelabel_Admin_UPI ad = new Whitelabel_Admin_UPI();
                    ad.minamount = min;
                    ad.maxamount = max;
                    ad.txndate = DateTime.Now;
                    ad.Upiid = upiid;
                    ad.whitelabelid = userid;
                    db.Whitelabel_Admin_UPI.Add(ad);
                    db.SaveChanges();
                }
            }
            else
            {
                model.msg = "OTP MISSMATCH";
            }
            var chk1 = db.Whitelabel_Admin_UPI.Where(u => u.whitelabelid == userid).ToList();
            model.Admin_UPIs = chk1;
            model.Upi_slabs = db.Whitelabel_Upi_slab.Where(s => s.whitelabelid == userid).ToList();
            return PartialView("_upi_SelfList", model);
        }
