        public ActionResult Hide_Show_UPI(string usefor)
        {

            try
            {
                var userid = User.Identity.GetUserId();
                int res = 0;
                var CHKROW = db.Whitelabel_Hidw_Show.Where(p => p.UseFor == usefor && p.whitelabelid == userid).SingleOrDefault();
                if (CHKROW != null)
                {
                    if (CHKROW.Status == "N")
                    {
                        Whitelabel_Hidw_Show obj = (from tbl in db.Whitelabel_Hidw_Show
                                                    where tbl.Idno == CHKROW.Idno
                                                    select tbl).SingleOrDefault();
                        obj.Status = "Y";
                        res = db.SaveChanges();
                        return Json(new { status = "Success", Message = "ON" });
                    }
                    else
                    {
                        Whitelabel_Hidw_Show obj = (from tbl in db.Whitelabel_Hidw_Show
                                                    where tbl.Idno == CHKROW.Idno
                                                    select tbl).SingleOrDefault();
                        obj.Status = "N";
                        res = db.SaveChanges();
                        return Json(new { status = "Success", Message = "OFF" });
                    }

                }
                else
                {
                    return Json(new { status = "Failed", Message = "Something Went Wrong !" });
                }
            }
            catch
            {
                return Json(new { status = "Failed", Message = "Something Went Wrong !!!" });
            }
        }


        public ActionResult UPI_Manual_Pending_To_Success(int? hideupiidres, string hideupiidrestypes, string txtBankRRN, string txtcode)
        {
            var userid = User.Identity.GetUserId();

            if (!string.IsNullOrEmpty(hideupiidrestypes) && !string.IsNullOrEmpty(txtBankRRN) && !string.IsNullOrEmpty(txtcode))
            {
                if (hideupiidrestypes == "REJECTED")
                {
                    hideupiidrestypes = "Failed";
                    txtBankRRN = null;
                }
                else
                {
                    hideupiidrestypes = "Success";
                }
                var password = Encrypt(txtcode);
                var tranpass = (from paa in db.Whitelabel_Trans_HighSecu_Pass where paa.transpass == password && paa.WhitelabelId == userid select paa).Count();
                if (tranpass > 0)
                {
                    //System.Data.Entity.Core.Objects.ObjectParameter output = new
                    //  System.Data.Entity.Core.Objects.ObjectParameter("Output", typeof(string));
                    //var outres = db.whitelabel_Update_Upitxn_Pending_toSuccessFailed(hideupiidres, hideupiidrestypes, txtBankRRN, output).SingleOrDefault().msg;
                    //TempData["msgupi"] = outres;
                    //return RedirectToAction("UPICharges");

                    var upi_data = db.Whitelabel_Upi_txn_details.Where(s => s.idno == hideupiidres).SingleOrDefault();

                    if (upi_data != null)
                    {
                        var Token = string.Empty;
                        Token = GetToken();
                        var client = new RestClient(Vastwebmulti.Areas.WHITELABEL.Models.WapiBaseUrl.GetBaseUrl() + "/UPI/api/data/UPI_Update_TXN?refid=" + upi_data.refid + "&status=" + hideupiidrestypes + "&bankrrn=" + txtBankRRN);
                        var request = new RestRequest(Method.GET);
                        request.AddHeader("Content-Type", "application/json");
                        request.AddHeader("Authorization", "bearer " + Token + "");
                        IRestResponse response = client.Execute(request);

                        var statusCode = response.StatusCode.ToString();
                        if (statusCode == "Unauthorized")
                        {
                            TempData.Remove("data");
                            AuthenticationManager.SignOut(DefaultAuthenticationTypes.ApplicationCookie);
                            return RedirectToAction("Index", "Home", null);
                        }

                        dynamic json = JsonConvert.DeserializeObject(response.Content);
                        string message = (string)json.Message;

                        TempData["msgupi"] = message;
                        return RedirectToAction("UPICharges");
                    }
                    else
                    {
                        TempData["msgupi"] = "Entry Miss Match.";
                        return RedirectToAction("UPICharges");
                    }
                }
                else
                {
                    TempData["msgupi"] = "High Security Password was Wrong.";
                    return RedirectToAction("UPICharges");
                }
            }
            else
            {
                TempData["msgupi"] = "All Field Required";
                return RedirectToAction("UPICharges");
            }
        }


